#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ThreadRouteTarget {
    Server { thread_ref: ScopedThreadRef },
    Draft { draft_id: String },
}

pub fn resolve_thread_route_target(
    environment_id: Option<&str>,
    thread_id: Option<&str>,
    draft_id: Option<&str>,
) -> Option<ThreadRouteTarget> {
    match (environment_id, thread_id) {
        (Some(environment_id), Some(thread_id))
            if !environment_id.is_empty() && !thread_id.is_empty() =>
        {
            Some(ThreadRouteTarget::Server {
                thread_ref: ScopedThreadRef::new(environment_id, thread_id),
            })
        }
        _ => draft_id
            .filter(|draft_id| !draft_id.is_empty())
            .map(|draft_id| ThreadRouteTarget::Draft {
                draft_id: draft_id.to_string(),
            }),
    }
}

pub fn normalize_hosted_app_channel(channel: Option<&str>) -> Option<HostedAppChannel> {
    match channel
        .map(str::trim)
        .map(str::to_ascii_lowercase)
        .as_deref()
    {
        Some("latest") => Some(HostedAppChannel::Latest),
        Some("nightly") => Some(HostedAppChannel::Nightly),
        _ => None,
    }
}

pub fn resolve_web_app_branding(input: &WebAppBrandingInput) -> WebAppBranding {
    let hosted_app_channel = normalize_hosted_app_channel(input.hosted_app_channel_env.as_deref());
    let hosted_app_channel_label = hosted_app_channel.map(HostedAppChannel::label);

    if let Some(injected) = input.injected_desktop_branding.as_ref() {
        return WebAppBranding {
            hosted_app_channel,
            hosted_app_channel_label,
            app_base_name: injected.base_name.clone(),
            app_stage_label: injected.stage_label.clone(),
            app_display_name: injected.display_name.clone(),
            app_version: input
                .app_version
                .clone()
                .filter(|version| !version.is_empty())
                .unwrap_or_else(|| "0.0.0".to_string()),
        };
    }

    let app_base_name = APP_NAME.to_string();
    let app_stage_label = hosted_app_channel_label
        .map(str::to_string)
        .unwrap_or_else(|| if input.is_dev { "Dev" } else { "Alpha" }.to_string());
    WebAppBranding {
        hosted_app_channel,
        hosted_app_channel_label,
        app_display_name: format!("{app_base_name} ({app_stage_label})"),
        app_base_name,
        app_stage_label,
        app_version: input
            .app_version
            .clone()
            .filter(|version| !version.is_empty())
            .unwrap_or_else(|| "0.0.0".to_string()),
    }
}

pub fn resolve_diff_theme_name(theme: DiffColorScheme) -> &'static str {
    match theme {
        DiffColorScheme::Light => DIFF_THEME_LIGHT_NAME,
        DiffColorScheme::Dark => DIFF_THEME_DARK_NAME,
    }
}

pub fn fnv1a32(input: &str, seed: u32, multiplier: u32) -> u32 {
    let mut hash = seed;
    for code_unit in input.encode_utf16() {
        hash ^= u32::from(code_unit);
        hash = hash.wrapping_mul(multiplier);
    }
    hash
}

pub fn build_patch_cache_key(patch: &str, scope: Option<&str>) -> String {
    let normalized_patch = patch.trim();
    let primary = to_base36(fnv1a32(normalized_patch, FNV_OFFSET_BASIS_32, FNV_PRIME_32));
    let secondary = to_base36(fnv1a32(
        normalized_patch,
        SECONDARY_HASH_SEED,
        SECONDARY_HASH_MULTIPLIER,
    ));
    format!(
        "{}:{}:{}:{}",
        scope.unwrap_or("diff-panel"),
        normalized_patch.encode_utf16().count(),
        primary,
        secondary
    )
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct LruCacheEntry<T> {
    value: T,
    approximate_size: usize,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LruCache<T> {
    cache: HashMap<String, LruCacheEntry<T>>,
    order: VecDeque<String>,
    total_size: usize,
    max_entries: usize,
    max_memory_bytes: usize,
}

impl<T> LruCache<T> {
    pub fn new(max_entries: usize, max_memory_bytes: usize) -> Self {
        Self {
            cache: HashMap::new(),
            order: VecDeque::new(),
            total_size: 0,
            max_entries,
            max_memory_bytes,
        }
    }

    pub fn get(&mut self, key: &str) -> Option<&T> {
        if !self.cache.contains_key(key) {
            return None;
        }

        self.promote(key);
        self.cache.get(key).map(|entry| &entry.value)
    }

    pub fn set(&mut self, key: impl Into<String>, value: T, approximate_size: usize) {
        let key = key.into();
        if let Some(existing) = self.cache.remove(&key) {
            self.total_size = self.total_size.saturating_sub(existing.approximate_size);
            self.order.retain(|existing_key| existing_key != &key);
        }

        self.evict_if_needed(approximate_size);
        self.cache.insert(
            key.clone(),
            LruCacheEntry {
                value,
                approximate_size,
            },
        );
        self.order.push_back(key);
        self.total_size += approximate_size;
    }

    pub fn clear(&mut self) {
        self.cache.clear();
        self.order.clear();
        self.total_size = 0;
    }

    fn promote(&mut self, key: &str) {
        self.order.retain(|existing_key| existing_key != key);
        self.order.push_back(key.to_string());
    }

    fn evict_if_needed(&mut self, incoming_size: usize) {
        while (self.cache.len() >= self.max_entries
            || self.total_size + incoming_size > self.max_memory_bytes)
            && !self.cache.is_empty()
        {
            let Some(oldest_key) = self.order.pop_front() else {
                break;
            };
            if let Some(oldest_entry) = self.cache.remove(&oldest_key) {
                self.total_size = self
                    .total_size
                    .saturating_sub(oldest_entry.approximate_size);
            }
        }
    }
}

pub fn is_model_picker_new_model(provider: &str, slug: &str) -> bool {
    let key = format!("{provider}:{slug}");
    NEW_MODEL_KEYS.contains(&key.as_str())
}

pub fn is_transport_connection_error_message(message: Option<&str>) -> bool {
    let Some(message) = message.map(str::trim).filter(|message| !message.is_empty()) else {
        return false;
    };
    let lower = message.to_ascii_lowercase();
    contains_ascii_word(&lower, "socketcloseerror")
        || contains_ascii_word(&lower, "socketopenerror")
        || lower.contains("unable to connect to the t3 server websocket.")
        || contains_ascii_word(&lower, "ping timeout")
}

pub fn sanitize_thread_error_message(message: Option<&str>) -> Option<String> {
    if is_transport_connection_error_message(message) {
        None
    } else {
        message.map(str::to_string)
    }
}

fn contains_ascii_word(haystack: &str, needle: &str) -> bool {
    let mut search_start = 0;
    while let Some(relative_index) = haystack[search_start..].find(needle) {
        let start = search_start + relative_index;
        let end = start + needle.len();
        let before = haystack[..start].chars().next_back();
        let after = haystack[end..].chars().next();
        let before_boundary = before.is_none_or(|ch| !is_js_regex_word_char(ch));
        let after_boundary = after.is_none_or(|ch| !is_js_regex_word_char(ch));
        if before_boundary && after_boundary {
            return true;
        }
        search_start = end;
    }
    false
}

fn is_js_regex_word_char(ch: char) -> bool {
    ch.is_ascii_alphanumeric() || ch == '_'
}

fn to_base36(value: u32) -> String {
    const DIGITS: &[u8; 36] = b"0123456789abcdefghijklmnopqrstuvwxyz";
    if value == 0 {
        return "0".to_string();
    }

    let mut value = value;
    let mut output = Vec::new();
    while value > 0 {
        output.push(DIGITS[(value % 36) as usize] as char);
        value /= 36;
    }
    output.iter().rev().collect()
}

