fn normalize_key_token(token: &str) -> String {
    match token {
        "space" => " ".to_string(),
        "esc" => "escape".to_string(),
        value => value.to_string(),
    }
}

pub fn parse_keybinding_shortcut(value: &str) -> Option<KeybindingShortcut> {
    let mut tokens = value
        .to_ascii_lowercase()
        .split('+')
        .map(str::trim)
        .map(str::to_string)
        .collect::<Vec<_>>();

    let mut trailing_empty_count = 0;
    while tokens.last().is_some_and(|token| token.is_empty()) {
        trailing_empty_count += 1;
        tokens.pop();
    }
    if trailing_empty_count > 0 {
        tokens.push("+".to_string());
    }
    if tokens.is_empty() || tokens.iter().any(|token| token.is_empty()) {
        return None;
    }

    let mut key = None;
    let mut meta_key = false;
    let mut ctrl_key = false;
    let mut shift_key = false;
    let mut alt_key = false;
    let mut mod_key = false;

    for token in tokens {
        match token.as_str() {
            "cmd" | "command" | "meta" => meta_key = true,
            "ctrl" | "control" => ctrl_key = true,
            "shift" => shift_key = true,
            "alt" | "option" => alt_key = true,
            "mod" => mod_key = true,
            _ => {
                if key.is_some() {
                    return None;
                }
                key = Some(normalize_key_token(&token));
            }
        }
    }

    Some(KeybindingShortcut {
        key: key?,
        meta_key,
        ctrl_key,
        shift_key,
        alt_key,
        mod_key,
    })
}

pub fn shortcut_to_keybinding_input(shortcut: &KeybindingShortcut) -> String {
    let mut parts = Vec::new();
    if shortcut.mod_key {
        parts.push("mod".to_string());
    }
    if shortcut.meta_key {
        parts.push("meta".to_string());
    }
    if shortcut.ctrl_key {
        parts.push("ctrl".to_string());
    }
    if shortcut.alt_key {
        parts.push("alt".to_string());
    }
    if shortcut.shift_key {
        parts.push("shift".to_string());
    }
    parts.push(match shortcut.key.as_str() {
        " " => "space".to_string(),
        "escape" => "esc".to_string(),
        value => value.to_string(),
    });
    parts.join("+")
}

pub fn normalize_shortcut_key_token(key: &str) -> Option<String> {
    let normalized = key.to_ascii_lowercase();
    match normalized.as_str() {
        "meta" | "control" | "ctrl" | "shift" | "alt" | "option" => None,
        " " => Some("space".to_string()),
        "escape" => Some("esc".to_string()),
        "arrowup" | "arrowdown" | "arrowleft" | "arrowright" | "enter" | "tab" | "backspace"
        | "delete" | "home" | "end" | "pageup" | "pagedown" => Some(normalized),
        value if value.len() == 1 => Some(value.to_string()),
        value if is_function_key(value) => Some(value.to_string()),
        _ => None,
    }
}

fn is_function_key(value: &str) -> bool {
    let Some(number) = value.strip_prefix('f') else {
        return false;
    };
    (1..=2).contains(&number.len()) && number.chars().all(|ch| ch.is_ascii_digit())
}

pub fn is_mac_platform(platform: &str) -> bool {
    let platform = platform.to_ascii_lowercase();
    ["mac", "iphone", "ipad", "ipod"]
        .iter()
        .any(|needle| platform.contains(needle))
}

pub fn is_windows_platform(platform: &str) -> bool {
    platform.to_ascii_lowercase().starts_with("win")
}

pub fn is_linux_platform(platform: &str) -> bool {
    platform.to_ascii_lowercase().contains("linux")
}

pub fn keybinding_from_keyboard_event(
    event: KeybindingKeyboardEvent<'_>,
    platform: &str,
) -> Option<String> {
    let key_token = normalize_shortcut_key_token(event.key)?;
    let mut parts = Vec::new();

    if is_mac_platform(platform) {
        if event.meta_key {
            parts.push("mod".to_string());
        }
        if event.ctrl_key {
            parts.push("ctrl".to_string());
        }
    } else {
        if event.ctrl_key {
            parts.push("mod".to_string());
        }
        if event.meta_key {
            parts.push("meta".to_string());
        }
    }
    if event.alt_key {
        parts.push("alt".to_string());
    }
    if event.shift_key {
        parts.push("shift".to_string());
    }
    if parts.is_empty() {
        return None;
    }

    parts.push(key_token);
    Some(parts.join("+"))
}

pub fn compile_resolved_keybinding_rule(rule: &KeybindingRule) -> Option<ResolvedKeybindingRule> {
    let shortcut = parse_keybinding_shortcut(rule.key)?;
    let when_ast = if rule.when.is_empty() {
        None
    } else {
        Some(parse_keybinding_when_expression(rule.when)?)
    };

    Some(ResolvedKeybindingRule {
        command: rule.command.to_string(),
        shortcut,
        when_ast,
    })
}

pub fn default_resolved_keybindings() -> Vec<ResolvedKeybindingRule> {
    DEFAULT_KEYBINDING_RULES
        .iter()
        .filter_map(compile_resolved_keybinding_rule)
        .collect()
}

pub fn default_server_keybinding_rules() -> Vec<ServerKeybindingRule> {
    DEFAULT_KEYBINDING_RULES
        .iter()
        .map(|rule| ServerKeybindingRule {
            command: rule.command.to_string(),
            key: rule.key.to_string(),
            when: (!rule.when.is_empty()).then(|| rule.when.to_string()),
        })
        .collect()
}

fn normalized_keybinding_when(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

pub fn compile_server_keybinding_rule(
    rule: &ServerKeybindingRule,
) -> Option<ResolvedKeybindingRule> {
    let shortcut = parse_keybinding_shortcut(&rule.key)?;
    let when_ast = match normalized_keybinding_when(rule.when.as_deref()) {
        Some(when) => Some(parse_keybinding_when_expression(&when)?),
        None => None,
    };
    Some(ResolvedKeybindingRule {
        command: rule.command.clone(),
        shortcut,
        when_ast,
    })
}

pub fn compile_server_keybindings_config(
    config: &[ServerKeybindingRule],
) -> Vec<ResolvedKeybindingRule> {
    let compiled = config
        .iter()
        .filter_map(compile_server_keybinding_rule)
        .collect::<Vec<_>>();
    if compiled.len() > MAX_KEYBINDINGS_COUNT {
        compiled[compiled.len() - MAX_KEYBINDINGS_COUNT..].to_vec()
    } else {
        compiled
    }
}

pub fn merge_with_default_keybindings(
    custom: &[ResolvedKeybindingRule],
) -> Vec<ResolvedKeybindingRule> {
    if custom.is_empty() {
        return default_resolved_keybindings();
    }
    let overridden_commands = custom
        .iter()
        .map(|binding| binding.command.as_str())
        .collect::<BTreeSet<_>>();
    let mut merged = default_resolved_keybindings()
        .into_iter()
        .filter(|binding| !overridden_commands.contains(binding.command.as_str()))
        .collect::<Vec<_>>();
    merged.extend(custom.iter().cloned());
    if merged.len() > MAX_KEYBINDINGS_COUNT {
        merged[merged.len() - MAX_KEYBINDINGS_COUNT..].to_vec()
    } else {
        merged
    }
}

pub fn keybindings_config_state_from_custom_rules(
    rules: &[ServerKeybindingRule],
    issues: &[KeybindingsConfigIssue],
) -> KeybindingsConfigState {
    KeybindingsConfigState {
        keybindings: merge_with_default_keybindings(&compile_server_keybindings_config(rules)),
        issues: issues.to_vec(),
    }
}

fn keybinding_rule_from_upsert_input(input: &KeybindingUpsertInput) -> ServerKeybindingRule {
    ServerKeybindingRule {
        command: input.command.clone(),
        key: input.key.clone(),
        when: normalized_keybinding_when(input.when.as_deref()),
    }
}

fn keybinding_rule_from_target(target: &KeybindingTarget) -> ServerKeybindingRule {
    ServerKeybindingRule {
        command: target.command.clone(),
        key: target.key.clone(),
        when: normalized_keybinding_when(target.when.as_deref()),
    }
}

fn is_same_server_keybinding_rule(
    left: &ServerKeybindingRule,
    right: &ServerKeybindingRule,
) -> bool {
    left.command == right.command
        && left.key == right.key
        && normalized_keybinding_when(left.when.as_deref())
            == normalized_keybinding_when(right.when.as_deref())
}

fn keybinding_shortcut_context(rule: &ServerKeybindingRule) -> Option<String> {
    let parsed = parse_keybinding_shortcut(&rule.key)?;
    let encoded = shortcut_to_keybinding_input(&parsed);
    Some(format!(
        "{encoded}\u{0000}{}",
        normalized_keybinding_when(rule.when.as_deref()).unwrap_or_default()
    ))
}

fn has_same_keybinding_shortcut_context(
    left: &ServerKeybindingRule,
    right: &ServerKeybindingRule,
) -> bool {
    let Some(left_context) = keybinding_shortcut_context(left) else {
        return false;
    };
    let Some(right_context) = keybinding_shortcut_context(right) else {
        return false;
    };
    left_context == right_context
}

pub fn sync_default_keybindings_on_startup_plan(
    custom_config: &[ServerKeybindingRule],
    has_issues: bool,
) -> KeybindingsDefaultSyncPlan {
    if has_issues {
        return KeybindingsDefaultSyncPlan {
            next_config: custom_config.to_vec(),
            skipped_default_conflicts: Vec::new(),
            skipped_due_to_issues: true,
            changed: false,
            truncated: false,
        };
    }

    let existing_commands = custom_config
        .iter()
        .map(|entry| entry.command.as_str())
        .collect::<BTreeSet<_>>();
    let defaults = default_server_keybinding_rules();
    let mut missing_defaults = Vec::new();
    let mut skipped_default_conflicts = Vec::new();
    for default_rule in &defaults {
        if existing_commands.contains(default_rule.command.as_str()) {
            continue;
        }
        if let Some(conflicting_entry) = custom_config
            .iter()
            .find(|entry| has_same_keybinding_shortcut_context(entry, default_rule))
        {
            skipped_default_conflicts.push(KeybindingsDefaultConflict {
                default_command: default_rule.command.clone(),
                conflicting_command: conflicting_entry.command.clone(),
                key: default_rule.key.clone(),
                when: default_rule.when.clone(),
            });
            continue;
        }
        missing_defaults.push(default_rule.clone());
    }

    let next_config = custom_config
        .iter()
        .cloned()
        .chain(missing_defaults)
        .collect::<Vec<_>>();
    let truncated = next_config.len() > MAX_KEYBINDINGS_COUNT;
    let capped_config = if truncated {
        next_config[next_config.len() - MAX_KEYBINDINGS_COUNT..].to_vec()
    } else {
        next_config
    };
    KeybindingsDefaultSyncPlan {
        changed: capped_config != custom_config,
        next_config: capped_config,
        skipped_default_conflicts,
        skipped_due_to_issues: false,
        truncated,
    }
}

pub fn upsert_keybinding_rule_in_config(
    custom_config: &[ServerKeybindingRule],
    input: &KeybindingUpsertInput,
) -> Vec<ServerKeybindingRule> {
    let rule = keybinding_rule_from_upsert_input(input);
    let replace_target = input.replace.as_ref().map(keybinding_rule_from_target);
    let mut next_config = custom_config
        .iter()
        .filter(|entry| {
            if let Some(replace_target) = replace_target.as_ref() {
                return !is_same_server_keybinding_rule(entry, replace_target);
            }
            !is_same_server_keybinding_rule(entry, &rule)
        })
        .cloned()
        .collect::<Vec<_>>();
    next_config.push(rule);
    if next_config.len() > MAX_KEYBINDINGS_COUNT {
        next_config[next_config.len() - MAX_KEYBINDINGS_COUNT..].to_vec()
    } else {
        next_config
    }
}

pub fn remove_keybinding_rule_from_config(
    custom_config: &[ServerKeybindingRule],
    target: &KeybindingTarget,
) -> Vec<ServerKeybindingRule> {
    let target = keybinding_rule_from_target(target);
    custom_config
        .iter()
        .filter(|entry| !is_same_server_keybinding_rule(entry, &target))
        .cloned()
        .collect()
}

pub fn when_ast_to_expression(node: Option<&KeybindingWhenNode>) -> String {
    node.map(when_node_to_expression).unwrap_or_default()
}

fn when_node_to_expression(node: &KeybindingWhenNode) -> String {
    match node {
        KeybindingWhenNode::Identifier { name } => name.clone(),
        KeybindingWhenNode::Not { node } => format!("!{}", wrap_when_expression(node)),
        KeybindingWhenNode::And { left, right } => {
            format!(
                "{} && {}",
                wrap_when_expression(left),
                wrap_when_expression(right)
            )
        }
        KeybindingWhenNode::Or { left, right } => {
            format!(
                "{} || {}",
                wrap_when_expression(left),
                wrap_when_expression(right)
            )
        }
    }
}

fn wrap_when_expression(node: &KeybindingWhenNode) -> String {
    match node {
        KeybindingWhenNode::Identifier { .. } | KeybindingWhenNode::Not { .. } => {
            when_node_to_expression(node)
        }
        KeybindingWhenNode::And { .. } | KeybindingWhenNode::Or { .. } => {
            format!("({})", when_node_to_expression(node))
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum WhenToken {
    Identifier(String),
    Not,
    And,
    Or,
    LParen,
    RParen,
}

fn tokenize_when_expression(expression: &str) -> Option<Vec<WhenToken>> {
    let mut tokens = Vec::new();
    let mut cursor = 0;

    while cursor < expression.len() {
        let current = expression[cursor..].chars().next()?;
        if current.is_whitespace() {
            cursor += current.len_utf8();
            continue;
        }
        if expression[cursor..].starts_with("&&") {
            tokens.push(WhenToken::And);
            cursor += 2;
            continue;
        }
        if expression[cursor..].starts_with("||") {
            tokens.push(WhenToken::Or);
            cursor += 2;
            continue;
        }
        match current {
            '!' => {
                tokens.push(WhenToken::Not);
                cursor += 1;
                continue;
            }
            '(' => {
                tokens.push(WhenToken::LParen);
                cursor += 1;
                continue;
            }
            ')' => {
                tokens.push(WhenToken::RParen);
                cursor += 1;
                continue;
            }
            _ => {}
        }

        if !(current.is_ascii_alphabetic() || current == '_') {
            return None;
        }
        let start = cursor;
        cursor += current.len_utf8();
        while cursor < expression.len() {
            let next = expression[cursor..].chars().next()?;
            if next.is_ascii_alphanumeric() || matches!(next, '_' | '.' | '-') {
                cursor += next.len_utf8();
            } else {
                break;
            }
        }
        tokens.push(WhenToken::Identifier(expression[start..cursor].to_string()));
    }

    Some(tokens)
}

pub fn parse_keybinding_when_expression(expression: &str) -> Option<KeybindingWhenNode> {
    let tokens = tokenize_when_expression(expression)?;
    if tokens.is_empty() {
        return None;
    }

    struct Parser {
        tokens: Vec<WhenToken>,
        index: usize,
    }

    impl Parser {
        fn parse_primary(&mut self, depth: usize) -> Option<KeybindingWhenNode> {
            if depth > MAX_WHEN_EXPRESSION_DEPTH {
                return None;
            }
            match self.tokens.get(self.index)? {
                WhenToken::Identifier(value) => {
                    self.index += 1;
                    Some(KeybindingWhenNode::Identifier {
                        name: value.clone(),
                    })
                }
                WhenToken::LParen => {
                    self.index += 1;
                    let expression_node = self.parse_or(depth + 1)?;
                    if self.tokens.get(self.index) != Some(&WhenToken::RParen) {
                        return None;
                    }
                    self.index += 1;
                    Some(expression_node)
                }
                _ => None,
            }
        }

        fn parse_unary(&mut self, depth: usize) -> Option<KeybindingWhenNode> {
            let mut not_count = 0;
            while self.tokens.get(self.index) == Some(&WhenToken::Not) {
                self.index += 1;
                not_count += 1;
                if not_count > MAX_WHEN_EXPRESSION_DEPTH {
                    return None;
                }
            }

            let mut node = self.parse_primary(depth)?;
            while not_count > 0 {
                node = KeybindingWhenNode::Not {
                    node: Box::new(node),
                };
                not_count -= 1;
            }
            Some(node)
        }

        fn parse_and(&mut self, depth: usize) -> Option<KeybindingWhenNode> {
            let mut left = self.parse_unary(depth)?;
            while self.tokens.get(self.index) == Some(&WhenToken::And) {
                self.index += 1;
                let right = self.parse_unary(depth)?;
                left = KeybindingWhenNode::And {
                    left: Box::new(left),
                    right: Box::new(right),
                };
            }
            Some(left)
        }

        fn parse_or(&mut self, depth: usize) -> Option<KeybindingWhenNode> {
            let mut left = self.parse_and(depth)?;
            while self.tokens.get(self.index) == Some(&WhenToken::Or) {
                self.index += 1;
                let right = self.parse_and(depth)?;
                left = KeybindingWhenNode::Or {
                    left: Box::new(left),
                    right: Box::new(right),
                };
            }
            Some(left)
        }
    }

    let mut parser = Parser { tokens, index: 0 };
    let ast = parser.parse_or(0)?;
    (parser.index == parser.tokens.len()).then_some(ast)
}

pub fn parse_when_expression_draft(
    expression: &str,
) -> Result<Option<KeybindingWhenNode>, &'static str> {
    let trimmed = expression.trim();
    if trimmed.is_empty() {
        return Ok(None);
    }
    parse_keybinding_when_expression(trimmed)
        .map(Some)
        .ok_or(KEYBINDING_WHEN_PARSE_ERROR)
}

fn collect_when_identifiers_from_node(
    node: Option<&KeybindingWhenNode>,
    identifiers: &mut BTreeSet<String>,
) {
    let Some(node) = node else {
        return;
    };
    match node {
        KeybindingWhenNode::Identifier { name } => {
            identifiers.insert(name.clone());
        }
        KeybindingWhenNode::Not { node } => {
            collect_when_identifiers_from_node(Some(node), identifiers)
        }
        KeybindingWhenNode::And { left, right } | KeybindingWhenNode::Or { left, right } => {
            collect_when_identifiers_from_node(Some(left), identifiers);
            collect_when_identifiers_from_node(Some(right), identifiers);
        }
    }
}

pub fn build_when_variable_options() -> Vec<String> {
    let mut identifiers = BTreeSet::new();
    for value in CORE_WHEN_VARIABLES {
        identifiers.insert((*value).to_string());
    }
    for binding in default_resolved_keybindings() {
        collect_when_identifiers_from_node(binding.when_ast.as_ref(), &mut identifiers);
    }

    let mut values = identifiers.into_iter().collect::<Vec<_>>();
    values.sort_by(|left, right| {
        let left_core = CORE_WHEN_VARIABLES.iter().position(|value| *value == left);
        let right_core = CORE_WHEN_VARIABLES.iter().position(|value| *value == right);
        match (left_core, right_core) {
            (Some(left_index), Some(right_index)) => left_index.cmp(&right_index),
            (Some(_), None) => Ordering::Less,
            (None, Some(_)) => Ordering::Greater,
            (None, None) => left.cmp(right),
        }
    });
    values
}

pub fn default_when_variable() -> String {
    build_when_variable_options()
        .into_iter()
        .find(|identifier| identifier != "true" && identifier != "false")
        .unwrap_or_else(|| "terminalFocus".to_string())
}

pub fn default_when_condition() -> KeybindingWhenNode {
    KeybindingWhenNode::Identifier {
        name: default_when_variable(),
    }
}

pub fn default_when_group(operator: BooleanOperator) -> KeybindingWhenNode {
    let right = KeybindingWhenNode::Not {
        node: Box::new(default_when_condition()),
    };
    match operator {
        BooleanOperator::And => KeybindingWhenNode::And {
            left: Box::new(default_when_condition()),
            right: Box::new(right),
        },
        BooleanOperator::Or => KeybindingWhenNode::Or {
            left: Box::new(default_when_condition()),
            right: Box::new(right),
        },
    }
}

pub fn flatten_when_children(
    node: &KeybindingWhenNode,
    operator: BooleanOperator,
) -> Vec<KeybindingWhenNode> {
    match (node, operator) {
        (KeybindingWhenNode::And { left, right }, BooleanOperator::And)
        | (KeybindingWhenNode::Or { left, right }, BooleanOperator::Or) => {
            let mut children = flatten_when_children(left, operator);
            children.extend(flatten_when_children(right, operator));
            children
        }
        _ => vec![node.clone()],
    }
}

pub fn build_when_expression_group(
    children: &[KeybindingWhenNode],
    operator: BooleanOperator,
) -> Option<KeybindingWhenNode> {
    let first = children.first()?.clone();
    Some(
        children
            .iter()
            .skip(1)
            .cloned()
            .fold(first, |left, right| match operator {
                BooleanOperator::And => KeybindingWhenNode::And {
                    left: Box::new(left),
                    right: Box::new(right),
                },
                BooleanOperator::Or => KeybindingWhenNode::Or {
                    left: Box::new(left),
                    right: Box::new(right),
                },
            }),
    )
}

pub fn condition_parts(node: &KeybindingWhenNode) -> Option<WhenConditionParts> {
    match node {
        KeybindingWhenNode::Identifier { name } => Some(WhenConditionParts {
            identifier: name.clone(),
            negated: false,
        }),
        KeybindingWhenNode::Not { node } => match node.as_ref() {
            KeybindingWhenNode::Identifier { name } => Some(WhenConditionParts {
                identifier: name.clone(),
                negated: true,
            }),
            _ => None,
        },
        _ => None,
    }
}

pub fn set_condition_identifier(node: &KeybindingWhenNode, identifier: &str) -> KeybindingWhenNode {
    let Some(parts) = condition_parts(node) else {
        return node.clone();
    };
    let next = KeybindingWhenNode::Identifier {
        name: identifier.to_string(),
    };
    if parts.negated {
        KeybindingWhenNode::Not {
            node: Box::new(next),
        }
    } else {
        next
    }
}

pub fn set_condition_negated(node: &KeybindingWhenNode, negated: bool) -> KeybindingWhenNode {
    let Some(parts) = condition_parts(node) else {
        return if negated {
            KeybindingWhenNode::Not {
                node: Box::new(node.clone()),
            }
        } else {
            node.clone()
        };
    };
    let identifier = KeybindingWhenNode::Identifier {
        name: parts.identifier,
    };
    if negated {
        KeybindingWhenNode::Not {
            node: Box::new(identifier),
        }
    } else {
        identifier
    }
}

pub fn is_known_when_variable(identifier: &str) -> bool {
    build_when_variable_options()
        .iter()
        .any(|value| value == identifier)
}

pub fn unknown_when_variables(node: Option<&KeybindingWhenNode>) -> Vec<String> {
    let mut identifiers = BTreeSet::new();
    collect_when_identifiers_from_node(node, &mut identifiers);
    identifiers
        .into_iter()
        .filter(|identifier| !is_known_when_variable(identifier))
        .collect()
}

fn source_for_binding(binding: &ResolvedKeybindingRule) -> KeybindingSource {
    if binding.command.starts_with("script.") {
        return KeybindingSource::Project;
    }

    let binding_key = shortcut_to_keybinding_input(&binding.shortcut);
    let binding_when = when_ast_to_expression(binding.when_ast.as_ref());
    let is_default = default_resolved_keybindings().iter().any(|entry| {
        entry.command == binding.command
            && shortcut_to_keybinding_input(&entry.shortcut) == binding_key
            && when_ast_to_expression(entry.when_ast.as_ref()) == binding_when
    });
    if is_default {
        KeybindingSource::Default
    } else {
        KeybindingSource::Custom
    }
}

fn default_binding_for_binding(binding: &ResolvedKeybindingRule) -> Option<ResolvedKeybindingRule> {
    let binding_key = shortcut_to_keybinding_input(&binding.shortcut);
    let binding_when = when_ast_to_expression(binding.when_ast.as_ref());
    let defaults = default_resolved_keybindings();
    defaults
        .iter()
        .find(|entry| {
            entry.command == binding.command
                && shortcut_to_keybinding_input(&entry.shortcut) == binding_key
                && when_ast_to_expression(entry.when_ast.as_ref()) == binding_when
        })
        .or_else(|| {
            defaults.iter().find(|entry| {
                entry.command == binding.command
                    && when_ast_to_expression(entry.when_ast.as_ref()) == binding_when
            })
        })
        .or_else(|| {
            defaults
                .iter()
                .find(|entry| entry.command == binding.command)
        })
        .cloned()
}

fn keybinding_row_id(command: &str, key: &str, when: &str) -> String {
    format!("{command}\0{key}\0{when}")
}

fn conflicts_with_when(left_when: &str, right_when: &str) -> bool {
    left_when.is_empty() || right_when.is_empty() || left_when == right_when
}

pub fn keybinding_conflict_labels(
    rows: &[KeybindingRow],
    row_id: &str,
    key: &str,
    when: &str,
) -> Vec<String> {
    if key.trim().is_empty() {
        return Vec::new();
    }
    rows.iter()
        .filter(|candidate| {
            candidate.id != row_id
                && candidate.key == key
                && conflicts_with_when(&candidate.when, when)
        })
        .map(|candidate| keybinding_command_label(&candidate.command))
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect()
}

pub fn build_keybinding_rows(
    keybindings: &[ResolvedKeybindingRule],
    query: &str,
) -> Vec<KeybindingRow> {
    let normalized_query = query.trim().to_ascii_lowercase();
    let rows = keybindings
        .iter()
        .enumerate()
        .map(|(index, binding)| {
            let default_binding = default_binding_for_binding(binding);
            let key = shortcut_to_keybinding_input(&binding.shortcut);
            let when = when_ast_to_expression(binding.when_ast.as_ref());
            KeybindingRow {
                id: format!(
                    "{}\0{index}",
                    keybinding_row_id(&binding.command, &key, &when)
                ),
                command: binding.command.clone(),
                key,
                when,
                source: source_for_binding(binding),
                default_key: default_binding
                    .as_ref()
                    .map(|binding| shortcut_to_keybinding_input(&binding.shortcut)),
                default_when: when_ast_to_expression(
                    default_binding
                        .as_ref()
                        .and_then(|binding| binding.when_ast.as_ref()),
                ),
                binding: binding.clone(),
                conflicts: Vec::new(),
            }
        })
        .collect::<Vec<_>>();

    let mut rows_with_conflicts = rows
        .iter()
        .map(|row| {
            let mut row = row.clone();
            row.conflicts = keybinding_conflict_labels(&rows, &row.id, &row.key, &row.when);
            row
        })
        .collect::<Vec<_>>();

    rows_with_conflicts.sort_by(|left, right| {
        left.command
            .cmp(&right.command)
            .then_with(|| left.key.cmp(&right.key))
    });

    if normalized_query.is_empty() {
        return rows_with_conflicts;
    }

    rows_with_conflicts
        .into_iter()
        .filter(|row| {
            let source = match row.source {
                KeybindingSource::Default => "default",
                KeybindingSource::Custom => "custom",
                KeybindingSource::Project => "project",
            };
            row.command.to_ascii_lowercase().contains(&normalized_query)
                || row.key.to_ascii_lowercase().contains(&normalized_query)
                || row.when.to_ascii_lowercase().contains(&normalized_query)
                || source.contains(&normalized_query)
        })
        .collect()
}

pub fn create_keybinding_row_draft(row: &KeybindingRow) -> KeybindingRowDraftState {
    KeybindingRowDraftState {
        key_draft: row.key.clone(),
        when_draft: row.binding.when_ast.clone(),
        is_recording: false,
        is_when_draft_valid: true,
    }
}

pub fn new_keybinding_row_draft() -> KeybindingRowDraftState {
    KeybindingRowDraftState {
        key_draft: String::new(),
        when_draft: None,
        is_recording: false,
        is_when_draft_valid: true,
    }
}

pub fn apply_keybinding_row_draft_patch(
    state: &KeybindingRowDraftState,
    patch: KeybindingRowDraftPatch,
) -> KeybindingRowDraftState {
    KeybindingRowDraftState {
        key_draft: patch.key_draft.unwrap_or_else(|| state.key_draft.clone()),
        when_draft: patch.when_draft.unwrap_or_else(|| state.when_draft.clone()),
        is_recording: patch.is_recording.unwrap_or(state.is_recording),
        is_when_draft_valid: patch
            .is_when_draft_valid
            .unwrap_or(state.is_when_draft_valid),
    }
}

pub fn keybinding_row_when_draft_expression(state: &KeybindingRowDraftState) -> String {
    when_ast_to_expression(state.when_draft.as_ref())
}

pub fn keybinding_row_is_dirty(row: &KeybindingRow, state: &KeybindingRowDraftState) -> bool {
    state.key_draft != row.key || keybinding_row_when_draft_expression(state) != row.when
}

pub fn keybinding_row_can_reset(row: &KeybindingRow) -> bool {
    row.source == KeybindingSource::Custom && row.default_key.is_some()
}

pub fn keybinding_row_can_remove(row: &KeybindingRow) -> bool {
    row.source != KeybindingSource::Default
}

pub fn keybinding_row_show_pill(row: &KeybindingRow, state: &KeybindingRowDraftState) -> bool {
    !state.is_recording
        && state.key_draft == row.key
        && !row.key.is_empty()
        && !keybinding_row_is_dirty(row, state)
}

pub fn row_keybinding_target(row: &KeybindingRow) -> KeybindingTarget {
    KeybindingTarget {
        command: row.command.clone(),
        key: row.key.clone(),
        when: (!row.when.trim().is_empty()).then(|| row.when.clone()),
    }
}

pub fn keybinding_row_save_input(
    row: &KeybindingRow,
    state: &KeybindingRowDraftState,
) -> Option<KeybindingUpsertInput> {
    if state.key_draft.trim().is_empty() || !state.is_when_draft_valid {
        return None;
    }
    let when_expression = keybinding_row_when_draft_expression(state);
    Some(KeybindingUpsertInput {
        command: row.command.clone(),
        key: state.key_draft.trim().to_string(),
        when: (!when_expression.trim().is_empty()).then(|| when_expression.trim().to_string()),
        replace: Some(row_keybinding_target(row)),
    })
}

pub fn new_keybinding_save_input(
    command: &str,
    state: &KeybindingRowDraftState,
) -> Option<KeybindingUpsertInput> {
    if command.is_empty() || state.key_draft.trim().is_empty() || !state.is_when_draft_valid {
        return None;
    }
    let when_expression = keybinding_row_when_draft_expression(state);
    Some(KeybindingUpsertInput {
        command: command.to_string(),
        key: state.key_draft.trim().to_string(),
        when: (!when_expression.trim().is_empty()).then(|| when_expression.trim().to_string()),
        replace: None,
    })
}

pub fn keybinding_reset_input(row: &KeybindingRow) -> Option<KeybindingUpsertInput> {
    let default_key = row.default_key.as_ref()?;
    Some(KeybindingUpsertInput {
        command: row.command.clone(),
        key: default_key.clone(),
        when: (!row.default_when.trim().is_empty()).then(|| row.default_when.clone()),
        replace: Some(row_keybinding_target(row)),
    })
}

pub fn build_keybinding_command_options(keybindings: &[ResolvedKeybindingRule]) -> Vec<String> {
    let mut commands = BTreeSet::new();
    for binding in default_resolved_keybindings() {
        commands.insert(binding.command);
    }
    for binding in keybindings {
        commands.insert(binding.command.clone());
    }
    let mut commands = commands.into_iter().collect::<Vec<_>>();
    commands.sort_by_key(|command| keybinding_command_label(command));
    commands
}

pub fn keybinding_command_label(command: &str) -> String {
    if let Some(script_name) = command
        .strip_prefix("script.")
        .and_then(|value| value.strip_suffix(".run"))
    {
        return format!("Run Script: {}", title_case_command_segment(script_name));
    }

    command
        .split('.')
        .map(title_case_command_segment)
        .collect::<Vec<_>>()
        .join(": ")
}

fn title_case_command_segment(segment: &str) -> String {
    let mut separated = String::new();
    let mut previous_was_lower_or_digit = false;
    for ch in segment.chars() {
        if ch.is_ascii_uppercase() && previous_was_lower_or_digit {
            separated.push(' ');
        }
        separated.push(ch);
        previous_was_lower_or_digit = ch.is_ascii_lowercase() || ch.is_ascii_digit();
    }

    separated
        .split(|ch: char| ch == '-' || ch == '_' || ch.is_whitespace())
        .filter(|part| !part.is_empty())
        .map(|part| {
            let mut chars = part.chars();
            match chars.next() {
                Some(first) => {
                    let mut out = String::new();
                    out.push(first.to_ascii_uppercase());
                    out.push_str(chars.as_str());
                    out
                }
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

pub fn build_default_keybinding_rows() -> Vec<KeybindingSettingsRow> {
    let mut rows = DEFAULT_KEYBINDING_RULES
        .iter()
        .map(|rule| KeybindingSettingsRow {
            command_id: rule.command,
            command_label: keybinding_command_label(rule.command),
            key: rule.key,
            when: rule.when,
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        left.command_id
            .cmp(right.command_id)
            .then_with(|| left.key.cmp(right.key))
    });
    rows
}

pub fn score_model_picker_search(model: &ModelPickerItem, query: &str) -> Option<isize> {
    const FAVORITE_SCORE_BOOST: isize = 24;
    let tokens = normalize_search_query(query)
        .split_whitespace()
        .filter(|token| !token.is_empty())
        .map(str::to_string)
        .collect::<Vec<_>>();
    if tokens.is_empty() {
        return Some(0);
    }

    let fields = [
        normalize_search_query(&model.name),
        model
            .short_name
            .as_deref()
            .map(normalize_search_query)
            .unwrap_or_default(),
        model
            .sub_provider
            .as_deref()
            .map(normalize_search_query)
            .unwrap_or_default(),
        normalize_search_query(&model.driver_kind),
        normalize_search_query(&model.instance_display_name),
        build_model_picker_search_text(model),
    ];

    let mut score = 0isize;
    for token in tokens {
        let token_score = fields
            .iter()
            .enumerate()
            .filter(|(_, field)| !field.is_empty())
            .filter_map(|(index, field)| {
                let field_base = index * 10;
                score_query_match(
                    field,
                    &token,
                    field_base,
                    Some(field_base + 2),
                    Some(field_base + 4),
                    Some(field_base + 6),
                    (token.len() >= 3).then_some(field_base + 100),
                )
            })
            .min()?;
        score += token_score as isize;
    }

    Some(if model.is_favorite {
        score - FAVORITE_SCORE_BOOST
    } else {
        score
    })
}

pub fn sort_provider_model_items(
    items: &[ModelPickerItem],
    favorite_model_keys: &[String],
    group_favorites: bool,
    instance_order: &[String],
) -> Vec<ModelPickerItem> {
    let instance_rank = instance_order
        .iter()
        .enumerate()
        .map(|(index, instance_id)| (instance_id.clone(), index))
        .collect::<BTreeMap<_, _>>();
    let original_rank = items
        .iter()
        .enumerate()
        .map(|(index, item)| (provider_model_key(&item.instance_id, &item.slug), index))
        .collect::<BTreeMap<_, _>>();
    let mut indexed = items.to_vec();
    indexed.sort_by(|left, right| {
        if group_favorites {
            let left_fav =
                is_favorite_model_key(favorite_model_keys, &left.instance_id, &left.slug);
            let right_fav =
                is_favorite_model_key(favorite_model_keys, &right.instance_id, &right.slug);
            if left_fav != right_fav {
                return right_fav.cmp(&left_fav);
            }
        }

        let left_instance_rank = instance_rank
            .get(&left.instance_id)
            .copied()
            .unwrap_or(usize::MAX);
        let right_instance_rank = instance_rank
            .get(&right.instance_id)
            .copied()
            .unwrap_or(usize::MAX);
        left_instance_rank.cmp(&right_instance_rank).then_with(|| {
            let left_key = provider_model_key(&left.instance_id, &left.slug);
            let right_key = provider_model_key(&right.instance_id, &right.slug);
            original_rank
                .get(&left_key)
                .copied()
                .unwrap_or(usize::MAX)
                .cmp(&original_rank.get(&right_key).copied().unwrap_or(usize::MAX))
        })
    });
    indexed
}

pub fn normalize_model_slug(model: Option<&str>, provider: &str) -> Option<String> {
    let trimmed = model?.trim();
    if trimmed.is_empty() {
        return None;
    }
    let aliased = match provider {
        "codex" => match trimmed {
            "gpt-5-codex" | "5.4" => Some("gpt-5.4"),
            "5.3" | "gpt-5.3" => Some("gpt-5.3-codex"),
            "5.3-spark" | "gpt-5.3-spark" => Some("gpt-5.3-codex-spark"),
            _ => None,
        },
        "claudeAgent" => match trimmed {
            "opus" | "opus-4.7" | "claude-opus-4.7" => Some("claude-opus-4-7"),
            "opus-4.6" | "claude-opus-4.6" | "claude-opus-4-6-20251117" => Some("claude-opus-4-6"),
            "sonnet" | "sonnet-4.6" | "claude-sonnet-4.6" | "claude-sonnet-4-6-20251117" => {
                Some("claude-sonnet-4-6")
            }
            "haiku" | "haiku-4.5" | "claude-haiku-4.5" | "claude-haiku-4-5-20251001" => {
                Some("claude-haiku-4-5")
            }
            _ => None,
        },
        "cursor" => match trimmed {
            "composer" => Some("composer-2"),
            "composer-1" => Some("composer-1.5"),
            "composer-1.5" => Some("composer-1.5"),
            "opus-4.6-thinking" | "opus-4.6" => Some("claude-opus-4-6"),
            "sonnet-4.6-thinking" | "sonnet-4.6" => Some("claude-sonnet-4-6"),
            "opus-4.5-thinking" | "opus-4.5" => Some("claude-opus-4-5"),
            _ => None,
        },
        _ => None,
    };
    Some(aliased.unwrap_or(trimmed).to_string())
}

pub fn resolve_selectable_model(
    provider: &str,
    value: Option<&str>,
    options: &[ServerProviderModel],
) -> Option<String> {
    let trimmed = value?.trim();
    if trimmed.is_empty() {
        return None;
    }
    if let Some(direct) = options.iter().find(|option| option.slug == trimmed) {
        return Some(direct.slug.clone());
    }
    if let Some(by_name) = options
        .iter()
        .find(|option| option.name.eq_ignore_ascii_case(trimmed))
    {
        return Some(by_name.slug.clone());
    }
    let normalized = normalize_model_slug(Some(trimmed), provider)?;
    options
        .iter()
        .find(|option| option.slug == normalized)
        .map(|option| option.slug.clone())
}

fn matches_locked_provider(
    entry: &ProviderInstanceEntry,
    locked_provider: Option<&str>,
    locked_continuation_group_key: Option<&str>,
) -> bool {
    let Some(locked_provider) = locked_provider else {
        return true;
    };
    if entry.driver_kind != locked_provider {
        return false;
    }
    locked_continuation_group_key
        .filter(|key| !key.is_empty())
        .map(|key| entry.continuation_group_key.as_deref() == Some(key))
        .unwrap_or(true)
}

pub fn resolve_model_picker_state(
    snapshot: &AppSnapshot,
    search_query: &str,
    selected_instance: Option<ModelPickerSelectedInstance>,
    locked_provider: Option<&str>,
    locked_continuation_group_key: Option<&str>,
) -> ModelPickerState {
    let entries = derive_provider_instance_entries(&snapshot.providers);
    let active_entry = entries
        .iter()
        .find(|entry| entry.instance_id == snapshot.selected_provider_instance_id)
        .cloned();
    let selected_options = active_entry
        .as_ref()
        .map(|entry| entry.models.as_slice())
        .unwrap_or(&[]);
    let selected_model = selected_options
        .iter()
        .find(|option| option.slug == snapshot.selected_model)
        .or_else(|| selected_options.first());
    let trigger_title = selected_model
        .map(get_trigger_display_model_name)
        .unwrap_or_else(|| snapshot.selected_model.clone());
    let trigger_subtitle = selected_model.and_then(|model| model.sub_provider.clone());
    let trigger_label = selected_model
        .map(get_trigger_display_model_label)
        .unwrap_or_else(|| snapshot.selected_model.clone());
    let duplicate_driver_count = active_entry
        .as_ref()
        .map(|active| {
            entries
                .iter()
                .filter(|entry| entry.driver_kind == active.driver_kind)
                .count()
        })
        .unwrap_or(0);
    let show_instance_badge = active_entry
        .as_ref()
        .map(|entry| entry.accent_color.is_some() || duplicate_driver_count > 1)
        .unwrap_or(false);
    let favorite_keys = favorite_model_key_set(&snapshot.model_favorites);
    let selected_instance = selected_instance.unwrap_or_else(|| {
        if locked_provider.is_some() {
            ModelPickerSelectedInstance::Instance(snapshot.selected_provider_instance_id.clone())
        } else if !snapshot.model_favorites.is_empty() {
            ModelPickerSelectedInstance::Favorites
        } else {
            ModelPickerSelectedInstance::Instance(snapshot.selected_provider_instance_id.clone())
        }
    });
    let is_locked = locked_provider.is_some();
    let locked_instance_entries = locked_provider
        .map(|_| {
            entries
                .iter()
                .filter(|entry| {
                    matches_locked_provider(entry, locked_provider, locked_continuation_group_key)
                })
                .cloned()
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let show_locked_instance_sidebar = is_locked && locked_instance_entries.len() > 1;
    let is_searching = !search_query.trim().is_empty();
    let show_sidebar = !is_searching && (!is_locked || show_locked_instance_sidebar);
    let sidebar_entries = if show_locked_instance_sidebar {
        locked_instance_entries.clone()
    } else {
        entries.clone()
    };
    let mut flat_models = Vec::<ModelPickerItem>::new();
    for entry in &entries {
        if entry.status != ServerProviderState::Ready {
            continue;
        }
        for model in &entry.models {
            flat_models.push(ModelPickerItem {
                slug: model.slug.clone(),
                name: model.name.clone(),
                short_name: model.short_name.clone(),
                sub_provider: model.sub_provider.clone(),
                instance_id: entry.instance_id.clone(),
                driver_kind: entry.driver_kind.clone(),
                instance_display_name: entry.display_name.clone(),
                instance_accent_color: entry.accent_color.clone(),
                continuation_group_key: entry.continuation_group_key.clone(),
                is_favorite: is_favorite_model_key(&favorite_keys, &entry.instance_id, &model.slug),
            });
        }
    }

    let filtered_models = if is_searching {
        let mut ranked = flat_models
            .into_iter()
            .filter(|model| {
                locked_provider
                    .map(|_| {
                        matches_locked_provider(
                            &ProviderInstanceEntry {
                                instance_id: model.instance_id.clone(),
                                driver_kind: model.driver_kind.clone(),
                                display_name: model.instance_display_name.clone(),
                                accent_color: model.instance_accent_color.clone(),
                                continuation_group_key: model.continuation_group_key.clone(),
                                enabled: true,
                                installed: true,
                                status: ServerProviderState::Ready,
                                is_default: false,
                                is_available: true,
                                models: Vec::new(),
                            },
                            locked_provider,
                            locked_continuation_group_key,
                        )
                    })
                    .unwrap_or(true)
            })
            .filter_map(|model| {
                score_model_picker_search(&model, search_query).map(|score| {
                    let tie_breaker = build_model_picker_search_text(&model);
                    (model, score, tie_breaker)
                })
            })
            .collect::<Vec<_>>();
        ranked.sort_by(
            |(left, left_score, left_tie), (right, right_score, right_tie)| {
                left_score
                    .cmp(right_score)
                    .then_with(|| right.is_favorite.cmp(&left.is_favorite))
                    .then_with(|| left_tie.cmp(right_tie))
            },
        );
        ranked.into_iter().map(|(model, _, _)| model).collect()
    } else {
        let mut result = flat_models
            .into_iter()
            .filter(|model| {
                locked_provider
                    .map(|_| {
                        model.driver_kind == locked_provider.unwrap_or_default()
                            && locked_continuation_group_key
                                .filter(|key| !key.is_empty())
                                .map(|key| model.continuation_group_key.as_deref() == Some(key))
                                .unwrap_or(true)
                    })
                    .unwrap_or(true)
            })
            .collect::<Vec<_>>();

        if is_locked {
            if show_locked_instance_sidebar {
                if let Some(instance_id) = selected_instance.instance_id() {
                    result.retain(|model| model.instance_id == instance_id);
                }
            }
        } else if selected_instance == ModelPickerSelectedInstance::Favorites {
            result.retain(|model| model.is_favorite);
        } else if let Some(instance_id) = selected_instance.instance_id() {
            result.retain(|model| model.instance_id == instance_id);
        }

        let instance_order = if selected_instance == ModelPickerSelectedInstance::Favorites {
            entries
                .iter()
                .map(|entry| entry.instance_id.clone())
                .collect::<Vec<_>>()
        } else {
            Vec::new()
        };
        sort_provider_model_items(
            &result,
            &favorite_keys,
            selected_instance != ModelPickerSelectedInstance::Favorites,
            &instance_order,
        )
    };

    let locked_header_label = if is_locked && !show_locked_instance_sidebar {
        let matches = entries
            .iter()
            .filter(|entry| {
                matches_locked_provider(entry, locked_provider, locked_continuation_group_key)
            })
            .collect::<Vec<_>>();
        if matches.is_empty() {
            None
        } else {
            matches
                .iter()
                .find(|entry| entry.instance_id == snapshot.selected_provider_instance_id)
                .copied()
                .or_else(|| matches.first().copied())
                .map(|entry| entry.display_name.clone())
        }
    } else {
        None
    };

    ModelPickerState {
        active_entry,
        trigger_title,
        trigger_subtitle,
        trigger_label,
        show_instance_badge,
        selected_instance,
        is_locked,
        show_locked_instance_sidebar,
        show_sidebar,
        sidebar_entries,
        locked_header_label,
        filtered_models,
    }
}

const MAX_SCRIPT_ID_LENGTH: usize = 64;

pub fn command_for_project_script(script_id: &str) -> String {
    format!("script.{script_id}.run")
}

pub fn project_script_id_from_command(command: &str) -> Option<String> {
    let trimmed = command.trim();
    let prefix = "script.";
    let suffix = ".run";
    if !trimmed.starts_with(prefix) || !trimmed.ends_with(suffix) {
        return None;
    }
    let script_id = &trimmed[prefix.len()..trimmed.len() - suffix.len()];
    if script_id.is_empty() {
        None
    } else {
        Some(script_id.to_string())
    }
}

fn normalize_script_id(value: &str) -> String {
    let mut cleaned = String::new();
    let mut last_was_dash = false;
    for ch in value.trim().chars().flat_map(char::to_lowercase) {
        if ch.is_ascii_alphanumeric() {
            cleaned.push(ch);
            last_was_dash = false;
        } else if !last_was_dash && !cleaned.is_empty() {
            cleaned.push('-');
            last_was_dash = true;
        }
    }
    while cleaned.ends_with('-') {
        cleaned.pop();
    }
    if cleaned.is_empty() {
        return "script".to_string();
    }
    if cleaned.len() <= MAX_SCRIPT_ID_LENGTH {
        return cleaned;
    }
    let mut truncated = cleaned[..MAX_SCRIPT_ID_LENGTH]
        .trim_end_matches('-')
        .to_string();
    if truncated.is_empty() {
        truncated = "script".to_string();
    }
    truncated
}

pub fn next_project_script_id<I, S>(name: &str, existing_ids: I) -> String
where
    I: IntoIterator<Item = S>,
    S: AsRef<str>,
{
    let taken = existing_ids
        .into_iter()
        .map(|id| id.as_ref().to_string())
        .collect::<Vec<_>>();
    let base_id = normalize_script_id(name);
    if !taken.iter().any(|id| id == &base_id) {
        return base_id;
    }

    for suffix in 2..10_000 {
        let candidate = format!("{base_id}-{suffix}");
        let safe_candidate = if candidate.len() <= MAX_SCRIPT_ID_LENGTH {
            candidate
        } else {
            let suffix_len = suffix.to_string().len();
            let prefix_len = MAX_SCRIPT_ID_LENGTH.saturating_sub(suffix_len + 1).max(1);
            format!("{}-{suffix}", &base_id[..prefix_len])
        };
        if !taken.iter().any(|id| id == &safe_candidate) {
            return safe_candidate;
        }
    }

    base_id
}

pub fn primary_project_script(scripts: &[ProjectScript]) -> Option<&ProjectScript> {
    scripts
        .iter()
        .find(|script| !script.run_on_worktree_create)
        .or_else(|| scripts.first())
}

pub fn setup_project_script(scripts: &[ProjectScript]) -> Option<&ProjectScript> {
    scripts.iter().find(|script| script.run_on_worktree_create)
}

pub const SOURCE_CONTROL_DEFAULT_FETCH_INTERVAL_SECONDS: u32 = 30;

