pub fn source_control_repository_error(
    provider: SourceControlProviderKind,
    operation: &str,
    detail: &str,
) -> SourceControlRepositoryErrorContract {
    source_control_repository_error_with_cause(provider, operation, detail, None)
}

pub fn source_control_repository_error_with_cause(
    provider: SourceControlProviderKind,
    operation: &str,
    detail: &str,
    cause: Option<&str>,
) -> SourceControlRepositoryErrorContract {
    SourceControlRepositoryErrorContract {
        provider,
        operation: operation.to_string(),
        detail: detail.to_string(),
        cause: trimmed_optional_string(cause),
    }
}

pub fn source_control_repository_detail_from_unknown(
    detail: Option<&str>,
    message: Option<&str>,
) -> String {
    trimmed_optional_string(detail)
        .or_else(|| trimmed_optional_string(message))
        .unwrap_or_else(|| "An unexpected source control error occurred.".to_string())
}

pub fn source_control_map_repository_error(
    existing: Option<SourceControlRepositoryErrorContract>,
    operation: &str,
    provider: SourceControlProviderKind,
    detail: Option<&str>,
    message: Option<&str>,
    cause: Option<&str>,
) -> SourceControlRepositoryErrorContract {
    existing.unwrap_or_else(|| {
        source_control_repository_error_with_cause(
            provider,
            operation,
            &source_control_repository_detail_from_unknown(detail, message),
            cause,
        )
    })
}

pub fn source_control_ensure_concrete_provider(
    provider: SourceControlProviderKind,
    operation: &str,
) -> Result<SourceControlProviderKind, SourceControlRepositoryErrorContract> {
    if provider != SourceControlProviderKind::Unknown {
        return Ok(provider);
    }
    Err(source_control_repository_error(
        provider,
        operation,
        "Choose a source control provider before continuing.",
    ))
}

