fn bitbucket_api_error(
    operation: &str,
    detail: &str,
    status: Option<u16>,
    cause: Option<&str>,
) -> BitbucketApiErrorContract {
    BitbucketApiErrorContract {
        operation: operation.to_string(),
        detail: detail.to_string(),
        status,
        cause: trimmed_optional_string(cause),
    }
}

pub fn bitbucket_api_request_error(operation: &str, cause: &str) -> BitbucketApiErrorContract {
    bitbucket_api_error(operation, cause, None, Some(cause))
}

pub fn bitbucket_api_response_error(
    operation: &str,
    status: u16,
    body: Option<&str>,
) -> BitbucketApiErrorContract {
    let detail = trimmed_optional_string(body)
        .map(|body| format!("Bitbucket returned HTTP {status}: {body}"))
        .unwrap_or_else(|| format!("Bitbucket returned HTTP {status}."));
    bitbucket_api_error(operation, &detail, Some(status), None)
}

pub fn bitbucket_api_invalid_json_error(operation: &str, cause: &str) -> BitbucketApiErrorContract {
    bitbucket_api_error(
        operation,
        "Bitbucket returned invalid JSON for the requested resource.",
        None,
        Some(cause),
    )
}

pub fn bitbucket_resolve_repository_error(
    operation: &str,
    cwd: &str,
    cause: Option<&str>,
) -> BitbucketApiErrorContract {
    let detail = match operation {
        "resolveRepository.vcs" => format!("Failed to resolve VCS repository for {cwd}."),
        "resolveRepository.remotes" => format!("Failed to list remotes for {cwd}."),
        _ => format!("No Bitbucket repository remote was detected for {cwd}."),
    };
    bitbucket_api_error("resolveRepository", &detail, None, cause)
}

pub fn bitbucket_default_change_request_target_branch(
    repository_main_branch: Option<&str>,
    development_branch_name: Option<&str>,
    development_name: Option<&str>,
    development_use_mainbranch: Option<bool>,
    development_is_valid: Option<bool>,
) -> Option<String> {
    let repository_main_branch = trimmed_optional_string(repository_main_branch);
    if development_use_mainbranch == Some(true) || development_is_valid == Some(false) {
        return repository_main_branch;
    }

    let development_branch = trimmed_optional_string(development_branch_name)
        .or_else(|| trimmed_optional_string(development_name));
    match development_branch.as_deref() {
        Some("null") | None => repository_main_branch,
        Some(_) => development_branch,
    }
}

pub fn bitbucket_create_repository_request_plan(
    base_url: &str,
    repository: &BitbucketRepositoryLocator,
    visibility: SourceControlRepositoryVisibility,
) -> BitbucketApiRequestPlan {
    let mut plan = bitbucket_repository_request_plan(base_url, repository);
    plan.method = "POST";
    plan.json_body = Some(
        serde_json::json!({
            "scm": "git",
            "is_private": visibility == SourceControlRepositoryVisibility::Private,
        })
        .to_string(),
    );
    plan
}

pub fn bitbucket_create_pull_request_request_plan(
    base_url: &str,
    repository: &BitbucketRepositoryLocator,
    base_branch: &str,
    head_selector: &str,
    source: Option<&SourceControlRefSelector>,
    target: Option<&SourceControlRefSelector>,
    title: &str,
    body: &str,
) -> BitbucketApiRequestPlan {
    let branch = source_control_branch(head_selector, source);
    let mut source_object = serde_json::json!({
        "branch": { "name": branch },
    });
    if let Some(workspace) = bitbucket_source_workspace(head_selector, source) {
        source_object["repository"] = serde_json::json!({
            "full_name": format!("{}/{}", workspace, repository.repo_slug),
        });
    }
    let destination_branch = target.map_or(base_branch, |target| target.ref_name.as_str());
    BitbucketApiRequestPlan {
        method: "POST",
        url: bitbucket_api_url(
            base_url,
            &format!(
                "/repositories/{}/{}/pullrequests",
                encode_uri_component(&repository.workspace),
                encode_uri_component(&repository.repo_slug)
            ),
        ),
        query_params: Vec::new(),
        json_body: Some(
            serde_json::json!({
                "title": title,
                "description": body,
                "source": source_object,
                "destination": {
                    "branch": { "name": destination_branch },
                },
            })
            .to_string(),
        ),
    }
}

pub fn sanitize_branch_fragment(raw: &str) -> String {
    let mut normalized = raw
        .trim()
        .to_ascii_lowercase()
        .chars()
        .filter(|character| !matches!(character, '\'' | '"' | '`'))
        .collect::<String>();
    normalized = normalized
        .trim_matches(|character: char| {
            matches!(character, '.' | '/' | '_' | '-') || character.is_whitespace()
        })
        .to_string();

    let mut fragment = String::new();
    let mut previous_dash = false;
    let mut previous_slash = false;
    for character in normalized.chars() {
        let mapped = if character.is_ascii_lowercase()
            || character.is_ascii_digit()
            || matches!(character, '/' | '_' | '-')
        {
            character
        } else {
            '-'
        };
        if mapped == '/' {
            if !previous_slash {
                fragment.push(mapped);
            }
            previous_slash = true;
            previous_dash = false;
        } else if mapped == '-' {
            if !previous_dash {
                fragment.push(mapped);
            }
            previous_dash = true;
            previous_slash = false;
        } else {
            fragment.push(mapped);
            previous_dash = false;
            previous_slash = false;
        }
    }
    let mut fragment = fragment
        .trim_matches(|character: char| matches!(character, '.' | '/' | '_' | '-'))
        .chars()
        .take(64)
        .collect::<String>();
    fragment = fragment
        .trim_end_matches(|character: char| matches!(character, '.' | '/' | '_' | '-'))
        .to_string();
    if fragment.is_empty() {
        "update".to_string()
    } else {
        fragment
    }
}

pub fn bitbucket_checkout_branch_name(
    pull_request_id: u32,
    head_branch: &str,
    is_cross_repository: bool,
) -> String {
    if !is_cross_repository {
        return head_branch.to_string();
    }
    format!(
        "t3code/pr-{}/{}",
        pull_request_id,
        sanitize_branch_fragment(head_branch)
    )
}

pub fn bitbucket_should_prefer_ssh_remote(origin_remote_url: Option<&str>) -> bool {
    let trimmed = origin_remote_url.unwrap_or("").trim();
    trimmed.starts_with("git@") || trimmed.starts_with("ssh://")
}

pub fn bitbucket_select_clone_url(
    clone_urls: &SourceControlRepositoryCloneUrls,
    origin_remote_url: Option<&str>,
) -> String {
    if bitbucket_should_prefer_ssh_remote(origin_remote_url) {
        clone_urls.ssh_url.clone()
    } else {
        clone_urls.url.clone()
    }
}

fn repository_owner_name(repository_name: &str) -> String {
    repository_name
        .split('/')
        .next()
        .map(str::trim)
        .filter(|owner| !owner.is_empty())
        .unwrap_or("bitbucket")
        .to_string()
}

pub fn bitbucket_checkout_plan(
    cwd: &str,
    context: Option<&SourceControlProviderContext>,
    destination_repository: &BitbucketRepositoryLocator,
    destination_repository_name: &str,
    source_repository_name: &str,
    pull_request_id: u32,
    remote_branch: &str,
    source_clone_urls: &SourceControlRepositoryCloneUrls,
    origin_remote_url: Option<&str>,
    primary_remote_name: Option<&str>,
    local_branch_names: &[String],
    force: bool,
) -> BitbucketCheckoutPlan {
    let is_cross_repository = source_repository_name != destination_repository_name;
    let mut ensure_remote = None;
    let remote_name = if context.is_some_and(|context| {
        context.provider.kind == SourceControlProviderKind::Bitbucket
            && !is_cross_repository
            && parse_bitbucket_remote_url(&context.remote_url).is_some()
    }) {
        context.unwrap().remote_name.clone()
    } else if !is_cross_repository && primary_remote_name.is_some() {
        primary_remote_name.unwrap().to_string()
    } else {
        let preferred_name = if is_cross_repository {
            repository_owner_name(source_repository_name)
        } else {
            destination_repository.workspace.clone()
        };
        let url = bitbucket_select_clone_url(source_clone_urls, origin_remote_url);
        ensure_remote = Some(SourceControlEnsureRemotePlan {
            cwd: cwd.to_string(),
            preferred_name: preferred_name.clone(),
            url,
        });
        preferred_name
    };
    let local_branch =
        bitbucket_checkout_branch_name(pull_request_id, remote_branch, is_cross_repository);
    let local_branch_exists = local_branch_names
        .iter()
        .any(|branch_name| branch_name == &local_branch);
    let (fetch_remote_branch, fetch_remote_tracking_branch) = if force || !local_branch_exists {
        (
            Some(SourceControlFetchRemoteBranchPlan {
                cwd: cwd.to_string(),
                remote_name: remote_name.clone(),
                remote_branch: remote_branch.to_string(),
                local_branch: local_branch.clone(),
            }),
            None,
        )
    } else {
        (
            None,
            Some(SourceControlFetchRemoteTrackingBranchPlan {
                cwd: cwd.to_string(),
                remote_name: remote_name.clone(),
                remote_branch: remote_branch.to_string(),
            }),
        )
    };

    BitbucketCheckoutPlan {
        remote_name: remote_name.clone(),
        local_branch: local_branch.clone(),
        ensure_remote,
        fetch_remote_branch,
        fetch_remote_tracking_branch,
        set_upstream: SourceControlSetBranchUpstreamPlan {
            cwd: cwd.to_string(),
            branch: local_branch.clone(),
            remote_name: remote_name.clone(),
            remote_branch: remote_branch.to_string(),
        },
        switch_ref: SourceControlSwitchRefPlan {
            cwd: cwd.to_string(),
            ref_name: local_branch,
        },
    }
}

fn source_control_change_request(
    provider: SourceControlProviderKind,
    summary: &SourceControlChangeRequestSummary,
    state: ChangeRequestState,
    updated_at: Option<String>,
    force_cross_repository: Option<bool>,
) -> ChangeRequest {
    ChangeRequest {
        provider,
        number: summary.number,
        title: summary.title.clone(),
        url: summary.url.clone(),
        base_ref_name: summary.base_ref_name.clone(),
        head_ref_name: summary.head_ref_name.clone(),
        state,
        updated_at,
        is_cross_repository: force_cross_repository.or(summary.is_cross_repository),
        head_repository_name_with_owner: summary.head_repository_name_with_owner.clone(),
        head_repository_owner_login: summary.head_repository_owner_login.clone(),
    }
}

