pub const BITBUCKET_DISCOVERY_INSTALL_HINT: &str = "Set T3CODE_BITBUCKET_EMAIL and T3CODE_BITBUCKET_API_TOKEN on the server (use a Bitbucket API token with pull request and repository scopes).";

pub const BITBUCKET_AUTH_CONFIG_DETAIL: &str =
    "Set T3CODE_BITBUCKET_EMAIL and T3CODE_BITBUCKET_API_TOKEN, or T3CODE_BITBUCKET_ACCESS_TOKEN.";

pub fn bitbucket_api_discovery_spec() -> SourceControlApiDiscoverySpec {
    SourceControlApiDiscoverySpec {
        kind: SourceControlProviderKind::Bitbucket,
        label: "Bitbucket",
        install_hint: BITBUCKET_DISCOVERY_INSTALL_HINT,
    }
}

pub fn bitbucket_user_auth(
    username: Option<&str>,
    display_name: Option<&str>,
    account_id: Option<&str>,
) -> SourceControlProviderAuth {
    source_control_provider_auth(
        SourceControlProviderAuthStatus::Authenticated,
        trimmed_optional_string(username)
            .or_else(|| trimmed_optional_string(display_name))
            .or_else(|| trimmed_optional_string(account_id))
            .as_deref(),
        Some("bitbucket.org"),
        None,
    )
}

pub fn bitbucket_auth_from_config(
    access_token: Option<&str>,
    email: Option<&str>,
    api_token: Option<&str>,
) -> SourceControlProviderAuth {
    if trimmed_optional_string(access_token).is_some() {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Unknown,
            None,
            Some("bitbucket.org"),
            Some("Bitbucket access token is configured."),
        );
    }

    if let (Some(email), Some(_api_token)) = (
        trimmed_optional_string(email),
        trimmed_optional_string(api_token),
    ) {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Unknown,
            Some(&email),
            Some("bitbucket.org"),
            Some("Bitbucket API token is configured."),
        );
    }

    source_control_provider_auth(
        SourceControlProviderAuthStatus::Unauthenticated,
        None,
        Some("bitbucket.org"),
        Some(BITBUCKET_AUTH_CONFIG_DETAIL),
    )
}

pub fn source_control_api_provider_discovery_item(
    spec: &SourceControlApiDiscoverySpec,
    auth: SourceControlProviderAuth,
) -> SourceControlProviderDiscoveryItem {
    SourceControlProviderDiscoveryItem {
        kind: spec.kind,
        label: spec.label.to_string(),
        executable: None,
        status: SourceControlDiscoveryStatus::Available,
        version: None,
        install_hint: spec.install_hint.to_string(),
        detail: None,
        auth,
    }
}

fn source_control_account_after_marker(line: &str, marker: &str) -> Option<String> {
    let lower = line.to_ascii_lowercase();
    let marker_index = lower.find(marker)?;
    let rest = line[marker_index + marker.len()..].trim_start();
    let account = rest
        .split(|character: char| character.is_whitespace() || character == '(')
        .next()
        .unwrap_or("")
        .trim();
    (!account.is_empty()).then(|| account.to_string())
}

fn source_control_account_after_label(line: &str, label: &str) -> Option<String> {
    let lower = line.to_ascii_lowercase();
    let label_index = lower.find(label)?;
    let rest = line[label_index + label.len()..].trim_start();
    let account = rest
        .split(|character: char| character.is_whitespace() || character == '(')
        .next()
        .unwrap_or("")
        .trim();
    (!account.is_empty()).then(|| account.to_string())
}

pub fn parse_github_source_control_auth(
    input: &SourceControlAuthProbeInput,
) -> SourceControlProviderAuth {
    let output = source_control_combined_auth_output(input);
    let account = output.lines().find_map(|line| {
        source_control_account_after_marker(line, " account ")
            .or_else(|| source_control_account_after_marker(line, " as "))
    });
    let host = source_control_parse_cli_host(&output);

    if input.exit_code != 0 {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Unauthenticated,
            None,
            host.as_deref(),
            source_control_first_safe_auth_line(&output)
                .as_deref()
                .or(Some("Run `gh auth login` to authenticate GitHub CLI.")),
        );
    }

    if let Some(account) = account {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Authenticated,
            Some(&account),
            host.as_deref(),
            None,
        );
    }

    source_control_provider_auth(
        SourceControlProviderAuthStatus::Unknown,
        None,
        host.as_deref(),
        source_control_first_safe_auth_line(&output)
            .as_deref()
            .or(Some("GitHub CLI auth status could not be parsed.")),
    )
}

pub fn parse_gitlab_source_control_auth(
    input: &SourceControlAuthProbeInput,
) -> SourceControlProviderAuth {
    let output = source_control_combined_auth_output(input);
    let account = output.lines().find_map(|line| {
        source_control_account_after_marker(line, " as ")
            .or_else(|| source_control_account_after_marker(line, " account "))
            .or_else(|| source_control_account_after_label(line, "account:"))
    });
    let host = source_control_parse_cli_host(&output);

    if input.exit_code != 0 {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Unauthenticated,
            None,
            host.as_deref(),
            source_control_first_safe_auth_line(&output)
                .as_deref()
                .or(Some("Run `glab auth login` to authenticate GitLab CLI.")),
        );
    }

    if let Some(account) = account {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Authenticated,
            Some(&account),
            host.as_deref(),
            None,
        );
    }

    source_control_provider_auth(
        SourceControlProviderAuthStatus::Unknown,
        None,
        host.as_deref(),
        source_control_first_safe_auth_line(&output)
            .as_deref()
            .or(Some("GitLab CLI auth status could not be parsed.")),
    )
}

pub fn parse_azure_devops_source_control_auth(
    input: &SourceControlAuthProbeInput,
) -> SourceControlProviderAuth {
    let account = input.stdout.lines().next().map(str::trim).unwrap_or("");

    if input.exit_code != 0 {
        let output = source_control_combined_auth_output(input);
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Unauthenticated,
            None,
            None,
            source_control_first_safe_auth_line(&output)
                .as_deref()
                .or(Some("Run `az login` to authenticate Azure CLI.")),
        );
    }

    if !account.is_empty() {
        return source_control_provider_auth(
            SourceControlProviderAuthStatus::Authenticated,
            Some(account),
            Some("dev.azure.com"),
            None,
        );
    }

    source_control_provider_auth(
        SourceControlProviderAuthStatus::Unknown,
        None,
        Some("dev.azure.com"),
        Some("Azure CLI account status could not be parsed."),
    )
}

