pub fn scope_project_ref(environment_id: &str, project_id: &str) -> ScopedProjectRef {
    ScopedProjectRef::new(environment_id, project_id)
}

pub fn scope_thread_ref(environment_id: &str, thread_id: &str) -> ScopedThreadRef {
    ScopedThreadRef::new(environment_id, thread_id)
}

pub fn scoped_project_key(ref_: &ScopedProjectRef) -> String {
    format!("{}:{}", ref_.environment_id, ref_.project_id)
}

pub fn scoped_thread_key(ref_: &ScopedThreadRef) -> String {
    format!("{}:{}", ref_.environment_id, ref_.thread_id)
}

pub fn resolve_thread_action_project_ref(
    context: &ChatThreadActionContext,
) -> Option<ScopedProjectRef> {
    if let Some(active_thread) = context.active_thread.as_ref() {
        return Some(scope_project_ref(
            &active_thread.environment_id,
            &active_thread.project_id,
        ));
    }
    if let Some(active_draft_thread) = context.active_draft_thread.as_ref() {
        return Some(scope_project_ref(
            &active_draft_thread.environment_id,
            &active_draft_thread.project_id,
        ));
    }
    context.default_project_ref.clone()
}

pub fn contextual_thread_action_options(
    context: &ChatThreadActionContext,
) -> ThreadActionNewThreadOptions {
    let branch = context
        .active_thread
        .as_ref()
        .and_then(|thread| thread.branch.clone())
        .or_else(|| {
            context
                .active_draft_thread
                .as_ref()
                .and_then(|thread| thread.branch.clone())
        });
    let worktree_path = context
        .active_thread
        .as_ref()
        .and_then(|thread| thread.worktree_path.clone())
        .or_else(|| {
            context
                .active_draft_thread
                .as_ref()
                .and_then(|thread| thread.worktree_path.clone())
        });
    let env_mode = context
        .active_draft_thread
        .as_ref()
        .map(|thread| thread.env_mode)
        .unwrap_or_else(|| {
            if context
                .active_thread
                .as_ref()
                .and_then(|thread| thread.worktree_path.as_ref())
                .is_some()
            {
                DraftThreadEnvMode::Worktree
            } else {
                DraftThreadEnvMode::Local
            }
        });

    ThreadActionNewThreadOptions {
        branch: Some(branch),
        worktree_path: Some(worktree_path),
        env_mode: Some(env_mode),
    }
}

pub fn default_thread_action_options(
    context: &ChatThreadActionContext,
) -> ThreadActionNewThreadOptions {
    ThreadActionNewThreadOptions {
        env_mode: Some(context.default_thread_env_mode),
        ..ThreadActionNewThreadOptions::default()
    }
}

pub fn start_new_thread_in_project_from_context_plan(
    context: &ChatThreadActionContext,
    project_ref: ScopedProjectRef,
) -> ThreadActionStartPlan {
    ThreadActionStartPlan {
        project_ref,
        options: contextual_thread_action_options(context),
    }
}

pub fn start_new_thread_from_context_plan(
    context: &ChatThreadActionContext,
) -> Option<ThreadActionStartPlan> {
    let project_ref = resolve_thread_action_project_ref(context)?;
    Some(start_new_thread_in_project_from_context_plan(
        context,
        project_ref,
    ))
}

pub fn start_new_local_thread_from_context_plan(
    context: &ChatThreadActionContext,
) -> Option<ThreadActionStartPlan> {
    let project_ref = resolve_thread_action_project_ref(context)?;
    Some(ThreadActionStartPlan {
        project_ref,
        options: default_thread_action_options(context),
    })
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ProjectAbsolutePathParts {
    root: String,
    separator: &'static str,
    segments: Vec<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ProjectPathCandidate {
    pub id: String,
    pub cwd: String,
}

fn project_absolute_path_kind(value: &str) -> Option<&'static str> {
    if shared::is_windows_drive_path(value) || shared::is_unc_path(value) {
        Some("windows")
    } else if value.starts_with('/') {
        Some("unix")
    } else {
        None
    }
}

pub fn normalize_project_path_for_dispatch(value: &str) -> String {
    trim_trailing_project_path_separators(value.trim())
}

pub fn normalize_project_path_for_comparison(value: &str) -> String {
    let normalized = normalize_project_path_for_dispatch(value);
    if shared::is_windows_drive_path(&normalized) || normalized.starts_with("\\\\") {
        normalized.replace('/', "\\").to_ascii_lowercase()
    } else {
        normalized
    }
}

pub fn is_explicit_relative_project_path(value: &str) -> bool {
    shared::is_explicit_relative_path(value)
}

pub fn has_trailing_project_path_separator(value: &str) -> bool {
    if project_absolute_path_kind(value) == Some("unix") {
        value.ends_with('/')
    } else {
        value.ends_with('/') || value.ends_with('\\')
    }
}

fn split_project_path_segments(value: &str, separator: &str) -> Vec<String> {
    if separator == "/" {
        value
            .split('/')
            .filter(|segment| !segment.is_empty())
            .map(str::to_string)
            .collect()
    } else {
        value
            .split(['/', '\\'])
            .filter(|segment| !segment.is_empty())
            .map(str::to_string)
            .collect()
    }
}

fn split_absolute_project_path(value: &str) -> Option<ProjectAbsolutePathParts> {
    if shared::is_windows_drive_path(value) {
        let root = format!("{}\\", &value[..2]);
        let rest_start = root.len().min(value.len());
        return Some(ProjectAbsolutePathParts {
            segments: split_project_path_segments(&value[rest_start..], "\\"),
            root,
            separator: "\\",
        });
    }
    if shared::is_unc_path(value) {
        let segments = split_project_path_segments(value, "\\");
        let server = segments.first()?;
        let share = segments.get(1)?;
        return Some(ProjectAbsolutePathParts {
            root: format!("\\\\{server}\\{share}\\"),
            separator: "\\",
            segments: segments.into_iter().skip(2).collect(),
        });
    }
    if value.starts_with('/') {
        return Some(ProjectAbsolutePathParts {
            root: "/".to_string(),
            separator: "/",
            segments: split_project_path_segments(&value[1..], "/"),
        });
    }
    None
}

fn preferred_project_path_separator(value: &str) -> &'static str {
    match project_absolute_path_kind(value) {
        Some("windows") => "\\",
        Some("unix") => "/",
        _ if value.contains('\\') => "\\",
        _ => "/",
    }
}

fn last_project_path_separator_index(value: &str) -> Option<usize> {
    if project_absolute_path_kind(value) == Some("unix") {
        value.rfind('/')
    } else {
        match (value.rfind('/'), value.rfind('\\')) {
            (Some(forward), Some(backward)) => Some(forward.max(backward)),
            (Some(index), None) | (None, Some(index)) => Some(index),
            (None, None) => None,
        }
    }
}

pub fn is_filesystem_browse_query(value: &str, platform: &str) -> bool {
    value.starts_with("./")
        || value.starts_with("../")
        || value.starts_with(".\\")
        || value.starts_with("..\\")
        || value.starts_with('/')
        || value.starts_with("~/")
        || (is_windows_platform(platform) && shared::is_windows_absolute_path(value))
}

pub fn is_unsupported_windows_project_path(value: &str, platform: &str) -> bool {
    shared::is_windows_absolute_path(value) && !is_windows_platform(platform)
}

pub fn resolve_project_path_for_dispatch(value: &str, cwd: Option<&str>) -> String {
    let trimmed_value = value.trim();
    if !shared::is_explicit_relative_path(trimmed_value) {
        return normalize_project_path_for_dispatch(trimmed_value);
    }
    let Some(cwd) = cwd else {
        return normalize_project_path_for_dispatch(trimmed_value);
    };
    let Some(absolute_base) =
        split_absolute_project_path(&normalize_project_path_for_dispatch(cwd))
    else {
        return normalize_project_path_for_dispatch(trimmed_value);
    };

    let mut next_segments = absolute_base.segments;
    for segment in trimmed_value.split(['/', '\\']) {
        if segment.is_empty() || segment == "." {
            continue;
        }
        if segment == ".." {
            next_segments.pop();
        } else {
            next_segments.push(segment.to_string());
        }
    }

    let joined_path = next_segments.join(absolute_base.separator);
    if joined_path.is_empty() {
        normalize_project_path_for_dispatch(&absolute_base.root)
    } else {
        normalize_project_path_for_dispatch(&format!("{}{}", absolute_base.root, joined_path))
    }
}

pub fn find_project_by_path<'a>(
    projects: &'a [ProjectPathCandidate],
    candidate_path: &str,
) -> Option<&'a ProjectPathCandidate> {
    let normalized_candidate = normalize_project_path_for_comparison(candidate_path);
    if normalized_candidate.is_empty() {
        return None;
    }
    projects
        .iter()
        .find(|project| normalize_project_path_for_comparison(&project.cwd) == normalized_candidate)
}

pub fn infer_project_title_from_path(value: &str) -> String {
    let normalized = normalize_project_path_for_dispatch(value);
    if let Some(absolute_path) = split_absolute_project_path(&normalized) {
        return absolute_path
            .segments
            .iter()
            .rev()
            .find(|segment| !segment.is_empty())
            .cloned()
            .unwrap_or(normalized);
    }

    normalized
        .split(['/', '\\'])
        .rev()
        .find(|segment| !segment.is_empty())
        .map(str::to_string)
        .unwrap_or(normalized)
}

pub fn get_browse_directory_path(current_path: &str) -> String {
    if has_trailing_project_path_separator(current_path) {
        return current_path.to_string();
    }
    let Some(last_separator_index) = last_project_path_separator_index(current_path) else {
        return current_path.to_string();
    };
    current_path[..=last_separator_index].to_string()
}

pub fn append_browse_path_segment(current_path: &str, segment: &str) -> String {
    let separator = preferred_project_path_separator(current_path);
    format!(
        "{}{}{}",
        get_browse_directory_path(current_path),
        segment,
        separator
    )
}

pub fn get_browse_leaf_path_segment(current_path: &str) -> String {
    let Some(last_separator_index) = last_project_path_separator_index(current_path) else {
        return current_path.to_string();
    };
    current_path[last_separator_index + 1..].to_string()
}

pub fn ensure_browse_directory_path(current_path: &str) -> String {
    let trimmed = current_path.trim();
    if trimmed.is_empty() || has_trailing_project_path_separator(trimmed) {
        return trimmed.to_string();
    }
    format!("{}{}", trimmed, preferred_project_path_separator(trimmed))
}

pub fn get_browse_parent_path(current_path: &str) -> Option<String> {
    let trimmed = trim_trailing_project_path_separators(current_path);
    if let Some(absolute_path) = split_absolute_project_path(&trimmed) {
        if absolute_path.segments.is_empty() {
            return None;
        }
        if absolute_path.segments.len() == 1 {
            return Some(absolute_path.root);
        }
        let parent_segments = absolute_path.segments[..absolute_path.segments.len() - 1]
            .join(absolute_path.separator);
        return Some(format!(
            "{}{}{}",
            absolute_path.root, parent_segments, absolute_path.separator
        ));
    }

    let separator = preferred_project_path_separator(current_path);
    let last_separator_index = last_project_path_separator_index(&trimmed)?;
    if last_separator_index == 2 && is_windows_drive_path(&trimmed) {
        return Some(format!("{}{}", &trimmed[..2], separator));
    }
    Some(trimmed[..=last_separator_index].to_string())
}

pub fn can_navigate_up(current_path: &str) -> bool {
    has_trailing_project_path_separator(current_path)
        && get_browse_parent_path(current_path).is_some()
}

pub fn derive_physical_project_key_from_path(environment_id: &str, cwd: &str) -> String {
    format!(
        "{}:{}",
        environment_id,
        normalize_project_path_for_comparison(cwd)
    )
}

pub fn derive_physical_project_key(project: &LogicalProject) -> String {
    derive_physical_project_key_from_path(&project.environment_id, &project.cwd)
}

pub fn derive_project_grouping_override_key(project: &LogicalProject) -> String {
    derive_physical_project_key(project)
}

pub fn get_project_order_key(project: &LogicalProject) -> String {
    derive_physical_project_key(project)
}

pub fn resolve_project_grouping_mode(
    project: &LogicalProject,
    settings: &ProjectGroupingSettings,
) -> SidebarProjectGroupingMode {
    settings
        .sidebar_project_grouping_overrides
        .get(&derive_project_grouping_override_key(project))
        .copied()
        .unwrap_or(settings.sidebar_project_grouping_mode)
}

pub fn derive_logical_project_key(
    project: &LogicalProject,
    grouping_mode: Option<SidebarProjectGroupingMode>,
) -> String {
    let grouping_mode = grouping_mode.unwrap_or(SidebarProjectGroupingMode::Repository);
    if grouping_mode == SidebarProjectGroupingMode::Separate {
        return derive_physical_project_key(project);
    }
    derive_repository_scoped_key(project, grouping_mode).unwrap_or_else(|| {
        let physical_key = derive_physical_project_key(project);
        if physical_key.trim().is_empty() {
            scoped_project_key(&scope_project_ref(&project.environment_id, &project.id))
        } else {
            physical_key
        }
    })
}

pub fn derive_logical_project_key_from_settings(
    project: &LogicalProject,
    settings: &ProjectGroupingSettings,
) -> String {
    derive_logical_project_key(
        project,
        Some(resolve_project_grouping_mode(project, settings)),
    )
}

pub fn derive_logical_project_key_from_ref(
    project_ref: &ScopedProjectRef,
    project: Option<&LogicalProject>,
    grouping_mode: Option<SidebarProjectGroupingMode>,
) -> String {
    project
        .map(|project| derive_logical_project_key(project, grouping_mode))
        .unwrap_or_else(|| scoped_project_key(project_ref))
}

pub fn derive_project_group_label(
    representative: &LogicalProject,
    members: &[LogicalProject],
) -> String {
    let display_names = unique_non_empty_values(
        members
            .iter()
            .filter_map(|member| member.repository_identity.as_ref())
            .map(|identity| identity.display_name.as_deref()),
    );
    if display_names.len() == 1 {
        return display_names[0].clone();
    }
    let repository_names = unique_non_empty_values(
        members
            .iter()
            .filter_map(|member| member.repository_identity.as_ref())
            .map(|identity| identity.name.as_deref()),
    );
    if repository_names.len() == 1 {
        return repository_names[0].clone();
    }
    representative.name.clone()
}

fn derive_repository_scoped_key(
    project: &LogicalProject,
    grouping_mode: SidebarProjectGroupingMode,
) -> Option<String> {
    let identity = project.repository_identity.as_ref()?;
    let canonical_key = identity
        .canonical_key
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    if grouping_mode == SidebarProjectGroupingMode::Repository {
        return Some(canonical_key.to_string());
    }
    let Some(relative_path) = derive_repository_relative_project_path(project) else {
        return Some(canonical_key.to_string());
    };
    if relative_path.is_empty() {
        Some(canonical_key.to_string())
    } else {
        Some(format!("{canonical_key}::{relative_path}"))
    }
}

pub fn derive_repository_relative_project_path(project: &LogicalProject) -> Option<String> {
    let root_path = project
        .repository_identity
        .as_ref()?
        .root_path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    let normalized_project_path = normalize_project_path_for_comparison(&project.cwd);
    let normalized_root_path = normalize_project_path_for_comparison(root_path);
    if normalized_project_path.is_empty() || normalized_root_path.is_empty() {
        return None;
    }
    if normalized_project_path == normalized_root_path {
        return Some(String::new());
    }
    let separator = if normalized_root_path.contains('\\') {
        "\\"
    } else {
        "/"
    };
    let root_prefix = format!("{normalized_root_path}{separator}");
    normalized_project_path
        .strip_prefix(&root_prefix)
        .map(|value| value.replace('\\', "/"))
}

fn trim_trailing_project_path_separators(value: &str) -> String {
    if value.is_empty() || is_root_project_path(value) {
        return value.to_string();
    }
    let trimmed = if value.starts_with('/') {
        value.trim_end_matches('/').to_string()
    } else {
        value.trim_end_matches(['/', '\\']).to_string()
    };
    if trimmed.is_empty() {
        value.to_string()
    } else if trimmed.len() == 2 && trimmed.ends_with(':') {
        format!("{trimmed}\\")
    } else {
        trimmed
    }
}

fn is_root_project_path(value: &str) -> bool {
    value == "/"
        || value == "\\"
        || (value.len() <= 3
            && value.as_bytes().get(1) == Some(&b':')
            && value
                .chars()
                .next()
                .is_some_and(|character| character.is_ascii_alphabetic())
            && value
                .chars()
                .nth(2)
                .map_or(true, |character| matches!(character, '/' | '\\')))
}

fn is_windows_drive_path(value: &str) -> bool {
    value.len() >= 2
        && value.as_bytes().get(1) == Some(&b':')
        && value
            .chars()
            .next()
            .is_some_and(|character| character.is_ascii_alphabetic())
}

fn unique_non_empty_values<'a>(values: impl Iterator<Item = Option<&'a str>>) -> Vec<String> {
    let mut seen = BTreeSet::new();
    let mut unique = Vec::new();
    for value in values.flatten() {
        let trimmed = value.trim();
        if trimmed.is_empty() || !seen.insert(trimmed.to_string()) {
            continue;
        }
        unique.push(trimmed.to_string());
    }
    unique
}

fn parse_scoped_key(key: &str) -> Option<(&str, &str)> {
    let separator_index = key.find(':')?;
    if separator_index == 0 || separator_index >= key.len().saturating_sub(1) {
        return None;
    }
    Some((&key[..separator_index], &key[separator_index + 1..]))
}

pub fn parse_scoped_project_key(key: &str) -> Option<ScopedProjectRef> {
    let (environment_id, project_id) = parse_scoped_key(key)?;
    Some(scope_project_ref(environment_id, project_id))
}

pub fn parse_scoped_thread_key(key: &str) -> Option<ScopedThreadRef> {
    let (environment_id, thread_id) = parse_scoped_key(key)?;
    Some(scope_thread_ref(environment_id, thread_id))
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SourceControlDiscoveryStateSnapshot {
    pub has_data: bool,
    pub error: Option<String>,
    pub is_pending: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum SourceControlDiscoveryRefreshDecision {
    InvalidTarget,
    ReturnInFlight,
    MissingClient {
        next: SourceControlDiscoveryStateSnapshot,
    },
    Start {
        next: SourceControlDiscoveryStateSnapshot,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum SourceControlDiscoveryCompletionDecision {
    Success(SourceControlDiscoveryStateSnapshot),
    Failure(SourceControlDiscoveryStateSnapshot),
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SourceControlDiscoveryResetPlan {
    pub clear_in_flight: bool,
    pub reset_keys: Vec<String>,
    pub next: SourceControlDiscoveryStateSnapshot,
}

pub const EMPTY_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT: SourceControlDiscoveryStateSnapshot =
    SourceControlDiscoveryStateSnapshot {
        has_data: false,
        error: None,
        is_pending: false,
    };

pub const INITIAL_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT: SourceControlDiscoveryStateSnapshot =
    SourceControlDiscoveryStateSnapshot {
        has_data: false,
        error: None,
        is_pending: true,
    };

pub fn get_source_control_discovery_target_key(key: Option<&str>) -> Option<String> {
    key.map(str::trim)
        .filter(|key| !key.is_empty())
        .map(str::to_string)
}

pub fn source_control_discovery_mark_pending(
    current: &SourceControlDiscoveryStateSnapshot,
) -> SourceControlDiscoveryStateSnapshot {
    if !current.has_data {
        INITIAL_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT
    } else {
        SourceControlDiscoveryStateSnapshot {
            has_data: true,
            error: None,
            is_pending: true,
        }
    }
}

pub fn source_control_discovery_set_data() -> SourceControlDiscoveryStateSnapshot {
    SourceControlDiscoveryStateSnapshot {
        has_data: true,
        error: None,
        is_pending: false,
    }
}

pub fn source_control_discovery_set_error(
    current: &SourceControlDiscoveryStateSnapshot,
    error: Option<&str>,
) -> SourceControlDiscoveryStateSnapshot {
    SourceControlDiscoveryStateSnapshot {
        has_data: current.has_data,
        error: Some(
            error
                .filter(|message| !message.is_empty())
                .unwrap_or("Failed to discover source control tools.")
                .to_string(),
        ),
        is_pending: false,
    }
}

pub fn source_control_discovery_refresh_decision(
    target_key: Option<&str>,
    current: &SourceControlDiscoveryStateSnapshot,
    has_in_flight_refresh: bool,
    has_client: bool,
) -> SourceControlDiscoveryRefreshDecision {
    if get_source_control_discovery_target_key(target_key).is_none() {
        return SourceControlDiscoveryRefreshDecision::InvalidTarget;
    }
    if has_in_flight_refresh {
        return SourceControlDiscoveryRefreshDecision::ReturnInFlight;
    }
    if !has_client {
        return SourceControlDiscoveryRefreshDecision::MissingClient {
            next: source_control_discovery_set_error(
                current,
                Some("Source control discovery client is unavailable."),
            ),
        };
    }
    SourceControlDiscoveryRefreshDecision::Start {
        next: source_control_discovery_mark_pending(current),
    }
}

pub fn source_control_discovery_complete_success() -> SourceControlDiscoveryCompletionDecision {
    SourceControlDiscoveryCompletionDecision::Success(source_control_discovery_set_data())
}

pub fn source_control_discovery_complete_failure(
    current: &SourceControlDiscoveryStateSnapshot,
    error: Option<&str>,
) -> SourceControlDiscoveryCompletionDecision {
    SourceControlDiscoveryCompletionDecision::Failure(source_control_discovery_set_error(
        current, error,
    ))
}

pub fn source_control_discovery_reset_plan<I, S>(known_keys: I) -> SourceControlDiscoveryResetPlan
where
    I: IntoIterator<Item = S>,
    S: AsRef<str>,
{
    SourceControlDiscoveryResetPlan {
        clear_in_flight: true,
        reset_keys: known_keys
            .into_iter()
            .filter_map(|key| get_source_control_discovery_target_key(Some(key.as_ref())))
            .collect(),
        next: INITIAL_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT,
    }
}

pub fn is_tailscale_https_endpoint(endpoint: &AdvertisedEndpoint) -> bool {
    endpoint.id.starts_with("tailscale-magicdns:")
}

pub fn endpoint_default_preference_key(endpoint: &AdvertisedEndpoint) -> String {
    if endpoint.id.starts_with("desktop-loopback:") {
        return "desktop-core:loopback:http".to_string();
    }
    if endpoint.id.starts_with("desktop-lan:") {
        return "desktop-core:lan:http".to_string();
    }
    if endpoint.id.starts_with("tailscale-ip:") {
        return "tailscale:ip:http".to_string();
    }
    if is_tailscale_https_endpoint(endpoint) {
        return "tailscale:magicdns:https".to_string();
    }

    let scheme = ParsedPairingUrl::parse(&endpoint.http_base_url)
        .map(|url| url.scheme)
        .unwrap_or_else(|| "unknown".to_string());
    format!(
        "{}:{}:{}:{}",
        endpoint.provider_id, endpoint.reachability, scheme, endpoint.label
    )
}

pub fn select_pairing_endpoint<'a>(
    endpoints: &'a [AdvertisedEndpoint],
    default_endpoint_key: Option<&str>,
) -> Option<&'a AdvertisedEndpoint> {
    let available = endpoints
        .iter()
        .filter(|endpoint| endpoint.status != AdvertisedEndpointStatus::Unavailable)
        .collect::<Vec<_>>();

    if let Some(default_endpoint_key) = default_endpoint_key {
        if let Some(endpoint) = available
            .iter()
            .copied()
            .find(|endpoint| endpoint_default_preference_key(endpoint) == default_endpoint_key)
        {
            return Some(endpoint);
        }
    }

    available
        .iter()
        .copied()
        .find(|endpoint| endpoint.is_default)
        .or_else(|| {
            available
                .iter()
                .copied()
                .find(|endpoint| endpoint.reachability != "loopback")
        })
        .or_else(|| {
            available.iter().copied().find(|endpoint| {
                endpoint.hosted_https_app == HostedHttpsAppCompatibility::Compatible
            })
        })
}

pub fn resolve_desktop_pairing_url(endpoint_url: &str, credential: &str) -> Option<String> {
    let parsed = ParsedPairingUrl::parse(endpoint_url)?;
    Some(format!(
        "{}/pair#token={}",
        parsed.origin,
        form_url_encode_component(credential)
    ))
}

pub fn resolve_hosted_pairing_url(endpoint_url: &str, credential: &str) -> Option<String> {
    resolve_hosted_pairing_url_with_hosted_app_url(endpoint_url, credential, None)
}

pub fn resolve_hosted_pairing_url_with_hosted_app_url(
    endpoint_url: &str,
    credential: &str,
    configured_hosted_app_url: Option<&str>,
) -> Option<String> {
    let parsed = ParsedPairingUrl::parse(endpoint_url)?;
    if parsed.scheme != "https" {
        return None;
    }
    build_hosted_pairing_url(configured_hosted_app_url, endpoint_url, credential, None)
}

pub fn resolve_advertised_endpoint_pairing_url(
    endpoint: &AdvertisedEndpoint,
    credential: &str,
) -> Option<String> {
    if endpoint.hosted_https_app == HostedHttpsAppCompatibility::Compatible {
        return resolve_hosted_pairing_url(&endpoint.http_base_url, credential)
            .or_else(|| resolve_desktop_pairing_url(&endpoint.http_base_url, credential));
    }
    resolve_desktop_pairing_url(&endpoint.http_base_url, credential)
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ServerPairingLinkRecord {
    pub id: String,
    pub created_at: String,
}

pub fn sort_desktop_pairing_links(
    links: &[ServerPairingLinkRecord],
) -> Vec<ServerPairingLinkRecord> {
    let mut sorted = links.to_vec();
    sorted.sort_by(|left, right| right.created_at.cmp(&left.created_at));
    sorted
}

pub fn upsert_desktop_pairing_link(
    current: &[ServerPairingLinkRecord],
    next: ServerPairingLinkRecord,
) -> Vec<ServerPairingLinkRecord> {
    let mut updated = current.to_vec();
    if let Some(existing_index) = updated
        .iter()
        .position(|pairing_link| pairing_link.id == next.id)
    {
        updated[existing_index] = next;
    } else {
        updated.push(next);
    }
    sort_desktop_pairing_links(&updated)
}

pub fn remove_desktop_pairing_link(
    current: &[ServerPairingLinkRecord],
    id: &str,
) -> Vec<ServerPairingLinkRecord> {
    current
        .iter()
        .filter(|pairing_link| pairing_link.id != id)
        .cloned()
        .collect()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ServerClientSessionRecord {
    pub session_id: String,
    pub issued_at: String,
    pub current: bool,
    pub connected: bool,
}

pub fn sort_desktop_client_sessions(
    sessions: &[ServerClientSessionRecord],
) -> Vec<ServerClientSessionRecord> {
    let mut sorted = sessions.to_vec();
    sorted.sort_by(|left, right| {
        right
            .current
            .cmp(&left.current)
            .then(right.connected.cmp(&left.connected))
            .then(right.issued_at.cmp(&left.issued_at))
    });
    sorted
}

pub fn upsert_desktop_client_session(
    current: &[ServerClientSessionRecord],
    next: ServerClientSessionRecord,
) -> Vec<ServerClientSessionRecord> {
    let mut updated = current.to_vec();
    if let Some(existing_index) = updated
        .iter()
        .position(|client_session| client_session.session_id == next.session_id)
    {
        updated[existing_index] = next;
    } else {
        updated.push(next);
    }
    sort_desktop_client_sessions(&updated)
}

pub fn remove_desktop_client_session(
    current: &[ServerClientSessionRecord],
    session_id: &str,
) -> Vec<ServerClientSessionRecord> {
    current
        .iter()
        .filter(|client_session| client_session.session_id != session_id)
        .cloned()
        .collect()
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct DiagnosticsDescriptionInput<'a> {
    pub local_tracing_enabled: bool,
    pub otlp_traces_enabled: bool,
    pub otlp_traces_url: Option<&'a str>,
    pub otlp_metrics_enabled: bool,
    pub otlp_metrics_url: Option<&'a str>,
}

pub fn collapse_otel_signals_url(traces_url: &str, metrics_url: &str) -> Option<String> {
    let traces_suffix = "/traces";
    let metrics_suffix = "/metrics";
    if !traces_url.ends_with(traces_suffix) || !metrics_url.ends_with(metrics_suffix) {
        return None;
    }

    let traces_base = &traces_url[..traces_url.len() - traces_suffix.len()];
    let metrics_base = &metrics_url[..metrics_url.len() - metrics_suffix.len()];
    if traces_base != metrics_base {
        return None;
    }

    Some(format!("{traces_base}/{{traces,metrics}}"))
}

pub fn format_diagnostics_description(input: DiagnosticsDescriptionInput<'_>) -> String {
    let mode = if input.local_tracing_enabled {
        "Local trace file"
    } else {
        "Terminal logs only"
    };
    let traces_url = input
        .otlp_traces_enabled
        .then_some(input.otlp_traces_url)
        .flatten();
    let metrics_url = input
        .otlp_metrics_enabled
        .then_some(input.otlp_metrics_url)
        .flatten();

    match (traces_url, metrics_url) {
        (Some(traces_url), Some(metrics_url)) => {
            if let Some(collapsed_url) = collapse_otel_signals_url(traces_url, metrics_url) {
                format!("{mode}. Exporting OTEL to {collapsed_url}.")
            } else {
                format!(
                    "{mode}. Exporting OTEL traces to {traces_url} and metrics to {metrics_url}."
                )
            }
        }
        (Some(traces_url), None) => format!("{mode}. Exporting OTEL traces to {traces_url}."),
        (None, Some(metrics_url)) => format!("{mode}. Exporting OTEL metrics to {metrics_url}."),
        (None, None) => format!("{mode}."),
    }
}

pub fn format_diagnostics_count(value: u64) -> String {
    let digits = value.to_string();
    let mut grouped = String::with_capacity(digits.len() + digits.len() / 3);
    for (index, ch) in digits.chars().rev().enumerate() {
        if index > 0 && index % 3 == 0 {
            grouped.push(',');
        }
        grouped.push(ch);
    }
    grouped.chars().rev().collect()
}

pub fn format_diagnostics_duration_ms(value: f64) -> String {
    if value < 1_000.0 {
        return format!("{} ms", value.round() as i64);
    }
    if value >= 10_000.0 {
        format!("{:.1} s", value / 1_000.0)
    } else {
        format!("{:.2} s", value / 1_000.0)
    }
}

pub fn format_diagnostics_bytes(value: u64) -> String {
    if value < 1024 {
        return format!("{value} B");
    }
    let units = ["KB", "MB", "GB"];
    let mut unit_index = 0_usize;
    let mut next = value as f64 / 1024.0;
    while next >= 1024.0 && unit_index < units.len() - 1 {
        next /= 1024.0;
        unit_index += 1;
    }
    if next >= 10.0 {
        format!("{next:.1} {}", units[unit_index])
    } else {
        format!("{next:.2} {}", units[unit_index])
    }
}

pub fn shorten_trace_id(trace_id: &str) -> String {
    if trace_id.len() <= 32 {
        return trace_id.to_string();
    }
    format!("{}...{}", &trace_id[..18], &trace_id[trace_id.len() - 10..])
}

pub fn is_stale_process_signal_message(message: Option<&str>) -> bool {
    message
        .map(|message| message.contains("not a live descendant"))
        .unwrap_or(false)
}

const POSIX_PROCESS_QUERY_COMMAND: &str = "pid=,ppid=,pgid=,stat=,pcpu=,rss=,etime=,command=";

#[derive(Debug, Clone, PartialEq)]
pub struct ProcessDiagnosticsRow {
    pub pid: u32,
    pub ppid: u32,
    pub pgid: Option<i32>,
    pub status: String,
    pub cpu_percent: f64,
    pub rss_bytes: u64,
    pub elapsed: String,
    pub command: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct ProcessDiagnosticsEntry {
    pub pid: u32,
    pub ppid: u32,
    pub pgid: Option<i32>,
    pub status: String,
    pub cpu_percent: f64,
    pub rss_bytes: u64,
    pub elapsed: String,
    pub command: String,
    pub depth: usize,
    pub child_pids: Vec<u32>,
}

#[derive(Debug, Clone, PartialEq)]
pub struct ProcessDiagnosticsResult {
    pub server_pid: u32,
    pub read_at: String,
    pub process_count: usize,
    pub total_rss_bytes: u64,
    pub total_cpu_percent: f64,
    pub processes: Vec<ProcessDiagnosticsEntry>,
    pub error: Option<String>,
}

pub fn parse_posix_process_rows(output: &str) -> Vec<ProcessDiagnosticsRow> {
    output.lines().filter_map(parse_posix_process_row).collect()
}

fn parse_posix_process_row(line: &str) -> Option<ProcessDiagnosticsRow> {
    if line.trim().is_empty() {
        return None;
    }

    let fields = split_posix_process_fields(line)?;
    let pid = parse_positive_u32(&fields[0])?;
    let ppid = parse_non_negative_u32(&fields[1])?;
    let pgid = fields[2].parse::<i32>().ok()?;
    let status = fields[3].clone();
    let cpu_percent = fields[4].parse::<f64>().ok()?;
    if !cpu_percent.is_finite() {
        return None;
    }
    let rss_kib = fields[5].parse::<u64>().ok()?;
    let elapsed = fields[6].clone();
    let command = fields[7].clone();

    if status.is_empty() || elapsed.is_empty() || command.is_empty() {
        return None;
    }

    Some(ProcessDiagnosticsRow {
        pid,
        ppid,
        pgid: Some(pgid),
        status,
        cpu_percent,
        rss_bytes: rss_kib.saturating_mul(1024),
        elapsed,
        command,
    })
}

fn split_posix_process_fields(line: &str) -> Option<Vec<String>> {
    let mut fields = Vec::with_capacity(8);
    let mut index = 0_usize;
    let bytes = line.as_bytes();

    while index < bytes.len() && bytes[index].is_ascii_whitespace() {
        index += 1;
    }

    for _ in 0..7 {
        let start = index;
        while index < bytes.len() && !bytes[index].is_ascii_whitespace() {
            index += 1;
        }
        if start == index {
            return None;
        }
        fields.push(line[start..index].to_string());
        while index < bytes.len() && bytes[index].is_ascii_whitespace() {
            index += 1;
        }
    }

    let command = line.get(index..)?.trim_end();
    if command.is_empty() {
        return None;
    }
    fields.push(command.to_string());
    Some(fields)
}

pub fn parse_windows_process_rows(output: &str) -> Vec<ProcessDiagnosticsRow> {
    if output.trim().is_empty() {
        return Vec::new();
    }

    let Ok(parsed) = serde_json::from_str::<serde_json::Value>(output) else {
        return Vec::new();
    };
    match parsed {
        serde_json::Value::Array(records) => records
            .iter()
            .filter_map(normalize_windows_process_row)
            .collect(),
        record => normalize_windows_process_row(&record).into_iter().collect(),
    }
}

fn normalize_windows_process_row(value: &serde_json::Value) -> Option<ProcessDiagnosticsRow> {
    let record = value.as_object()?;
    let pid = record
        .get("ProcessId")?
        .as_u64()
        .and_then(to_positive_u32)?;
    let ppid = record
        .get("ParentProcessId")?
        .as_u64()
        .and_then(to_non_negative_u32)?;
    let command = record
        .get("CommandLine")
        .and_then(serde_json::Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .or_else(|| record.get("Name").and_then(serde_json::Value::as_str))?
        .to_string();
    let working_set = record
        .get("WorkingSetSize")
        .and_then(serde_json::Value::as_f64)
        .filter(|value| value.is_finite())
        .map(|value| value.max(0.0).round() as u64)
        .unwrap_or(0);
    let cpu_percent = record
        .get("PercentProcessorTime")
        .and_then(serde_json::Value::as_f64)
        .filter(|value| value.is_finite())
        .map(|value| value.max(0.0))
        .unwrap_or(0.0);
    let status = record
        .get("Status")
        .and_then(serde_json::Value::as_str)
        .filter(|value| !value.is_empty())
        .unwrap_or("Live")
        .to_string();

    Some(ProcessDiagnosticsRow {
        pid,
        ppid,
        pgid: None,
        status,
        cpu_percent,
        rss_bytes: working_set,
        elapsed: String::new(),
        command,
    })
}

pub fn build_process_descendant_entries(
    rows: &[ProcessDiagnosticsRow],
    server_pid: u32,
) -> Vec<ProcessDiagnosticsEntry> {
    let mut children_by_parent = BTreeMap::<u32, Vec<ProcessDiagnosticsRow>>::new();
    for row in rows {
        children_by_parent
            .entry(row.ppid)
            .or_default()
            .push(row.clone());
    }

    for children in children_by_parent.values_mut() {
        children.sort_by_key(|row| row.pid);
    }

    let mut entries = Vec::new();
    let mut visited = Vec::<u32>::new();
    let mut stack = children_by_parent
        .get(&server_pid)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .map(|row| (row, 0_usize))
        .collect::<Vec<_>>();

    while let Some((row, depth)) = stack.first().cloned() {
        stack.remove(0);
        if visited.contains(&row.pid) {
            continue;
        }
        visited.push(row.pid);

        let children = children_by_parent
            .get(&row.pid)
            .cloned()
            .unwrap_or_default();
        entries.push(ProcessDiagnosticsEntry {
            pid: row.pid,
            ppid: row.ppid,
            pgid: row.pgid,
            status: row.status,
            cpu_percent: row.cpu_percent,
            rss_bytes: row.rss_bytes,
            elapsed: if row.elapsed.is_empty() {
                "n/a".to_string()
            } else {
                row.elapsed
            },
            command: row.command,
            depth,
            child_pids: children.iter().map(|child| child.pid).collect(),
        });

        stack.splice(
            0..0,
            children
                .into_iter()
                .map(|child| (child, depth + 1))
                .collect::<Vec<_>>(),
        );
    }

    entries
}

pub fn aggregate_process_diagnostics(
    server_pid: u32,
    rows: &[ProcessDiagnosticsRow],
    read_at: &str,
) -> ProcessDiagnosticsResult {
    make_process_diagnostics_result(server_pid, rows, read_at, None)
}

pub fn make_process_diagnostics_result(
    server_pid: u32,
    rows: &[ProcessDiagnosticsRow],
    read_at: &str,
    error: Option<&str>,
) -> ProcessDiagnosticsResult {
    let rows = rows
        .iter()
        .filter(|row| !is_diagnostics_query_process(row, server_pid))
        .cloned()
        .collect::<Vec<_>>();
    let processes = build_process_descendant_entries(&rows, server_pid);
    let total_rss_bytes = processes.iter().map(|process| process.rss_bytes).sum();
    let total_cpu_percent = processes
        .iter()
        .map(|process| process.cpu_percent)
        .sum::<f64>();

    ProcessDiagnosticsResult {
        server_pid,
        read_at: read_at.to_string(),
        process_count: processes.len(),
        total_rss_bytes,
        total_cpu_percent,
        processes,
        error: error.map(str::to_string),
    }
}

pub fn is_diagnostics_query_process(row: &ProcessDiagnosticsRow, server_pid: u32) -> bool {
    if row.ppid != server_pid {
        return false;
    }

    let command = row.command.trim();
    let command_lower = command.to_ascii_lowercase();
    let posix_query = command.contains(POSIX_PROCESS_QUERY_COMMAND)
        && (command.starts_with("ps -axo ")
            || command.contains("/ps -axo ")
            || command.contains("\\ps -axo "));
    let windows_query = (command_lower.contains("powershell ")
        || command_lower.contains("powershell.exe"))
        && command_lower.contains("get-ciminstance win32_process");
    posix_query || windows_query
}

fn parse_positive_u32(value: &str) -> Option<u32> {
    let value = value.parse::<u32>().ok()?;
    (value > 0).then_some(value)
}

fn parse_non_negative_u32(value: &str) -> Option<u32> {
    value.parse::<u32>().ok()
}

fn to_positive_u32(value: u64) -> Option<u32> {
    let value = u32::try_from(value).ok()?;
    (value > 0).then_some(value)
}

fn to_non_negative_u32(value: u64) -> Option<u32> {
    u32::try_from(value).ok()
}

const DEFAULT_SLOW_SPAN_THRESHOLD_MS: f64 = 1_000.0;
const TRACE_TOP_LIMIT: usize = 10;
const TRACE_RECENT_LIMIT: usize = 20;

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsFile {
    pub path: String,
    pub text: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TraceDiagnosticsErrorSummary {
    pub kind: String,
    pub message: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsSpanSummary {
    pub name: String,
    pub count: u64,
    pub failure_count: u64,
    pub total_duration_ms: f64,
    pub average_duration_ms: f64,
    pub max_duration_ms: f64,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsSpanOccurrence {
    pub name: String,
    pub duration_ms: f64,
    pub ended_at: String,
    pub trace_id: String,
    pub span_id: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsRecentFailure {
    pub name: String,
    pub cause: String,
    pub duration_ms: f64,
    pub ended_at: String,
    pub trace_id: String,
    pub span_id: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsFailureSummary {
    pub name: String,
    pub cause: String,
    pub count: u64,
    pub last_seen_at: String,
    pub trace_id: String,
    pub span_id: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsLogEvent {
    pub span_name: String,
    pub level: String,
    pub message: String,
    pub seen_at: String,
    pub trace_id: String,
    pub span_id: String,
}

#[derive(Debug, Clone, PartialEq)]
pub struct TraceDiagnosticsResult {
    pub trace_file_path: String,
    pub scanned_file_paths: Vec<String>,
    pub read_at: String,
    pub record_count: u64,
    pub parse_error_count: u64,
    pub first_span_at: Option<String>,
    pub last_span_at: Option<String>,
    pub failure_count: u64,
    pub interruption_count: u64,
    pub slow_span_threshold_ms: f64,
    pub slow_span_count: u64,
    pub log_level_counts: BTreeMap<String, u64>,
    pub top_spans_by_count: Vec<TraceDiagnosticsSpanSummary>,
    pub slowest_spans: Vec<TraceDiagnosticsSpanOccurrence>,
    pub common_failures: Vec<TraceDiagnosticsFailureSummary>,
    pub latest_failures: Vec<TraceDiagnosticsRecentFailure>,
    pub latest_warning_and_error_logs: Vec<TraceDiagnosticsLogEvent>,
    pub partial_failure: Option<bool>,
    pub error: Option<TraceDiagnosticsErrorSummary>,
}

pub struct TraceDiagnosticsInput<'a> {
    pub trace_file_path: &'a str,
    pub files: &'a [TraceDiagnosticsFile],
    pub scanned_file_paths: Option<Vec<String>>,
    pub slow_span_threshold_ms: Option<f64>,
    pub read_at: &'a str,
    pub error: Option<TraceDiagnosticsErrorSummary>,
    pub partial_failure: bool,
}

#[derive(Debug, Clone)]
struct MutableTraceSpanSummary {
    count: u64,
    failure_count: u64,
    total_duration_ms: f64,
    max_duration_ms: f64,
}

pub fn to_rotated_trace_paths(trace_file_path: &str, max_files: i32) -> Vec<String> {
    let backup_count = max_files.max(0) as usize;
    let mut paths = (0..backup_count)
        .map(|index| format!("{trace_file_path}.{}", backup_count - index))
        .collect::<Vec<_>>();
    paths.push(trace_file_path.to_string());
    paths
}

pub fn aggregate_trace_diagnostics(input: TraceDiagnosticsInput<'_>) -> TraceDiagnosticsResult {
    let slow_span_threshold_ms = input
        .slow_span_threshold_ms
        .unwrap_or(DEFAULT_SLOW_SPAN_THRESHOLD_MS);
    let scanned_file_paths = input
        .scanned_file_paths
        .unwrap_or_else(|| input.files.iter().map(|file| file.path.clone()).collect());

    if input.files.is_empty() {
        return make_empty_trace_diagnostics(
            input.trace_file_path,
            scanned_file_paths,
            input.read_at,
            slow_span_threshold_ms,
            input.error.or_else(|| {
                Some(TraceDiagnosticsErrorSummary {
                    kind: "trace-file-not-found".to_string(),
                    message: "No local trace files were found.".to_string(),
                })
            }),
            input.partial_failure,
        );
    }

    let mut parse_error_count = 0_u64;
    let mut record_count = 0_u64;
    let mut failure_count = 0_u64;
    let mut interruption_count = 0_u64;
    let mut slow_span_count = 0_u64;
    let mut first_span_at_millis = None::<i128>;
    let mut last_span_at_millis = None::<i128>;
    let mut spans_by_name = BTreeMap::<String, MutableTraceSpanSummary>::new();
    let mut failures_by_key = BTreeMap::<String, TraceDiagnosticsFailureSummary>::new();
    let mut latest_failures = Vec::<TraceDiagnosticsRecentFailure>::new();
    let mut slowest_spans = Vec::<TraceDiagnosticsSpanOccurrence>::new();
    let mut latest_warning_and_error_logs = Vec::<TraceDiagnosticsLogEvent>::new();
    let mut log_level_counts = BTreeMap::<String, u64>::new();

    for file in input.files {
        for line in file.text.lines() {
            if line.trim().is_empty() {
                continue;
            }

            let Ok(parsed) = serde_json::from_str::<serde_json::Value>(line) else {
                parse_error_count += 1;
                continue;
            };
            let Some(record) = parsed.as_object() else {
                parse_error_count += 1;
                continue;
            };

            let name = trace_string_value(record.get("name"));
            let trace_id = trace_string_value(record.get("traceId"));
            let span_id = trace_string_value(record.get("spanId"));
            let duration_ms = trace_number_value(record.get("durationMs"));
            let ended_at_millis = unix_nano_to_millis(record.get("endTimeUnixNano"))
                .and_then(|millis| unix_millis_to_iso(millis).map(|iso| (millis, iso)));
            let started_at_millis = unix_nano_to_millis(record.get("startTimeUnixNano"));

            let (
                Some(name),
                Some(trace_id),
                Some(span_id),
                Some(duration_ms),
                Some((ended_at_millis, ended_at)),
            ) = (name, trace_id, span_id, duration_ms, ended_at_millis)
            else {
                parse_error_count += 1;
                continue;
            };

            record_count += 1;
            if let Some(started_at_millis) = started_at_millis {
                first_span_at_millis = Some(
                    first_span_at_millis
                        .map(|current| current.min(started_at_millis))
                        .unwrap_or(started_at_millis),
                );
            }
            last_span_at_millis = Some(
                last_span_at_millis
                    .map(|current| current.max(ended_at_millis))
                    .unwrap_or(ended_at_millis),
            );

            let exit = record.get("exit");
            let exit_tag = read_trace_exit_tag(exit);
            let is_failure = exit_tag.as_deref() == Some("Failure");
            let is_interrupted = exit_tag.as_deref() == Some("Interrupted");
            if is_failure {
                failure_count += 1;
            }
            if is_interrupted {
                interruption_count += 1;
            }

            let span_summary =
                spans_by_name
                    .entry(name.clone())
                    .or_insert(MutableTraceSpanSummary {
                        count: 0,
                        failure_count: 0,
                        total_duration_ms: 0.0,
                        max_duration_ms: 0.0,
                    });
            span_summary.count += 1;
            span_summary.total_duration_ms += duration_ms;
            span_summary.max_duration_ms = span_summary.max_duration_ms.max(duration_ms);
            if is_failure {
                span_summary.failure_count += 1;
            }

            let span_item = TraceDiagnosticsSpanOccurrence {
                name: name.clone(),
                duration_ms,
                ended_at: ended_at.clone(),
                trace_id: trace_id.clone(),
                span_id: span_id.clone(),
            };
            if duration_ms >= slow_span_threshold_ms {
                slow_span_count += 1;
            }
            insert_bounded_slowest_span(&mut slowest_spans, span_item);

            if is_failure {
                let cause = read_trace_exit_cause(exit);
                latest_failures.push(TraceDiagnosticsRecentFailure {
                    name: name.clone(),
                    cause: cause.clone(),
                    duration_ms,
                    ended_at: ended_at.clone(),
                    trace_id: trace_id.clone(),
                    span_id: span_id.clone(),
                });

                let failure_key = format!("{name}\0{cause}");
                let existing = failures_by_key.get(&failure_key);
                let is_latest_failure = existing
                    .and_then(|failure| iso_utc_timestamp_millis(&failure.last_seen_at))
                    .map(|current| ended_at_millis > current)
                    .unwrap_or(true);
                failures_by_key.insert(
                    failure_key,
                    TraceDiagnosticsFailureSummary {
                        name: name.clone(),
                        cause,
                        count: existing.map(|failure| failure.count).unwrap_or(0) + 1,
                        last_seen_at: if is_latest_failure {
                            ended_at.clone()
                        } else {
                            existing.unwrap().last_seen_at.clone()
                        },
                        trace_id: if is_latest_failure {
                            trace_id.clone()
                        } else {
                            existing.unwrap().trace_id.clone()
                        },
                        span_id: if is_latest_failure {
                            span_id.clone()
                        } else {
                            existing.unwrap().span_id.clone()
                        },
                    },
                );
            }

            if let Some(events) = record.get("events").and_then(serde_json::Value::as_array) {
                for event in events {
                    let Some(event_record) = event.as_object() else {
                        continue;
                    };
                    let level = event_record
                        .get("attributes")
                        .and_then(serde_json::Value::as_object)
                        .and_then(|attributes| attributes.get("effect.logLevel"))
                        .and_then(|value| trace_string_value(Some(value)));
                    let Some(level) = level else {
                        continue;
                    };

                    *log_level_counts.entry(level.clone()).or_default() += 1;
                    let normalized_level = level.to_ascii_lowercase();
                    if !matches!(
                        normalized_level.as_str(),
                        "warning" | "warn" | "error" | "fatal"
                    ) {
                        continue;
                    }

                    let seen_at = unix_nano_to_millis(event_record.get("timeUnixNano"))
                        .and_then(unix_millis_to_iso)
                        .unwrap_or_else(|| ended_at.clone());
                    let message = event_record
                        .get("name")
                        .and_then(|value| trace_string_value(Some(value)))
                        .map(|value| value.trim().to_string())
                        .unwrap_or_else(|| "Log event".to_string());
                    latest_warning_and_error_logs.push(TraceDiagnosticsLogEvent {
                        span_name: name.clone(),
                        level,
                        message,
                        seen_at,
                        trace_id: trace_id.clone(),
                        span_id: span_id.clone(),
                    });
                }
            }
        }
    }

    let mut top_spans_by_count = spans_by_name
        .into_iter()
        .map(|(name, span)| TraceDiagnosticsSpanSummary {
            name,
            count: span.count,
            failure_count: span.failure_count,
            total_duration_ms: span.total_duration_ms,
            average_duration_ms: if span.count > 0 {
                span.total_duration_ms / span.count as f64
            } else {
                0.0
            },
            max_duration_ms: span.max_duration_ms,
        })
        .collect::<Vec<_>>();
    top_spans_by_count.sort_by(|left, right| {
        right
            .count
            .cmp(&left.count)
            .then_with(|| compare_f64_desc(right.max_duration_ms, left.max_duration_ms))
    });
    top_spans_by_count.truncate(TRACE_TOP_LIMIT);

    let mut common_failures = failures_by_key.into_values().collect::<Vec<_>>();
    common_failures.sort_by(|left, right| {
        right.count.cmp(&left.count).then_with(|| {
            iso_utc_timestamp_millis(&right.last_seen_at)
                .cmp(&iso_utc_timestamp_millis(&left.last_seen_at))
        })
    });
    common_failures.truncate(TRACE_TOP_LIMIT);

    latest_failures.sort_by(|left, right| {
        iso_utc_timestamp_millis(&right.ended_at).cmp(&iso_utc_timestamp_millis(&left.ended_at))
    });
    latest_failures.truncate(TRACE_RECENT_LIMIT);

    latest_warning_and_error_logs.sort_by(|left, right| {
        iso_utc_timestamp_millis(&right.seen_at).cmp(&iso_utc_timestamp_millis(&left.seen_at))
    });
    latest_warning_and_error_logs.truncate(TRACE_RECENT_LIMIT);

    TraceDiagnosticsResult {
        trace_file_path: input.trace_file_path.to_string(),
        scanned_file_paths,
        read_at: input.read_at.to_string(),
        record_count,
        parse_error_count,
        first_span_at: first_span_at_millis.and_then(unix_millis_to_iso),
        last_span_at: last_span_at_millis.and_then(unix_millis_to_iso),
        failure_count,
        interruption_count,
        slow_span_threshold_ms,
        slow_span_count,
        log_level_counts,
        top_spans_by_count,
        slowest_spans,
        common_failures,
        latest_failures,
        latest_warning_and_error_logs,
        partial_failure: input.partial_failure.then_some(true),
        error: input.error,
    }
}

fn make_empty_trace_diagnostics(
    trace_file_path: &str,
    scanned_file_paths: Vec<String>,
    read_at: &str,
    slow_span_threshold_ms: f64,
    error: Option<TraceDiagnosticsErrorSummary>,
    partial_failure: bool,
) -> TraceDiagnosticsResult {
    TraceDiagnosticsResult {
        trace_file_path: trace_file_path.to_string(),
        scanned_file_paths,
        read_at: read_at.to_string(),
        record_count: 0,
        parse_error_count: 0,
        first_span_at: None,
        last_span_at: None,
        failure_count: 0,
        interruption_count: 0,
        slow_span_threshold_ms,
        slow_span_count: 0,
        log_level_counts: BTreeMap::new(),
        top_spans_by_count: Vec::new(),
        slowest_spans: Vec::new(),
        common_failures: Vec::new(),
        latest_failures: Vec::new(),
        latest_warning_and_error_logs: Vec::new(),
        partial_failure: partial_failure.then_some(true),
        error,
    }
}

fn insert_bounded_slowest_span(
    slowest_spans: &mut Vec<TraceDiagnosticsSpanOccurrence>,
    span: TraceDiagnosticsSpanOccurrence,
) {
    if slowest_spans.len() >= TRACE_TOP_LIMIT
        && span.duration_ms <= slowest_spans.last().unwrap().duration_ms
    {
        return;
    }

    slowest_spans.push(span);
    slowest_spans.sort_by(|left, right| compare_f64_desc(right.duration_ms, left.duration_ms));
    if slowest_spans.len() > TRACE_TOP_LIMIT {
        slowest_spans.truncate(TRACE_TOP_LIMIT);
    }
}

fn trace_string_value(value: Option<&serde_json::Value>) -> Option<String> {
    let value = value?.as_str()?;
    (!value.trim().is_empty()).then(|| value.to_string())
}

fn trace_number_value(value: Option<&serde_json::Value>) -> Option<f64> {
    value
        .and_then(serde_json::Value::as_f64)
        .filter(|value| value.is_finite())
}

fn read_trace_exit_tag(exit: Option<&serde_json::Value>) -> Option<String> {
    exit.and_then(serde_json::Value::as_object)
        .and_then(|exit| exit.get("_tag"))
        .and_then(|value| trace_string_value(Some(value)))
}

fn read_trace_exit_cause(exit: Option<&serde_json::Value>) -> String {
    exit.and_then(serde_json::Value::as_object)
        .and_then(|exit| exit.get("cause"))
        .and_then(|value| trace_string_value(Some(value)))
        .map(|cause| cause.trim().to_string())
        .unwrap_or_else(|| "Failure".to_string())
}

fn unix_nano_to_millis(value: Option<&serde_json::Value>) -> Option<i128> {
    let value = trace_string_value(value)?;
    let nanos = value.parse::<i128>().ok()?;
    Some(nanos / 1_000_000)
}

fn unix_millis_to_iso(millis: i128) -> Option<String> {
    let seconds = millis.div_euclid(1_000);
    let millis_part = millis.rem_euclid(1_000);
    let days = seconds.div_euclid(86_400);
    let second_of_day = seconds.rem_euclid(86_400);
    let (year, month, day) = civil_from_days(days.try_into().ok()?);
    let hour = second_of_day / 3_600;
    let minute = (second_of_day % 3_600) / 60;
    let second = second_of_day % 60;
    Some(format!(
        "{year:04}-{month:02}-{day:02}T{hour:02}:{minute:02}:{second:02}.{millis_part:03}Z"
    ))
}

fn civil_from_days(days: i64) -> (i32, u32, u32) {
    let days = days + 719_468;
    let era = if days >= 0 { days } else { days - 146_096 } / 146_097;
    let day_of_era = days - era * 146_097;
    let year_of_era =
        (day_of_era - day_of_era / 1_460 + day_of_era / 36_524 - day_of_era / 146_096) / 365;
    let year = year_of_era + era * 400;
    let day_of_year = day_of_era - (365 * year_of_era + year_of_era / 4 - year_of_era / 100);
    let month_prime = (5 * day_of_year + 2) / 153;
    let day = day_of_year - (153 * month_prime + 2) / 5 + 1;
    let month = month_prime + if month_prime < 10 { 3 } else { -9 };
    let year = year + (month <= 2) as i64;
    (year as i32, month as u32, day as u32)
}

fn iso_utc_timestamp_millis(iso: &str) -> Option<i128> {
    let date_time = iso.strip_suffix('Z').unwrap_or(iso);
    let seconds = iso_utc_timestamp_seconds(iso)? as i128;
    let millis = if date_time.get(19..20) == Some(".") {
        date_time.get(20..23)?.parse::<i128>().ok()?
    } else {
        0
    };
    Some(seconds * 1_000 + millis)
}

fn compare_f64_desc(left: f64, right: f64) -> std::cmp::Ordering {
    left.partial_cmp(&right)
        .unwrap_or(std::cmp::Ordering::Equal)
}

fn trimmed_non_empty(value: &str) -> Option<&str> {
    let value = value.trim();
    if value.is_empty() { None } else { Some(value) }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ParsedPairingUrl {
    scheme: String,
    origin: String,
    query: String,
    hash: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PairingUrlRewriteParts {
    base: String,
    query: Option<String>,
    hash: Option<String>,
}

impl PairingUrlRewriteParts {
    fn parse(input: &str) -> Option<Self> {
        if input.is_empty() {
            return None;
        }
        let (before_hash, hash) = input
            .split_once('#')
            .map(|(base, hash)| (base, Some(hash.to_string())))
            .unwrap_or((input, None));
        let (base, query) = before_hash
            .split_once('?')
            .map(|(base, query)| (base.to_string(), Some(query.to_string())))
            .unwrap_or((before_hash.to_string(), None));
        if base.is_empty() {
            return None;
        }
        Some(Self { base, query, hash })
    }

    fn render(&self) -> String {
        let mut output = self.base.clone();
        if let Some(query) = self.query.as_ref().filter(|query| !query.is_empty()) {
            output.push('?');
            output.push_str(query);
        }
        if let Some(hash) = self.hash.as_ref().filter(|hash| !hash.is_empty()) {
            output.push('#');
            output.push_str(hash);
        }
        output
    }
}

impl ParsedPairingUrl {
    fn parse(input: &str) -> Option<Self> {
        if input.is_empty() {
            return None;
        }
        let url_like_input = if input.starts_with("//") {
            format!("https:{input}")
        } else if has_url_scheme_prefix(input) {
            input.to_string()
        } else {
            format!("https://{input}")
        };

        let scheme_end = url_like_input.find("://")?;
        let scheme = url_like_input[..scheme_end].to_ascii_lowercase();
        if scheme.is_empty() {
            return None;
        }
        let after_scheme = &url_like_input[scheme_end + 3..];
        let authority_end = after_scheme
            .find(|ch| matches!(ch, '/' | '?' | '#'))
            .unwrap_or(after_scheme.len());
        let authority = &after_scheme[..authority_end];
        if authority.is_empty() {
            return None;
        }
        let remainder = &after_scheme[authority_end..];
        let query = extract_url_query(remainder).unwrap_or_default();
        let hash = extract_url_hash(remainder).unwrap_or_default();

        Some(Self {
            scheme: scheme.clone(),
            origin: format!("{scheme}://{authority}"),
            query,
            hash,
        })
    }

    fn query_param(&self, name: &str) -> Option<String> {
        get_url_param(&self.query, name)
    }

    fn hash_param(&self, name: &str) -> Option<String> {
        get_url_param(&self.hash, name)
    }

    fn pairing_token(&self) -> Option<String> {
        self.hash_param("token")
            .filter(|token| !token.trim().is_empty())
            .or_else(|| {
                self.query_param("token")
                    .filter(|token| !token.trim().is_empty())
            })
    }
}

fn has_url_scheme_prefix(input: &str) -> bool {
    let Some((scheme, _)) = input.split_once("://") else {
        return false;
    };
    let mut chars = scheme.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    first.is_ascii_alphabetic()
        && chars.all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '+' | '.' | '-'))
}

fn extract_url_query(remainder: &str) -> Option<String> {
    let query_start = remainder.find('?')? + 1;
    let query_end = remainder[query_start..]
        .find('#')
        .map(|index| query_start + index)
        .unwrap_or(remainder.len());
    Some(remainder[query_start..query_end].to_string())
}

fn extract_url_hash(remainder: &str) -> Option<String> {
    let hash_start = remainder.find('#')? + 1;
    Some(remainder[hash_start..].to_string())
}

fn get_url_param(params: &str, name: &str) -> Option<String> {
    params.split('&').find_map(|part| {
        let (key, value) = part.split_once('=').unwrap_or((part, ""));
        (percent_decode_form_component(key) == name).then(|| percent_decode_form_component(value))
    })
}

fn url_params_has_name(params: &str, name: &str) -> bool {
    params.split('&').any(|part| {
        let (key, _) = part.split_once('=').unwrap_or((part, ""));
        percent_decode_form_component(key) == name
    })
}

fn rewrite_url_params_without_name(params: Option<&str>, name: &str) -> Option<String> {
    let params = params?;
    let rewritten = params
        .split('&')
        .filter(|part| !part.is_empty())
        .filter_map(|part| {
            let (key, value) = part.split_once('=').unwrap_or((part, ""));
            let key = percent_decode_form_component(key);
            (key != name).then(|| {
                format!(
                    "{}={}",
                    form_url_encode_component(&key),
                    form_url_encode_component(&percent_decode_form_component(value))
                )
            })
        })
        .collect::<Vec<_>>()
        .join("&");
    (!rewritten.is_empty()).then_some(rewritten)
}

fn percent_decode_form_component(value: &str) -> String {
    let bytes = value.as_bytes();
    let mut output = Vec::with_capacity(bytes.len());
    let mut index = 0_usize;
    while index < bytes.len() {
        match bytes[index] {
            b'+' => {
                output.push(b' ');
                index += 1;
            }
            b'%' if index + 2 < bytes.len() => {
                let high = hex_value(bytes[index + 1]);
                let low = hex_value(bytes[index + 2]);
                if let (Some(high), Some(low)) = (high, low) {
                    output.push(high * 16 + low);
                    index += 3;
                } else {
                    output.push(bytes[index]);
                    index += 1;
                }
            }
            byte => {
                output.push(byte);
                index += 1;
            }
        }
    }
    String::from_utf8_lossy(&output).into_owned()
}

fn hex_value(byte: u8) -> Option<u8> {
    match byte {
        b'0'..=b'9' => Some(byte - b'0'),
        b'a'..=b'f' => Some(byte - b'a' + 10),
        b'A'..=b'F' => Some(byte - b'A' + 10),
        _ => None,
    }
}

fn form_url_encode_component(value: &str) -> String {
    let mut output = String::new();
    for byte in value.bytes() {
        if byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b'.' | b'_' | b'~') {
            output.push(byte as char);
        } else if byte == b' ' {
            output.push('+');
        } else {
            output.push_str(&format!("%{byte:02X}"));
        }
    }
    output
}

