pub fn compute_message_duration_start(messages: &[ChatMessage]) -> BTreeMap<String, String> {
    let mut result = BTreeMap::new();
    let mut last_boundary: Option<String> = None;
    for message in messages {
        if message.role == MessageRole::User {
            last_boundary = Some(message.created_at.clone());
        }
        result.insert(
            message.id.clone(),
            last_boundary
                .clone()
                .unwrap_or_else(|| message.created_at.clone()),
        );
        if message.role == MessageRole::Assistant {
            if let Some(completed_at) = message.completed_at.as_ref() {
                last_boundary = Some(completed_at.clone());
            }
        }
    }
    result
}

pub fn normalize_compact_tool_label(value: &str) -> String {
    let trimmed = value.trim_end();
    for suffix in ["complete", "completed"] {
        if trimmed.len() <= suffix.len() {
            continue;
        }
        let split_at = trimmed.len() - suffix.len();
        let (prefix, candidate) = trimmed.split_at(split_at);
        if candidate.eq_ignore_ascii_case(suffix)
            && prefix
                .chars()
                .last()
                .is_some_and(|character| character.is_whitespace())
        {
            return prefix.trim().to_string();
        }
    }
    trimmed.trim().to_string()
}

pub fn resolve_assistant_message_copy_state(
    text: Option<&str>,
    show_copy_button: bool,
    streaming: bool,
) -> AssistantMessageCopyState {
    let text = text
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    AssistantMessageCopyState {
        visible: show_copy_button && text.is_some() && !streaming,
        text,
    }
}

pub fn derive_terminal_assistant_message_ids(messages: &[ChatMessage]) -> BTreeSet<String> {
    let mut last_assistant_message_id_by_response_key = BTreeMap::new();
    let mut null_turn_response_index = 0usize;
    for message in messages {
        if message.role == MessageRole::User {
            null_turn_response_index += 1;
            continue;
        }
        if message.role != MessageRole::Assistant {
            continue;
        }
        let response_key = message
            .turn_id
            .as_ref()
            .map(|turn_id| format!("turn:{turn_id}"))
            .unwrap_or_else(|| format!("unkeyed:{null_turn_response_index}"));
        last_assistant_message_id_by_response_key.insert(response_key, message.id.clone());
    }
    last_assistant_message_id_by_response_key
        .into_values()
        .collect()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum MessagesTimelineEntry {
    Work {
        id: String,
        created_at: String,
        entry: WorkLogEntry,
    },
    Message {
        id: String,
        created_at: String,
        message: ChatMessage,
    },
    ProposedPlan {
        id: String,
        created_at: String,
        proposed_plan: ProposedPlan,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum MessagesTimelineRow {
    Work {
        id: String,
        created_at: String,
        grouped_entries: Vec<WorkLogEntry>,
    },
    Message {
        id: String,
        created_at: String,
        message: ChatMessage,
        duration_start: String,
        show_completion_divider: bool,
        completion_summary: Option<String>,
        show_assistant_copy_button: bool,
        assistant_copy_streaming: bool,
        assistant_turn_diff_summary: Option<TurnDiffSummary>,
        revert_turn_count: Option<u32>,
    },
    ProposedPlan {
        id: String,
        created_at: String,
        proposed_plan: ProposedPlan,
    },
    Working {
        id: String,
        created_at: Option<String>,
    },
}

impl MessagesTimelineRow {
    pub fn id(&self) -> &str {
        match self {
            Self::Work { id, .. }
            | Self::Message { id, .. }
            | Self::ProposedPlan { id, .. }
            | Self::Working { id, .. } => id,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct StableMessagesTimelineRowsState {
    pub by_id: BTreeMap<String, MessagesTimelineRow>,
    pub result: Vec<MessagesTimelineRow>,
}

#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct DeriveMessagesTimelineRowsInput {
    pub timeline_entries: Vec<MessagesTimelineEntry>,
    pub completion_divider_before_entry_id: Option<String>,
    pub completion_summary: Option<String>,
    pub is_working: bool,
    pub active_turn_in_progress: bool,
    pub active_turn_id: Option<String>,
    pub active_turn_started_at: Option<String>,
    pub turn_diff_summary_by_assistant_message_id: BTreeMap<String, TurnDiffSummary>,
    pub revert_turn_count_by_user_message_id: BTreeMap<String, u32>,
}

pub fn derive_messages_timeline_rows(
    input: DeriveMessagesTimelineRowsInput,
) -> Vec<MessagesTimelineRow> {
    let messages = input
        .timeline_entries
        .iter()
        .filter_map(|entry| match entry {
            MessagesTimelineEntry::Message { message, .. } => Some(message.clone()),
            _ => None,
        })
        .collect::<Vec<_>>();
    let duration_start_by_message_id = compute_message_duration_start(&messages);
    let terminal_assistant_message_ids = derive_terminal_assistant_message_ids(&messages);
    let mut rows = Vec::new();
    let mut index = 0usize;
    while index < input.timeline_entries.len() {
        match &input.timeline_entries[index] {
            MessagesTimelineEntry::Work {
                id,
                created_at,
                entry,
            } => {
                let mut grouped_entries = vec![entry.clone()];
                let mut cursor = index + 1;
                while let Some(MessagesTimelineEntry::Work { entry, .. }) =
                    input.timeline_entries.get(cursor)
                {
                    grouped_entries.push(entry.clone());
                    cursor += 1;
                }
                rows.push(MessagesTimelineRow::Work {
                    id: id.clone(),
                    created_at: created_at.clone(),
                    grouped_entries,
                });
                index = cursor;
            }
            MessagesTimelineEntry::ProposedPlan {
                id,
                created_at,
                proposed_plan,
            } => {
                rows.push(MessagesTimelineRow::ProposedPlan {
                    id: id.clone(),
                    created_at: created_at.clone(),
                    proposed_plan: proposed_plan.clone(),
                });
                index += 1;
            }
            MessagesTimelineEntry::Message {
                id,
                created_at,
                message,
            } => {
                let assistant_turn_still_in_progress = message.role == MessageRole::Assistant
                    && input.active_turn_in_progress
                    && input.active_turn_id.as_ref().is_some()
                    && message.turn_id == input.active_turn_id;
                let show_completion_divider = message.role == MessageRole::Assistant
                    && input.completion_divider_before_entry_id.as_deref() == Some(id.as_str());
                rows.push(MessagesTimelineRow::Message {
                    id: id.clone(),
                    created_at: created_at.clone(),
                    message: message.clone(),
                    duration_start: duration_start_by_message_id
                        .get(&message.id)
                        .cloned()
                        .unwrap_or_else(|| message.created_at.clone()),
                    show_completion_divider,
                    completion_summary: show_completion_divider
                        .then(|| input.completion_summary.clone())
                        .flatten(),
                    show_assistant_copy_button: message.role == MessageRole::Assistant
                        && terminal_assistant_message_ids.contains(&message.id),
                    assistant_copy_streaming: message.streaming || assistant_turn_still_in_progress,
                    assistant_turn_diff_summary: (message.role == MessageRole::Assistant)
                        .then(|| {
                            input
                                .turn_diff_summary_by_assistant_message_id
                                .get(&message.id)
                                .cloned()
                        })
                        .flatten(),
                    revert_turn_count: (message.role == MessageRole::User)
                        .then(|| {
                            input
                                .revert_turn_count_by_user_message_id
                                .get(&message.id)
                                .copied()
                        })
                        .flatten(),
                });
                index += 1;
            }
        }
    }
    if input.is_working {
        rows.push(MessagesTimelineRow::Working {
            id: "working-indicator-row".to_string(),
            created_at: input.active_turn_started_at,
        });
    }
    rows
}

pub fn compute_stable_messages_timeline_rows(
    rows: Vec<MessagesTimelineRow>,
    previous: &StableMessagesTimelineRowsState,
) -> StableMessagesTimelineRowsState {
    let mut next = BTreeMap::new();
    let mut any_changed = rows.len() != previous.by_id.len();
    let result = rows
        .into_iter()
        .enumerate()
        .map(|(index, row)| {
            let row_id = row.id().to_string();
            let next_row = previous
                .by_id
                .get(&row_id)
                .filter(|previous_row| *previous_row == &row)
                .cloned()
                .unwrap_or(row);
            next.insert(row_id, next_row.clone());
            if !any_changed && previous.result.get(index) != Some(&next_row) {
                any_changed = true;
            }
            next_row
        })
        .collect::<Vec<_>>();
    if any_changed {
        StableMessagesTimelineRowsState {
            by_id: next,
            result,
        }
    } else {
        previous.clone()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct UserInputQuestionOption {
    pub label: String,
    pub description: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct UserInputQuestion {
    pub id: String,
    pub header: String,
    pub question: String,
    pub options: Vec<UserInputQuestionOption>,
    pub multi_select: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PendingUserInput {
    pub request_id: String,
    pub created_at: String,
    pub questions: Vec<UserInputQuestion>,
}

#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct PendingUserInputDraftAnswer {
    pub selected_option_labels: Vec<String>,
    pub custom_answer: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PendingUserInputAnswer {
    Text(String),
    Multiple(Vec<String>),
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PendingUserInputProgress {
    pub question_index: usize,
    pub active_question: Option<UserInputQuestion>,
    pub active_draft: Option<PendingUserInputDraftAnswer>,
    pub selected_option_labels: Vec<String>,
    pub custom_answer: String,
    pub resolved_answer: Option<PendingUserInputAnswer>,
    pub using_custom_answer: bool,
    pub answered_question_count: usize,
    pub is_last_question: bool,
    pub is_complete: bool,
    pub can_advance: bool,
}

fn normalize_draft_answer(value: Option<&str>) -> Option<String> {
    let trimmed = value?.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

fn normalize_selected_option_labels(value: &[String]) -> Vec<String> {
    let mut normalized = Vec::new();
    for label in value {
        let trimmed = label.trim();
        if trimmed.is_empty() || normalized.iter().any(|entry| entry == trimmed) {
            continue;
        }
        normalized.push(trimmed.to_string());
    }
    normalized
}

pub fn resolve_pending_user_input_answer(
    question: &UserInputQuestion,
    draft: Option<&PendingUserInputDraftAnswer>,
) -> Option<PendingUserInputAnswer> {
    if let Some(custom_answer) =
        normalize_draft_answer(draft.and_then(|draft| draft.custom_answer.as_deref()))
    {
        return Some(PendingUserInputAnswer::Text(custom_answer));
    }

    let selected_option_labels = draft
        .map(|draft| normalize_selected_option_labels(&draft.selected_option_labels))
        .unwrap_or_default();
    if question.multi_select {
        return if selected_option_labels.is_empty() {
            None
        } else {
            Some(PendingUserInputAnswer::Multiple(selected_option_labels))
        };
    }

    selected_option_labels
        .first()
        .cloned()
        .map(PendingUserInputAnswer::Text)
}

pub fn set_pending_user_input_custom_answer(
    draft: Option<&PendingUserInputDraftAnswer>,
    custom_answer: impl Into<String>,
) -> PendingUserInputDraftAnswer {
    let custom_answer = custom_answer.into();
    let selected_option_labels = if custom_answer.trim().is_empty() {
        draft
            .map(|draft| normalize_selected_option_labels(&draft.selected_option_labels))
            .unwrap_or_default()
    } else {
        Vec::new()
    };

    PendingUserInputDraftAnswer {
        selected_option_labels,
        custom_answer: Some(custom_answer),
    }
}

pub fn toggle_pending_user_input_option_selection(
    question: &UserInputQuestion,
    draft: Option<&PendingUserInputDraftAnswer>,
    option_label: impl Into<String>,
) -> PendingUserInputDraftAnswer {
    let option_label = option_label.into();
    if question.multi_select {
        let mut selected_option_labels = draft
            .map(|draft| normalize_selected_option_labels(&draft.selected_option_labels))
            .unwrap_or_default();
        if selected_option_labels
            .iter()
            .any(|label| label == &option_label)
        {
            selected_option_labels.retain(|label| label != &option_label);
        } else {
            selected_option_labels.push(option_label);
        }

        return PendingUserInputDraftAnswer {
            selected_option_labels,
            custom_answer: Some(String::new()),
        };
    }

    PendingUserInputDraftAnswer {
        selected_option_labels: vec![option_label],
        custom_answer: Some(String::new()),
    }
}

pub fn build_pending_user_input_answers(
    questions: &[UserInputQuestion],
    draft_answers: &BTreeMap<String, PendingUserInputDraftAnswer>,
) -> Option<BTreeMap<String, PendingUserInputAnswer>> {
    let mut answers = BTreeMap::new();

    for question in questions {
        let answer = resolve_pending_user_input_answer(question, draft_answers.get(&question.id))?;
        answers.insert(question.id.clone(), answer);
    }

    Some(answers)
}

pub fn count_answered_pending_user_input_questions(
    questions: &[UserInputQuestion],
    draft_answers: &BTreeMap<String, PendingUserInputDraftAnswer>,
) -> usize {
    questions
        .iter()
        .filter(|question| {
            resolve_pending_user_input_answer(question, draft_answers.get(&question.id)).is_some()
        })
        .count()
}

pub fn find_first_unanswered_pending_user_input_question_index(
    questions: &[UserInputQuestion],
    draft_answers: &BTreeMap<String, PendingUserInputDraftAnswer>,
) -> usize {
    questions
        .iter()
        .position(|question| {
            resolve_pending_user_input_answer(question, draft_answers.get(&question.id)).is_none()
        })
        .unwrap_or_else(|| questions.len().saturating_sub(1))
}

pub fn derive_pending_user_input_progress(
    questions: &[UserInputQuestion],
    draft_answers: &BTreeMap<String, PendingUserInputDraftAnswer>,
    question_index: usize,
) -> PendingUserInputProgress {
    let normalized_question_index = if questions.is_empty() {
        0
    } else {
        question_index.min(questions.len() - 1)
    };
    let active_question = questions.get(normalized_question_index).cloned();
    let active_draft = active_question
        .as_ref()
        .and_then(|question| draft_answers.get(&question.id).cloned());
    let resolved_answer = active_question
        .as_ref()
        .and_then(|question| resolve_pending_user_input_answer(question, active_draft.as_ref()));
    let custom_answer = active_draft
        .as_ref()
        .and_then(|draft| draft.custom_answer.clone())
        .unwrap_or_default();
    let answered_question_count =
        count_answered_pending_user_input_questions(questions, draft_answers);
    let is_last_question = questions.is_empty() || normalized_question_index >= questions.len() - 1;

    PendingUserInputProgress {
        question_index: normalized_question_index,
        active_question,
        selected_option_labels: active_draft
            .as_ref()
            .map(|draft| normalize_selected_option_labels(&draft.selected_option_labels))
            .unwrap_or_default(),
        active_draft,
        using_custom_answer: custom_answer.trim().len() > 0,
        custom_answer,
        can_advance: resolved_answer.is_some(),
        resolved_answer,
        answered_question_count,
        is_last_question,
        is_complete: build_pending_user_input_answers(questions, draft_answers).is_some(),
    }
}

