    #[test]
    fn parses_manual_desktop_ssh_targets_like_upstream() {
        let resolved = parse_ssh_resolve_output(
            "devbox",
            [
                "hostname devbox.example.com",
                "user julius",
                "port 2222",
                "",
            ]
            .join("\n")
            .as_str(),
        );
        assert_eq!(
            resolved,
            DesktopSshEnvironmentTarget {
                alias: "devbox".to_string(),
                hostname: "devbox.example.com".to_string(),
                username: Some("julius".to_string()),
                port: Some(2222),
            }
        );
        assert_eq!(build_ssh_host_spec(&resolved).unwrap(), "julius@devbox");
        assert_eq!(
            base_ssh_args(&resolved, Some("no")),
            vec![
                "-o",
                "BatchMode=no",
                "-o",
                "ConnectTimeout=10",
                "-p",
                "2222"
            ]
        );
        assert_eq!(DEFAULT_REMOTE_PORT, 3773);
        assert_eq!(REMOTE_PORT_SCAN_WINDOW, 200);
        assert_eq!(SSH_READY_TIMEOUT_MS, 20_000);
        assert_eq!(SSH_READY_PROBE_TIMEOUT_MS, 1_000);
        assert_eq!(TUNNEL_SHUTDOWN_TIMEOUT_MS, 2_000);
        assert_eq!(REMOTE_READY_TIMEOUT_MS, 15_000);
        assert_eq!(REMOTE_REUSE_READY_TIMEOUT_MS, 2_000);
        assert_eq!(
            normalize_ssh_error_message("  denied\n", "fallback"),
            "denied"
        );
        assert_eq!(normalize_ssh_error_message("   ", "fallback"), "fallback");
        assert_eq!(
            shell_single_quote("t3@nightly; echo 'owned'"),
            "'t3@nightly; echo '\\''owned'\\'''"
        );
        assert_eq!(
            apply_script_placeholders(
                "@@ONE@@ @@TWO@@ @@ONE@@",
                &BTreeMap::from([
                    ("ONE".to_string(), "1".to_string()),
                    ("TWO".to_string(), "2".to_string()),
                ])
            ),
            "1 2 1"
        );
        assert_eq!(
            decode_remote_launch_output("loaded nvm default\n{\"remotePort\":3774}\n").unwrap(),
            RemoteLaunchOutput {
                remote_port: 3774.0,
                server_kind: None,
            }
        );
        assert_eq!(
            decode_remote_launch_output("{\"remotePort\":3775,\"serverKind\":\"external\"}")
                .unwrap()
                .server_kind
                .as_deref(),
            Some("external")
        );
        assert_eq!(
            decode_remote_pairing_output("noise\n{\"credential\":\"pairing-token\"}\n")
                .unwrap()
                .credential,
            "pairing-token"
        );
        assert_eq!(
            get_last_non_empty_output_line(
                [
                    "Welcome to the host",
                    "",
                    "{\"credential\":\"pairing-token\"}",
                    ""
                ]
                .join("\n")
                .as_str()
            )
            .as_deref(),
            Some("{\"credential\":\"pairing-token\"}")
        );
        assert_eq!(
            target_connection_key(&resolved),
            format!("devbox{}devbox.example.com{}julius{}2222", '\0', '\0', '\0')
        );
        assert_eq!(remote_state_key(&resolved).len(), 16);
        assert_eq!(
            resolve_remote_t3_cli_package_spec("0.0.17", "latest", false),
            "t3@0.0.17"
        );
        assert_eq!(
            resolve_remote_t3_cli_package_spec("0.0.17-nightly.20260415.44", "nightly", false),
            "t3@0.0.17-nightly.20260415.44"
        );
        assert_eq!(
            resolve_remote_t3_cli_package_spec("0.0.0-dev", "latest", true),
            "t3@nightly"
        );
        assert_eq!(
            resolve_remote_t3_cli_package_spec("not-publishable", "latest", false),
            "t3@latest"
        );
        assert_eq!(DEFAULT_SSH_COMMAND_TIMEOUT_MS, 60_000);
        assert_eq!(SSH_ASKPASS_DIR_NAME, "t3code-ssh-askpass");
        assert!(is_ssh_auth_failure(
            "julius@100.65.180.100: Permission denied (publickey,password,keyboard-interactive)."
        ));
        assert!(is_ssh_auth_failure("Too many authentication failures"));
        assert!(!is_ssh_auth_failure("mkdir: Permission denied"));
        let askpass = build_ssh_askpass_helper_descriptor("C:\\temp\\t3code-ssh-askpass", "win32");
        assert_eq!(
            askpass.launcher_path,
            "C:\\temp\\t3code-ssh-askpass\\ssh-askpass.cmd"
        );
        assert_eq!(
            askpass
                .files
                .iter()
                .filter_map(|file| file.path.rsplit('\\').next())
                .collect::<Vec<_>>(),
            vec!["ssh-askpass.cmd", "ssh-askpass.ps1"]
        );
        let env_plan = build_ssh_child_environment_plan(
            &BTreeMap::new(),
            true,
            "/tmp/t3code-ssh-askpass",
            Some(Some("super-secret")),
            "linux",
        );
        assert_eq!(
            env_plan.env["SSH_ASKPASS"],
            "/tmp/t3code-ssh-askpass/ssh-askpass.sh"
        );
        assert_eq!(env_plan.env["SSH_ASKPASS_REQUIRE"], "force");
        assert_eq!(env_plan.env["T3_SSH_AUTH_SECRET"], "super-secret");
        assert_eq!(env_plan.env["DISPLAY"], "t3code");
        assert!(
            env_plan.askpass.as_ref().unwrap().files[0]
                .contents
                .contains("R3Code ssh-askpass")
        );
        assert_eq!(
            collect_ssh_config_aliases(
                [
                    "Host devbox",
                    "  HostName devbox.example.com",
                    "Host=equalsbox",
                    "Host *",
                    "Host !blocked",
                    "Host staging?",
                    "",
                ]
                .join("\n")
                .as_str()
            ),
            vec!["devbox".to_string(), "equalsbox".to_string()]
        );
        assert_eq!(
            resolve_ssh_config_include_pattern("~/.ssh/config.d/*.conf", "/tmp/home"),
            "/tmp/home/.ssh/config.d/*.conf"
        );
        assert_eq!(
            resolve_ssh_config_include_pattern("config.d/*.conf", "/tmp/home"),
            "/tmp/home/.ssh/config.d/*.conf"
        );
        let known_hosts = parse_known_hosts_hostnames(
            [
                "github.com ssh-ed25519 AAAA",
                "gitlab.com,gitlab-alias ssh-ed25519 BBBB",
                "|1|hashed|entry ssh-ed25519 CCCC",
                "@cert-authority *.example.com ssh-ed25519 DDDD",
                "[ssh.example.com]:2200 ssh-ed25519 EEEE",
                "port.example.com:22 ssh-ed25519 HHHH",
                "::1 ssh-ed25519 FFFF",
                "2001:db8::1 ssh-ed25519 GGGG",
                "",
            ]
            .join("\n")
            .as_str(),
        );
        assert_eq!(
            known_hosts,
            vec![
                "::1".to_string(),
                "2001:db8::1".to_string(),
                "github.com".to_string(),
                "gitlab-alias".to_string(),
                "gitlab.com".to_string(),
                "port.example.com".to_string(),
                "ssh.example.com".to_string(),
            ]
        );
        assert_eq!(
            merge_discovered_ssh_hosts(&["devbox".to_string()], &known_hosts)[0],
            DesktopDiscoveredSshHost {
                alias: "::1".to_string(),
                hostname: "::1".to_string(),
                username: None,
                port: None,
                source: "known-hosts".to_string(),
            }
        );

        let target = parse_manual_desktop_ssh_target("alice@example.com:2222", "", "").unwrap();
        assert_eq!(
            target,
            DesktopSshEnvironmentTarget {
                alias: "example.com".to_string(),
                hostname: "example.com".to_string(),
                username: Some("alice".to_string()),
                port: Some(2222),
            }
        );
        assert_eq!(format_desktop_ssh_target(&target), "alice@example.com:2222");

        let explicit_username =
            parse_manual_desktop_ssh_target("alice@example.com", "root", "").unwrap();
        assert_eq!(explicit_username.username.as_deref(), Some("root"));

        let ipv6 = parse_manual_desktop_ssh_target("bob@[fe80::1]:2200", "", "").unwrap();
        assert_eq!(ipv6.hostname, "fe80::1");
        assert_eq!(ipv6.username.as_deref(), Some("bob"));
        assert_eq!(ipv6.port, Some(2200));
        assert_eq!(format_desktop_ssh_target(&ipv6), "bob@fe80::1:2200");

        let explicit_port_parse_int =
            parse_manual_desktop_ssh_target("devbox", "", "22abc").unwrap();
        assert_eq!(explicit_port_parse_int.port, Some(22));
    }

    #[test]
    fn builds_remote_ssh_tunnel_scripts_like_upstream() {
        const TEST_NODE_ENGINE_RANGE: &str = "^22.16 || ^23.11 || >=24.10";
        let target = DesktopSshEnvironmentTarget {
            alias: "devbox".to_string(),
            hostname: "devbox.example.com".to_string(),
            username: Some("julius".to_string()),
            port: Some(2222),
        };
        let engine_options = RemoteT3RunnerOptions {
            node_engine_range: Some(TEST_NODE_ENGINE_RANGE.to_string()),
            ..Default::default()
        };
        let runner = build_remote_t3_runner_script(Some(&engine_options));

        assert!(runner.contains("T3_NODE_SCRIPT_PATH=''"));
        assert!(runner.contains("exec t3 \"$@\""));
        assert!(runner.contains("exec npx --yes 't3@latest' \"$@\""));
        assert!(runner.contains("exec npm exec --yes 't3@latest' -- \"$@\""));
        assert!(runner.contains("could not install 't3@latest'"));
        assert!(runner.contains("prepend_path_if_dir \"$HOME/.local/bin\""));
        assert!(runner.contains(&format!("T3_NODE_ENGINE_RANGE='{TEST_NODE_ENGINE_RANGE}'")));
        assert!(runner.contains("remote_node_satisfies_engine()"));
        assert!(runner.contains("function satisfiesSemverRange"));
        assert!(runner.contains("satisfiesSemverRange(rawVersion, range)"));
        assert!(runner.contains("prepend_path_if_dir \"$VOLTA_HOME/bin\""));
        assert!(runner.contains("prepend_path_if_dir \"$HOME/.asdf/shims\""));
        assert!(runner.contains("prepend_path_if_dir \"$HOME/.local/share/mise/shims\""));
        assert!(runner.contains("eval \"$(fnm env --use-on-cd --shell sh)\""));
        assert!(runner.contains("prepend_path_if_dir \"$HOME/.nodenv/shims\""));
        assert!(runner.contains("NVM_DIR=\"$HOME/.nvm\""));
        assert!(runner.contains("nvm use --silent default"));
        assert!(runner.contains("for T3_NODE_BIN in \"$NVM_DIR\"/versions/node/*/bin"));
        assert!(!runner.contains("ensure $NVM_DIR/nvm.sh is available"));

        let default_runner = build_remote_t3_runner_script(None);
        assert!(default_runner.contains("T3_NODE_ENGINE_RANGE=''"));
        assert!(!default_runner.contains(TEST_NODE_ENGINE_RANGE));

        let quoted_package_runner = build_remote_t3_runner_script(Some(&RemoteT3RunnerOptions {
            package_spec: Some("t3@nightly; touch /tmp/t3-owned".to_string()),
            ..Default::default()
        }));
        assert!(
            quoted_package_runner
                .contains("exec npx --yes 't3@nightly; touch /tmp/t3-owned' \"$@\"")
        );
        assert!(
            quoted_package_runner
                .contains("exec npm exec --yes 't3@nightly; touch /tmp/t3-owned' -- \"$@\"")
        );
        assert!(!quoted_package_runner.contains("exec npx --yes t3@nightly; touch /tmp/t3-owned"));

        let node_script_runner = build_remote_t3_runner_script(Some(&RemoteT3RunnerOptions {
            node_script_path: Some(
                "/Users/julius/Development/Work/codething-mvp/apps/server/dist/bin.mjs".to_string(),
            ),
            ..Default::default()
        }));
        assert!(node_script_runner.contains(
            "T3_NODE_SCRIPT_PATH='/Users/julius/Development/Work/codething-mvp/apps/server/dist/bin.mjs'"
        ));
        assert!(node_script_runner.contains("exec node \"$T3_NODE_SCRIPT_PATH\" \"$@\""));

        let launch = build_remote_launch_script(Some(&engine_options));
        let default_launch = build_remote_launch_script(None);
        assert!(launch.contains(
            "[ -n \"$REMOTE_PID\" ] && [ -n \"$REMOTE_PORT\" ] && kill -0 \"$REMOTE_PID\" 2>/dev/null"
        ));
        assert!(default_launch.contains("RUNNER_CHANGED=1"));
        assert!(default_launch.contains("ensure_remote_node_path()"));
        assert!(default_launch.contains("if ! ensure_remote_node_path; then"));
        assert!(launch.contains(&format!("T3_NODE_ENGINE_RANGE='{TEST_NODE_ENGINE_RANGE}'")));
        assert!(launch.contains("does not satisfy required range "));
        assert!(default_launch.contains("kill \"$REMOTE_PID\" 2>/dev/null || true"));
        assert!(default_launch.contains("wait_ready"));
        assert!(default_launch.contains("\"$RUNNER_FILE\" serve --host 127.0.0.1"));
        assert!(default_launch.contains("--base-dir \"$DEFAULT_SERVER_HOME\""));
        assert!(!default_launch.contains("server-home"));
        assert!(default_launch.contains("Remote T3 server did not become ready"));
        assert!(
            build_remote_launch_script(Some(&RemoteT3RunnerOptions {
                package_spec: Some("t3@nightly".to_string()),
                ..Default::default()
            }))
            .contains("t3@nightly")
        );

        let pairing = build_remote_pairing_script(&target, None);
        assert!(pairing.contains(
            "\"$RUNNER_FILE\" auth pairing create --base-dir \"$PAIRING_BASE_DIR\" --json"
        ));
        assert!(pairing.contains("PAIRING_BASE_DIR=\"$DEFAULT_SERVER_HOME\""));
        assert!(!pairing.contains("server-home"));
        assert!(
            build_remote_pairing_script(
                &target,
                Some(&RemoteT3RunnerOptions {
                    package_spec: Some("t3@nightly".to_string()),
                    ..Default::default()
                })
            )
            .contains("t3@nightly")
        );

        let stop = build_remote_stop_script(&target);
        assert!(
            stop.contains("if [ \"$REMOTE_MANAGED\" != \"external\" ] && [ -n \"$REMOTE_PID\" ]")
        );
        assert!(stop.contains("kill \"$REMOTE_PID\" 2>/dev/null || true"));
        assert!(stop.contains("rm -f \"$PID_FILE\" \"$PORT_FILE\" \"$MANAGED_FILE\""));

        assert!(default_launch.contains(
            "DEFAULT_RUNTIME_FILE=\"$DEFAULT_SERVER_HOME/userdata/server-runtime.json\""
        ));
        assert!(default_launch.contains("resolve_default_runtime_port()"));
        assert!(default_launch.contains("DEFAULT_RUNTIME_INFO=\"$(resolve_default_runtime_port"));
        assert!(
            default_launch
                .contains("if (!Number.isInteger(pid) || pid <= 0 || !Number.isInteger(port))")
        );
        assert!(default_launch.contains("PID_TO_STOP=\"${REMOTE_PID:-$DEFAULT_RUNTIME_PID}\""));
        assert!(default_launch.contains("REMOTE_PORT=\"$DEFAULT_REMOTE_PORT\""));
        assert!(default_launch.contains("rm -f \"$PID_FILE\""));
        assert!(default_launch.contains("printf 'external\\n' >\"$MANAGED_FILE\""));
        assert!(default_launch.contains("if [ -z \"$REMOTE_PORT\" ]; then"));
        assert!(
            default_launch
                .find("if [ \"$REMOTE_MANAGED\" = \"managed\" ]")
                .unwrap()
                < default_launch
                    .find("printf 'external\\n' >\"$MANAGED_FILE\"")
                    .unwrap()
        );
        assert!(
            default_launch
                .find("DEFAULT_RUNTIME_INFO=\"$(resolve_default_runtime_port")
                .unwrap()
                < default_launch.find("elif [ -n \"$REMOTE_PID\" ]").unwrap()
        );
        assert!(REMOTE_PICK_PORT_SCRIPT.contains("const filePath = process.argv[2] ?? \"\";"));
        assert!(build_remote_log_tail_script(&target).contains("tail -n 80 \"$LOG_FILE\""));
    }

    #[test]
    fn rejects_manual_desktop_ssh_targets_with_upstream_messages() {
        assert_eq!(
            parse_manual_desktop_ssh_target("  ", "", "").unwrap_err(),
            "SSH host or alias is required."
        );
        assert_eq!(
            parse_manual_desktop_ssh_target("alice@:22", "", "").unwrap_err(),
            "SSH host or alias is required."
        );
        assert_eq!(
            parse_manual_desktop_ssh_target("example.com:70000", "", "").unwrap_err(),
            "SSH port must be between 1 and 65535."
        );
        assert_eq!(
            parse_manual_desktop_ssh_target("example.com", "", "nope").unwrap_err(),
            "SSH port must be between 1 and 65535."
        );
    }

    #[test]
    fn parses_remote_pairing_fields_from_urls_and_manual_fields() {
        assert_eq!(
            get_pairing_token_from_url(
                "https://remote.example.com/pair?token=search#token=%20hash+token%20"
            )
            .as_deref(),
            Some("hash token")
        );
        assert_eq!(
            get_pairing_token_from_url(
                "https://remote.example.com/pair?%74%6F%6B%65%6E=search%2Dtoken#token=+++"
            )
            .as_deref(),
            Some("search-token")
        );
        assert_eq!(
            strip_pairing_token_from_url(
                "https://remote.example.com/pair?token=search&next=a+b#token=hash&mode=remote"
            )
            .as_deref(),
            Some("https://remote.example.com/pair?next=a+b#mode=remote")
        );
        assert_eq!(
            set_pairing_token_on_url(
                "https://remote.example.com/pair?token=old&next=1#mode=remote",
                "PAIR CODE"
            )
            .as_deref(),
            Some("https://remote.example.com/pair?next=1#token=PAIR+CODE")
        );
        assert_eq!(
            parse_remote_pairing_fields("https://remote.example.com/pair#token=pairing-token", "")
                .unwrap(),
            RemotePairingFields {
                host: "https://remote.example.com".to_string(),
                pairing_code: "pairing-token".to_string(),
            }
        );
        assert_eq!(
            parse_remote_pairing_fields(
                "https://app.t3.codes/pair?host=https%3A%2F%2Fdesktop.tailnet.ts.net%3A44342%2F#token=pairing-token",
                "",
            )
            .unwrap(),
            RemotePairingFields {
                host: "https://desktop.tailnet.ts.net:44342/".to_string(),
                pairing_code: "pairing-token".to_string(),
            }
        );
        assert_eq!(
            parse_remote_pairing_fields("backend.example.com", "PAIRCODE").unwrap(),
            RemotePairingFields {
                host: "backend.example.com".to_string(),
                pairing_code: "PAIRCODE".to_string(),
            }
        );

        assert_eq!(
            parse_remote_pairing_fields("", "PAIRCODE").unwrap_err(),
            "Enter a backend host."
        );
        assert_eq!(
            parse_remote_pairing_fields("backend.example.com", "").unwrap_err(),
            "Enter a pairing code."
        );
    }

    #[test]
    fn hosted_pairing_helpers_match_upstream_url_logic() {
        assert_eq!(
            configured_hosted_app_url(Some(" https://preview.t3.codes/app ")),
            "https://preview.t3.codes/app"
        );
        assert_eq!(
            configured_hosted_app_url(Some("   ")),
            DEFAULT_HOSTED_APP_URL
        );
        assert_eq!(
            origin_from_url("https://preview.t3.codes/app/path?x=1#hash").as_deref(),
            Some("https://preview.t3.codes")
        );
        assert!(is_hosted_static_app(
            "https://preview.t3.codes/pair",
            Some("https://preview.t3.codes"),
            None,
            None,
            None
        ));
        assert!(!is_hosted_static_app(
            "https://preview.t3.codes/pair",
            Some("https://preview.t3.codes"),
            Some("https://backend.example.com"),
            None,
            Some("nightly")
        ));
        assert!(is_hosted_static_app(
            "https://elsewhere.example.com",
            Some("https://preview.t3.codes"),
            None,
            None,
            Some("nightly")
        ));

        let hosted_url = build_hosted_pairing_url(
            Some("https://preview.t3.codes/app"),
            "https://host.tailnet.example.ts.net:3773",
            "PAIR CODE",
            Some(" Tailnet Desktop "),
        )
        .unwrap();
        assert_eq!(
            hosted_url,
            "https://preview.t3.codes/pair?host=https%3A%2F%2Fhost.tailnet.example.ts.net%3A3773&label=Tailnet+Desktop#token=PAIR+CODE"
        );
        assert_eq!(
            read_hosted_pairing_request(&hosted_url),
            Some(HostedPairingRequest {
                host: "https://host.tailnet.example.ts.net:3773".to_string(),
                token: "PAIR CODE".to_string(),
                label: "Tailnet Desktop".to_string(),
            })
        );
        assert!(has_hosted_pairing_request(&hosted_url));
        assert!(!has_hosted_pairing_request(
            "https://preview.t3.codes/pair?host=https%3A%2F%2Fhost"
        ));
        assert_eq!(
            build_hosted_channel_selection_url(
                Some("https://preview.t3.codes/app"),
                HostedAppChannel::Nightly
            )
            .as_deref(),
            Some("https://preview.t3.codes/__t3code/channel?channel=nightly")
        );
    }

