    #[test]
    fn selects_and_resolves_advertised_pairing_endpoints() {
        let loopback = advertised_endpoint(
            "desktop-loopback:127.0.0.1",
            "http://127.0.0.1:8765",
            "loopback",
            true,
            AdvertisedEndpointStatus::Available,
            HostedHttpsAppCompatibility::Incompatible,
        );
        let lan = advertised_endpoint(
            "desktop-lan:192.168.1.44",
            "http://192.168.1.44:8765",
            "lan",
            false,
            AdvertisedEndpointStatus::Available,
            HostedHttpsAppCompatibility::Incompatible,
        );
        let tailscale_https = advertised_endpoint(
            "tailscale-magicdns:desktop.tailnet.ts.net",
            "https://desktop.tailnet.ts.net:8765",
            "tailscale",
            false,
            AdvertisedEndpointStatus::Available,
            HostedHttpsAppCompatibility::Compatible,
        );
        let unavailable_preference = advertised_endpoint(
            "desktop-lan:stale",
            "http://stale.local:8765",
            "lan",
            false,
            AdvertisedEndpointStatus::Unavailable,
            HostedHttpsAppCompatibility::Incompatible,
        );

        assert_eq!(
            endpoint_default_preference_key(&loopback),
            "desktop-core:loopback:http"
        );
        assert_eq!(
            endpoint_default_preference_key(&tailscale_https),
            "tailscale:magicdns:https"
        );

        let endpoints = vec![
            unavailable_preference,
            loopback.clone(),
            lan.clone(),
            tailscale_https.clone(),
        ];
        assert_eq!(
            select_pairing_endpoint(&endpoints, Some("desktop-core:lan:http"))
                .unwrap()
                .id,
            lan.id
        );
        assert_eq!(
            resolve_advertised_endpoint_pairing_url(&lan, "PAIRCODE").unwrap(),
            "http://192.168.1.44:8765/pair#token=PAIRCODE"
        );
        assert_eq!(
            resolve_advertised_endpoint_pairing_url(&tailscale_https, "PAIRCODE").unwrap(),
            "https://app.t3.codes/pair?host=https%3A%2F%2Fdesktop.tailnet.ts.net%3A8765#token=PAIRCODE"
        );
        assert_eq!(
            resolve_hosted_pairing_url_with_hosted_app_url(
                "https://host.tailnet.example.ts.net:3773",
                "PAIRCODE",
                Some("https://preview.t3.codes")
            )
            .as_deref(),
            Some(
                "https://preview.t3.codes/pair?host=https%3A%2F%2Fhost.tailnet.example.ts.net%3A3773#token=PAIRCODE"
            )
        );
    }

    #[test]
    fn ports_client_runtime_endpoint_environment_and_scoped_ref_helpers() {
        assert_eq!(
            normalize_client_runtime_http_base_url("https://example.com/path?x=1#hash").unwrap(),
            "https://example.com/"
        );
        assert_eq!(
            normalize_client_runtime_http_base_url("wss://example.com/socket").unwrap(),
            "https://example.com/"
        );
        assert_eq!(
            derive_client_runtime_ws_base_url("https://example.com/api").unwrap(),
            "wss://example.com/"
        );
        assert_eq!(
            derive_client_runtime_ws_base_url("http://127.0.0.1:3773").unwrap(),
            "ws://127.0.0.1:3773/"
        );
        assert_eq!(
            classify_client_runtime_hosted_https_compatibility(
                "http://192.168.1.44:3773",
                ClientRuntimeHostedHttpsCompatibility::Unknown
            )
            .unwrap(),
            ClientRuntimeHostedHttpsCompatibility::MixedContentBlocked
        );
        assert_eq!(
            classify_client_runtime_hosted_https_compatibility(
                "https://desktop.example.com",
                ClientRuntimeHostedHttpsCompatibility::Compatible
            )
            .unwrap(),
            ClientRuntimeHostedHttpsCompatibility::Compatible
        );

        let endpoint =
            create_client_runtime_advertised_endpoint(CreateClientRuntimeAdvertisedEndpointInput {
                id: "lan:http://192.168.1.44:3773".to_string(),
                label: "LAN".to_string(),
                provider: ClientRuntimeAdvertisedEndpointProvider {
                    id: "desktop-core".to_string(),
                    label: "Desktop".to_string(),
                    kind: "core".to_string(),
                    is_addon: false,
                },
                http_base_url: "http://192.168.1.44:3773".to_string(),
                reachability: "lan".to_string(),
                hosted_https_compatibility: None,
                desktop_compatibility: None,
                source: "desktop-core".to_string(),
                status: None,
                is_default: Some(true),
                description: None,
            })
            .unwrap();
        assert_eq!(endpoint.http_base_url, "http://192.168.1.44:3773/");
        assert_eq!(endpoint.ws_base_url, "ws://192.168.1.44:3773/");
        assert_eq!(
            endpoint.hosted_https_app,
            ClientRuntimeHostedHttpsCompatibility::MixedContentBlocked
        );
        assert_eq!(endpoint.desktop_app_compatibility, "compatible");
        assert_eq!(endpoint.status, "available");
        assert_eq!(endpoint.is_default, Some(true));

        let environment = create_known_environment(
            None,
            "Remote environment",
            None,
            KnownEnvironmentConnectionTarget {
                http_base_url: "https://remote.example.com".to_string(),
                ws_base_url: "wss://remote.example.com".to_string(),
            },
        );
        assert_eq!(environment.id, "ws:Remote environment");
        assert_eq!(environment.source, "manual");
        assert_eq!(
            get_known_environment_http_base_url(Some(&environment)).as_deref(),
            Some("https://remote.example.com")
        );
        assert_eq!(
            get_known_environment_ws_base_url(Some(&environment)).as_deref(),
            Some("wss://remote.example.com")
        );
        assert_eq!(
            attach_environment_descriptor_to_known_environment(
                &environment,
                "environment-test",
                "Test environment"
            )
            .label,
            "Test environment"
        );

        let project_ref = scope_project_ref("environment-test", "project-1");
        let thread_ref = scope_thread_ref("environment-test", "thread-1");
        assert_eq!(
            scoped_project_key(&project_ref),
            "environment-test:project-1"
        );
        assert_eq!(scoped_thread_key(&thread_ref), "environment-test:thread-1");
        assert_eq!(
            parse_scoped_project_key("environment-test:project-1"),
            Some(project_ref)
        );
        assert_eq!(
            parse_scoped_thread_key("environment-test:thread-1"),
            Some(thread_ref)
        );
        assert_eq!(parse_scoped_project_key("bad-key"), None);
    }

    #[test]
    fn ports_client_runtime_source_control_discovery_state_helpers() {
        assert_eq!(
            get_source_control_discovery_target_key(Some(" primary ")).as_deref(),
            Some("primary")
        );
        assert_eq!(get_source_control_discovery_target_key(Some("   ")), None);
        assert_eq!(get_source_control_discovery_target_key(None), None);
        assert_eq!(
            EMPTY_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT,
            SourceControlDiscoveryStateSnapshot {
                has_data: false,
                error: None,
                is_pending: false,
            }
        );
        assert_eq!(
            source_control_discovery_mark_pending(&EMPTY_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT),
            INITIAL_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT
        );
        let with_data = source_control_discovery_set_data();
        assert_eq!(
            source_control_discovery_mark_pending(&with_data),
            SourceControlDiscoveryStateSnapshot {
                has_data: true,
                error: None,
                is_pending: true,
            }
        );
        assert_eq!(
            source_control_discovery_set_error(&with_data, Some("probe failed")),
            SourceControlDiscoveryStateSnapshot {
                has_data: true,
                error: Some("probe failed".to_string()),
                is_pending: false,
            }
        );
        assert_eq!(
            source_control_discovery_set_error(&with_data, None)
                .error
                .as_deref(),
            Some("Failed to discover source control tools.")
        );
        assert_eq!(
            source_control_discovery_refresh_decision(
                Some("  "),
                &EMPTY_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT,
                false,
                true,
            ),
            SourceControlDiscoveryRefreshDecision::InvalidTarget
        );
        assert_eq!(
            source_control_discovery_refresh_decision(Some("primary"), &with_data, true, true),
            SourceControlDiscoveryRefreshDecision::ReturnInFlight
        );
        assert_eq!(
            source_control_discovery_refresh_decision(Some("primary"), &with_data, false, false),
            SourceControlDiscoveryRefreshDecision::MissingClient {
                next: SourceControlDiscoveryStateSnapshot {
                    has_data: true,
                    error: Some("Source control discovery client is unavailable.".to_string()),
                    is_pending: false,
                },
            }
        );
        assert_eq!(
            source_control_discovery_refresh_decision(Some("primary"), &with_data, false, true),
            SourceControlDiscoveryRefreshDecision::Start {
                next: SourceControlDiscoveryStateSnapshot {
                    has_data: true,
                    error: None,
                    is_pending: true,
                },
            }
        );
        assert_eq!(
            source_control_discovery_complete_success(),
            SourceControlDiscoveryCompletionDecision::Success(source_control_discovery_set_data())
        );
        assert_eq!(
            source_control_discovery_complete_failure(&with_data, Some("probe failed")),
            SourceControlDiscoveryCompletionDecision::Failure(
                SourceControlDiscoveryStateSnapshot {
                    has_data: true,
                    error: Some("probe failed".to_string()),
                    is_pending: false,
                }
            )
        );
        assert_eq!(
            source_control_discovery_reset_plan([" primary ", "", "secondary"]),
            SourceControlDiscoveryResetPlan {
                clear_in_flight: true,
                reset_keys: vec!["primary".to_string(), "secondary".to_string()],
                next: INITIAL_SOURCE_CONTROL_DISCOVERY_STATE_SNAPSHOT,
            }
        );
    }

    #[test]
    fn logical_project_helpers_match_upstream_grouping_rules() {
        let project = LogicalProject {
            id: "project-web".to_string(),
            environment_id: "local".to_string(),
            cwd: "/repo/apps/web/".to_string(),
            name: "web".to_string(),
            repository_identity: Some(LogicalProjectRepositoryIdentity {
                canonical_key: Some("git:/repo".to_string()),
                root_path: Some("/repo".to_string()),
                display_name: Some("T3Code".to_string()),
                name: Some("t3code".to_string()),
            }),
        };

        assert_eq!(
            normalize_project_path_for_comparison("/repo/apps/web/"),
            "/repo/apps/web"
        );
        assert_eq!(
            normalize_project_path_for_comparison("C:/Users/Bunny/Repo/"),
            r"c:\users\bunny\repo"
        );
        assert_eq!(
            derive_physical_project_key_from_path("local", "/repo/apps/web/"),
            "local:/repo/apps/web"
        );
        assert_eq!(
            derive_physical_project_key(&project),
            "local:/repo/apps/web"
        );
        assert_eq!(
            derive_project_grouping_override_key(&project),
            "local:/repo/apps/web"
        );
        assert_eq!(get_project_order_key(&project), "local:/repo/apps/web");
        assert_eq!(
            derive_repository_relative_project_path(&project).as_deref(),
            Some("apps/web")
        );
        assert_eq!(
            derive_logical_project_key(&project, Some(SidebarProjectGroupingMode::Repository)),
            "git:/repo"
        );
        assert_eq!(
            derive_logical_project_key(&project, Some(SidebarProjectGroupingMode::RepositoryPath)),
            "git:/repo::apps/web"
        );
        assert_eq!(
            derive_logical_project_key(&project, Some(SidebarProjectGroupingMode::Separate)),
            "local:/repo/apps/web"
        );

        let mut overrides = BTreeMap::new();
        overrides.insert(
            derive_project_grouping_override_key(&project),
            SidebarProjectGroupingMode::Separate,
        );
        let settings = ProjectGroupingSettings {
            sidebar_project_grouping_mode: SidebarProjectGroupingMode::Repository,
            sidebar_project_grouping_overrides: overrides,
        };
        assert_eq!(
            resolve_project_grouping_mode(&project, &settings),
            SidebarProjectGroupingMode::Separate
        );
        assert_eq!(
            derive_logical_project_key_from_settings(&project, &settings),
            "local:/repo/apps/web"
        );

        let fallback_ref = scope_project_ref("remote", "missing-project");
        assert_eq!(
            derive_logical_project_key_from_ref(&fallback_ref, None, None),
            "remote:missing-project"
        );

        let sibling = LogicalProject {
            id: "project-server".to_string(),
            cwd: "/repo/apps/server".to_string(),
            name: "server".to_string(),
            ..project.clone()
        };
        assert_eq!(
            derive_project_group_label(&project, &[project.clone(), sibling.clone()]),
            "T3Code"
        );

        let conflicting = LogicalProject {
            repository_identity: Some(LogicalProjectRepositoryIdentity {
                canonical_key: Some("git:/other".to_string()),
                root_path: Some("/other".to_string()),
                display_name: Some("Other".to_string()),
                name: Some("other".to_string()),
            }),
            ..sibling
        };
        assert_eq!(
            derive_project_group_label(&project, &[project.clone(), conflicting]),
            "web"
        );
    }

    #[test]
    fn project_paths_helpers_match_upstream_contract() {
        assert_eq!(
            normalize_project_path_for_dispatch(" /repo/app/ "),
            "/repo/app"
        );
        assert_eq!(
            normalize_project_path_for_comparison("/repo/app/"),
            "/repo/app"
        );
        assert_eq!(
            normalize_project_path_for_comparison("C:/Work/Repo/"),
            "c:\\work\\repo"
        );
        assert_eq!(
            normalize_project_path_for_comparison("C:\\Work\\Repo\\"),
            "c:\\work\\repo"
        );

        let projects = vec![
            ProjectPathCandidate {
                id: "project-1".to_string(),
                cwd: "/repo/app".to_string(),
            },
            ProjectPathCandidate {
                id: "project-2".to_string(),
                cwd: "C:\\Work\\Repo".to_string(),
            },
        ];
        assert_eq!(
            find_project_by_path(&projects, "C:/Work/Repo/").map(|project| project.id.as_str()),
            Some("project-2")
        );

        assert_eq!(infer_project_title_from_path("/repo/app/"), "app");
        assert_eq!(infer_project_title_from_path("C:\\Work\\Repo\\"), "Repo");
        assert_eq!(
            infer_project_title_from_path("/home/user\\project/"),
            "user\\project"
        );

        assert!(!is_filesystem_browse_query(".", ""));
        assert!(!is_filesystem_browse_query("..", ""));
        assert!(is_filesystem_browse_query("./", ""));
        assert!(is_filesystem_browse_query("../", ""));
        assert!(is_filesystem_browse_query("~/projects", ""));
        assert!(is_filesystem_browse_query("..\\docs", ""));
        assert!(!is_filesystem_browse_query("notes", ""));
        assert!(!is_filesystem_browse_query("C:\\Work\\Repo\\", "MacIntel"));
        assert!(is_filesystem_browse_query("C:\\Work\\Repo\\", "Win32"));
        assert!(is_unsupported_windows_project_path(
            "C:\\Work\\Repo\\",
            "MacIntel"
        ));
        assert!(!is_unsupported_windows_project_path(
            "C:\\Work\\Repo\\",
            "Win32"
        ));

        assert!(is_explicit_relative_project_path("."));
        assert!(is_explicit_relative_project_path(".."));
        assert!(is_explicit_relative_project_path("./docs"));
        assert!(is_explicit_relative_project_path("..\\docs"));
        assert!(!is_explicit_relative_project_path("/repo/docs"));

        assert_eq!(
            resolve_project_path_for_dispatch(".", Some("/repo/app")),
            "/repo/app"
        );
        assert_eq!(
            resolve_project_path_for_dispatch("..", Some("/repo/app")),
            "/repo"
        );
        assert_eq!(
            resolve_project_path_for_dispatch("./docs", Some("/repo/app")),
            "/repo/app/docs"
        );
        assert_eq!(
            resolve_project_path_for_dispatch("../docs", Some("/repo/app")),
            "/repo/docs"
        );
        assert_eq!(
            resolve_project_path_for_dispatch("./Repo", Some("C:\\Work")),
            "C:\\Work\\Repo"
        );
        assert_eq!(
            resolve_project_path_for_dispatch("./docs", Some("/home/user\\project")),
            "/home/user\\project/docs"
        );

        assert_eq!(append_browse_path_segment("/repo/", "src"), "/repo/src/");
        assert_eq!(
            append_browse_path_segment("C:\\Work\\", "Repo"),
            "C:\\Work\\Repo\\"
        );
        assert_eq!(
            append_browse_path_segment("/home/user\\project/", "docs"),
            "/home/user\\project/docs/"
        );
        assert_eq!(
            get_browse_parent_path("/repo/src/").as_deref(),
            Some("/repo/")
        );
        assert_eq!(
            get_browse_parent_path("C:\\Work\\Repo\\").as_deref(),
            Some("C:\\Work\\")
        );
        assert_eq!(get_browse_parent_path("\\\\server\\share\\"), None);
        assert_eq!(
            get_browse_parent_path("\\\\server\\share\\repo\\").as_deref(),
            Some("\\\\server\\share\\")
        );
        assert_eq!(get_browse_parent_path("C:\\"), None);
        assert_eq!(
            get_browse_parent_path("/home/user\\project/docs/").as_deref(),
            Some("/home/user\\project/")
        );

        assert!(has_trailing_project_path_separator("/repo/src/"));
        assert!(!has_trailing_project_path_separator("/repo/src"));
        assert_eq!(get_browse_directory_path("/repo/src"), "/repo/");
        assert_eq!(get_browse_directory_path("/repo/src/"), "/repo/src/");
        assert_eq!(get_browse_leaf_path_segment("/repo/src"), "src");
        assert_eq!(get_browse_leaf_path_segment("C:\\Work\\Repo\\Docs"), "Docs");
        assert_eq!(
            get_browse_directory_path("/home/user\\project/docs"),
            "/home/user\\project/"
        );
        assert_eq!(
            get_browse_leaf_path_segment("/home/user\\project/docs"),
            "docs"
        );
        assert_eq!(ensure_browse_directory_path("  "), "");
        assert_eq!(ensure_browse_directory_path("~/repo"), "~/repo/");

        assert!(!can_navigate_up("~/repo"));
        assert!(!can_navigate_up("~/a"));
        assert!(can_navigate_up("~/repo/"));
        assert!(!can_navigate_up("\\\\server\\share\\"));
        assert!(can_navigate_up("\\\\server\\share\\repo\\"));
    }

    #[test]
    fn chat_thread_action_plans_match_upstream_context_resolution() {
        let environment_id = "environment-1";
        let project_id = "project-1";
        let fallback_project_id = "project-2";
        let base_context = ChatThreadActionContext {
            active_draft_thread: None,
            active_thread: None,
            default_project_ref: Some(scope_project_ref(environment_id, fallback_project_id)),
            default_thread_env_mode: DraftThreadEnvMode::Local,
        };

        let draft_context = ChatThreadActionContext {
            active_draft_thread: Some(ThreadActionDraftThreadContext {
                environment_id: environment_id.to_string(),
                project_id: project_id.to_string(),
                branch: Some("feature/refactor".to_string()),
                worktree_path: Some("/tmp/worktree".to_string()),
                env_mode: DraftThreadEnvMode::Worktree,
            }),
            ..base_context.clone()
        };
        assert_eq!(
            resolve_thread_action_project_ref(&draft_context),
            Some(scope_project_ref(environment_id, project_id))
        );
        assert_eq!(
            start_new_thread_from_context_plan(&draft_context),
            Some(ThreadActionStartPlan {
                project_ref: scope_project_ref(environment_id, project_id),
                options: ThreadActionNewThreadOptions {
                    branch: Some(Some("feature/refactor".to_string())),
                    worktree_path: Some(Some("/tmp/worktree".to_string())),
                    env_mode: Some(DraftThreadEnvMode::Worktree),
                },
            })
        );

        let active_thread_context = ChatThreadActionContext {
            active_thread: Some(ThreadActionThreadContext {
                environment_id: "environment-active".to_string(),
                project_id: "project-active".to_string(),
                branch: None,
                worktree_path: Some("/tmp/active-worktree".to_string()),
            }),
            active_draft_thread: Some(ThreadActionDraftThreadContext {
                environment_id: environment_id.to_string(),
                project_id: project_id.to_string(),
                branch: Some("draft-branch".to_string()),
                worktree_path: None,
                env_mode: DraftThreadEnvMode::Local,
            }),
            ..base_context.clone()
        };
        assert_eq!(
            resolve_thread_action_project_ref(&active_thread_context),
            Some(scope_project_ref("environment-active", "project-active"))
        );
        assert_eq!(
            start_new_thread_from_context_plan(&active_thread_context)
                .unwrap()
                .options,
            ThreadActionNewThreadOptions {
                branch: Some(Some("draft-branch".to_string())),
                worktree_path: Some(Some("/tmp/active-worktree".to_string())),
                env_mode: Some(DraftThreadEnvMode::Local),
            }
        );

        let default_context = ChatThreadActionContext {
            default_project_ref: Some(scope_project_ref(environment_id, project_id)),
            default_thread_env_mode: DraftThreadEnvMode::Worktree,
            ..base_context.clone()
        };
        assert_eq!(
            resolve_thread_action_project_ref(&default_context),
            Some(scope_project_ref(environment_id, project_id))
        );
        assert_eq!(
            start_new_local_thread_from_context_plan(&default_context),
            Some(ThreadActionStartPlan {
                project_ref: scope_project_ref(environment_id, project_id),
                options: ThreadActionNewThreadOptions {
                    branch: None,
                    worktree_path: None,
                    env_mode: Some(DraftThreadEnvMode::Worktree),
                },
            })
        );

        let missing_context = ChatThreadActionContext {
            default_project_ref: None,
            ..base_context
        };
        assert_eq!(start_new_thread_from_context_plan(&missing_context), None);
        assert_eq!(
            start_new_local_thread_from_context_plan(&missing_context),
            None
        );
    }

