    #[test]
    fn lru_cache_matches_upstream_entry_and_memory_eviction() {
        let mut cache = LruCache::new(2, 100);
        assert_eq!(cache.get("missing"), None);

        cache.set("a", "A".to_string(), 10);
        cache.set("b", "B".to_string(), 10);
        cache.set("c", "C".to_string(), 10);
        assert_eq!(cache.get("a"), None);
        assert_eq!(cache.get("b").map(String::as_str), Some("B"));
        assert_eq!(cache.get("c").map(String::as_str), Some("C"));

        let mut promoted = LruCache::new(2, 1_000);
        promoted.set("a", "A".to_string(), 10);
        promoted.set("b", "B".to_string(), 10);
        assert_eq!(promoted.get("a").map(String::as_str), Some("A"));
        promoted.set("c", "C".to_string(), 10);
        assert_eq!(promoted.get("a").map(String::as_str), Some("A"));
        assert_eq!(promoted.get("b"), None);
        assert_eq!(promoted.get("c").map(String::as_str), Some("C"));

        let mut memory_bound = LruCache::new(10, 25);
        memory_bound.set("a", "A".to_string(), 10);
        memory_bound.set("b", "B".to_string(), 10);
        memory_bound.set("c", "C".to_string(), 10);
        assert_eq!(memory_bound.get("a"), None);
        assert_eq!(memory_bound.get("b").map(String::as_str), Some("B"));
        assert_eq!(memory_bound.get("c").map(String::as_str), Some("C"));

        memory_bound.clear();
        assert_eq!(memory_bound.get("b"), None);
    }

    #[test]
    fn transport_error_filtering_matches_upstream_patterns() {
        assert!(is_transport_connection_error_message(Some(
            "SocketCloseError: 1006"
        )));
        assert!(is_transport_connection_error_message(Some(
            "Unable to connect to the T3 server WebSocket."
        )));
        assert!(is_transport_connection_error_message(Some(
            "SocketOpenError: Timeout"
        )));
        assert!(is_transport_connection_error_message(Some("ping timeout")));
        assert!(!is_transport_connection_error_message(Some(
            "prefixSocketCloseErrorsuffix"
        )));
        assert!(!is_transport_connection_error_message(Some("   ")));
        assert!(!is_transport_connection_error_message(None));

        assert_eq!(
            sanitize_thread_error_message(Some("Turn failed")).as_deref(),
            Some("Turn failed")
        );
        assert_eq!(
            sanitize_thread_error_message(Some("Select a base branch before sending.")).as_deref(),
            Some("Select a base branch before sending.")
        );
        assert_eq!(
            sanitize_thread_error_message(Some("SocketCloseError: 1006")),
            None
        );
        assert_eq!(sanitize_thread_error_message(None), None);

        assert_eq!(thread_error_banner_plan(None, true), None);
        assert_eq!(thread_error_banner_plan(Some(""), true), None);
        assert_eq!(
            thread_error_banner_plan(Some("   "), false),
            Some(ThreadErrorBannerPlan {
                wrapper_class_name: "pt-3 mx-auto max-w-3xl",
                alert_variant: "error",
                icon_name: "CircleAlertIcon",
                description: "   ".to_string(),
                description_title: "   ".to_string(),
                description_class_name: "line-clamp-3",
                dismiss_action: None,
            })
        );
        assert_eq!(
            thread_error_banner_plan(Some("Turn failed"), true),
            Some(ThreadErrorBannerPlan {
                wrapper_class_name: "pt-3 mx-auto max-w-3xl",
                alert_variant: "error",
                icon_name: "CircleAlertIcon",
                description: "Turn failed".to_string(),
                description_title: "Turn failed".to_string(),
                description_class_name: "line-clamp-3",
                dismiss_action: Some(ThreadErrorBannerDismissAction {
                    aria_label: "Dismiss error",
                    button_class_name: "inline-flex size-6 items-center justify-center rounded-md text-destructive/60 transition-colors hover:text-destructive",
                    icon_name: "XIcon",
                    icon_class_name: "size-3.5",
                }),
            })
        );
    }

