    #[test]
    fn project_setup_script_runner_decisions_match_upstream_logic() {
        let input = ProjectSetupScriptRunnerInput {
            thread_id: "thread-1".to_string(),
            project_id: Some("project-1".to_string()),
            project_cwd: Some("/repo/project".to_string()),
            worktree_path: "/repo/worktrees/a".to_string(),
            preferred_terminal_id: None,
        };

        assert_eq!(
            resolve_project_setup_script_run(&input, None, None),
            ProjectSetupScriptRunnerDecision::Error {
                message: "Project was not found for setup script execution.".to_string(),
            }
        );

        let no_script_project = ProjectSummary {
            id: "project-1".to_string(),
            environment_id: "local".to_string(),
            name: "Project".to_string(),
            path: "/repo/project".to_string(),
            scripts: Vec::new(),
        };
        assert_eq!(
            resolve_project_setup_script_run(&input, Some(&no_script_project), None),
            ProjectSetupScriptRunnerDecision::NoScript
        );

        let setup_project = ProjectSummary {
            scripts: vec![ProjectScript {
                id: "setup".to_string(),
                name: "Setup".to_string(),
                command: "bun install".to_string(),
                icon: ProjectScriptIcon::Configure,
                run_on_worktree_create: true,
            }],
            ..no_script_project.clone()
        };
        assert_eq!(
            resolve_project_setup_script_run(&input, None, Some(&setup_project)),
            ProjectSetupScriptRunnerDecision::Started(ProjectSetupScriptStarted {
                script_id: "setup".to_string(),
                script_name: "Setup".to_string(),
                terminal_id: "setup-setup".to_string(),
                cwd: "/repo/worktrees/a".to_string(),
                open: ProjectSetupTerminalOpenPlan {
                    thread_id: "thread-1".to_string(),
                    terminal_id: "setup-setup".to_string(),
                    cwd: "/repo/worktrees/a".to_string(),
                    worktree_path: "/repo/worktrees/a".to_string(),
                    env: BTreeMap::from([
                        (
                            "T3CODE_PROJECT_ROOT".to_string(),
                            "/repo/project".to_string()
                        ),
                        (
                            "T3CODE_WORKTREE_PATH".to_string(),
                            "/repo/worktrees/a".to_string()
                        ),
                    ]),
                },
                write: ProjectSetupTerminalWritePlan {
                    thread_id: "thread-1".to_string(),
                    terminal_id: "setup-setup".to_string(),
                    data: "bun install\r".to_string(),
                },
            })
        );

        let preferred = ProjectSetupScriptRunnerInput {
            preferred_terminal_id: Some("setup-custom".to_string()),
            ..input.clone()
        };
        let ProjectSetupScriptRunnerDecision::Started(started) =
            resolve_project_setup_script_run(&preferred, Some(&setup_project), None)
        else {
            panic!("expected setup script to start");
        };
        assert_eq!(started.terminal_id, "setup-custom");
        assert_eq!(started.open.terminal_id, "setup-custom");
        assert_eq!(started.write.terminal_id, "setup-custom");

        let fallback_project = ProjectSummary {
            id: "project-2".to_string(),
            name: "Fallback".to_string(),
            path: "/repo/fallback".to_string(),
            scripts: Vec::new(),
            ..setup_project.clone()
        };
        let ProjectSetupScriptRunnerDecision::Started(started) =
            resolve_project_setup_script_run(&input, Some(&setup_project), Some(&fallback_project))
        else {
            panic!("expected project id match to win");
        };
        assert_eq!(
            started
                .open
                .env
                .get("T3CODE_PROJECT_ROOT")
                .map(String::as_str),
            Some("/repo/project")
        );
    }

    #[test]
    fn project_favicon_resolver_helpers_match_upstream_logic() {
        assert_eq!(
            project_favicon_candidate_paths("/repo")
                .into_iter()
                .take(6)
                .collect::<Vec<_>>(),
            vec![
                "/repo/favicon.svg".to_string(),
                "/repo/favicon.ico".to_string(),
                "/repo/favicon.png".to_string(),
                "/repo/public/favicon.svg".to_string(),
                "/repo/public/favicon.ico".to_string(),
                "/repo/public/favicon.png".to_string(),
            ]
        );
        assert_eq!(
            project_favicon_candidate_paths("/repo")
                .last()
                .map(String::as_str),
            Some("/repo/.idea/icon.svg")
        );
        assert_eq!(
            project_icon_source_paths("/repo"),
            vec![
                "/repo/index.html".to_string(),
                "/repo/public/index.html".to_string(),
                "/repo/app/routes/__root.tsx".to_string(),
                "/repo/src/routes/__root.tsx".to_string(),
                "/repo/app/root.tsx".to_string(),
                "/repo/src/root.tsx".to_string(),
                "/repo/src/index.html".to_string(),
            ]
        );

        assert_eq!(
            extract_project_icon_href(r#"<LINK HREF="/brand/logo.svg?version=1" REL="ICON">"#),
            Some("/brand/logo.svg".to_string())
        );
        assert_eq!(
            extract_project_icon_href(r#"{ href: "/meta/icon.png?x=1", rel: "shortcut icon" }"#),
            Some("/meta/icon.png".to_string())
        );
        assert_eq!(
            project_favicon_paths_for_href("/repo", "/brand/logo.svg"),
            vec![
                "/repo/public/brand/logo.svg".to_string(),
                "/repo/brand/logo.svg".to_string(),
            ]
        );
        assert!(is_project_favicon_path_within_project(
            "/repo",
            "/repo/public/brand/logo.svg"
        ));
        assert!(!is_project_favicon_path_within_project(
            "/repo",
            "/repo-other/logo.svg"
        ));

        let existing_files = BTreeSet::from([
            "/repo/favicon.svg".to_string(),
            "/repo/public/brand/logo.svg".to_string(),
        ]);
        assert_eq!(
            resolve_project_favicon_path_from_sources("/repo", &existing_files, &BTreeMap::new()),
            Some("/repo/favicon.svg".to_string())
        );

        let source_files = BTreeMap::from([(
            "/repo/index.html".to_string(),
            r#"<link rel="icon" href="/brand/logo.svg">"#.to_string(),
        )]);
        let existing_files = BTreeSet::from(["/repo/public/brand/logo.svg".to_string()]);
        assert_eq!(
            resolve_project_favicon_path_from_sources("/repo", &existing_files, &source_files),
            Some("/repo/public/brand/logo.svg".to_string())
        );

        let source_files = BTreeMap::from([(
            "/repo/index.html".to_string(),
            r#"<link rel="icon" href="../outside.svg">"#.to_string(),
        )]);
        let existing_files = BTreeSet::from(["/outside.svg".to_string()]);
        assert_eq!(
            resolve_project_favicon_path_from_sources("/repo", &existing_files, &source_files),
            None
        );
    }

