    #[test]
    fn keybinding_shortcuts_and_when_expressions_match_upstream_logic() {
        assert!(is_mac_platform("MacIntel"));
        assert!(is_mac_platform("iPhone"));
        assert!(is_windows_platform("Win32"));
        assert!(is_windows_platform("Windows"));
        assert!(is_windows_platform("windows_nt"));
        assert!(!is_windows_platform("darwin"));
        assert!(is_linux_platform("Linux x86_64"));
        assert!(!is_linux_platform("MacIntel"));

        assert_eq!(
            shortcut_to_keybinding_input(&KeybindingShortcut {
                key: " ".to_string(),
                mod_key: true,
                meta_key: false,
                ctrl_key: false,
                alt_key: true,
                shift_key: false,
            }),
            "mod+alt+space"
        );
        assert_eq!(normalize_shortcut_key_token("K"), Some("k".to_string()));
        assert_eq!(
            normalize_shortcut_key_token("Control"),
            None,
            "modifier-only key events are ignored upstream"
        );
        assert_eq!(
            keybinding_from_keyboard_event(
                KeybindingKeyboardEvent {
                    key: "K",
                    meta_key: true,
                    ctrl_key: false,
                    alt_key: false,
                    shift_key: true,
                },
                "MacIntel",
            ),
            Some("mod+shift+k".to_string())
        );
        assert_eq!(
            keybinding_from_keyboard_event(
                KeybindingKeyboardEvent {
                    key: "K",
                    meta_key: false,
                    ctrl_key: true,
                    alt_key: false,
                    shift_key: true,
                },
                "Win32",
            ),
            Some("mod+shift+k".to_string())
        );

        let expected = KeybindingWhenNode::And {
            left: Box::new(KeybindingWhenNode::Identifier {
                name: "editorFocus".to_string(),
            }),
            right: Box::new(KeybindingWhenNode::Or {
                left: Box::new(KeybindingWhenNode::Not {
                    node: Box::new(KeybindingWhenNode::Identifier {
                        name: "terminalFocus".to_string(),
                    }),
                }),
                right: Box::new(KeybindingWhenNode::Identifier {
                    name: "modelPickerOpen".to_string(),
                }),
            }),
        };
        let parsed =
            parse_when_expression_draft("editorFocus && (!terminalFocus || modelPickerOpen)")
                .unwrap()
                .unwrap();
        assert_eq!(parsed, expected);
        assert_eq!(
            when_ast_to_expression(Some(&parsed)),
            "editorFocus && (!terminalFocus || modelPickerOpen)"
        );
        assert_eq!(
            parse_when_expression_draft("editorFocus &&"),
            Err(KEYBINDING_WHEN_PARSE_ERROR)
        );
        assert_eq!(
            when_ast_to_expression(
                parse_when_expression_draft("!(terminalFocus || modelPickerOpen)")
                    .unwrap()
                    .as_ref()
            ),
            "!(terminalFocus || modelPickerOpen)"
        );
    }

    #[test]
    fn keybinding_rows_options_and_conflicts_match_upstream_logic() {
        let variable_options = build_when_variable_options();
        assert_eq!(
            variable_options
                .iter()
                .take(4)
                .map(String::as_str)
                .collect::<Vec<_>>(),
            vec!["terminalFocus", "terminalOpen", "true", "false"]
        );
        assert!(variable_options.contains(&"modelPickerOpen".to_string()));
        assert!(!variable_options.contains(&"customModeActive".to_string()));
        assert_eq!(default_when_variable(), "terminalFocus");

        let command_options = build_keybinding_command_options(&[ResolvedKeybindingRule {
            command: "script.setup-db.run".to_string(),
            shortcut: parse_keybinding_shortcut("mod+r").unwrap(),
            when_ast: None,
        }]);
        assert!(command_options.contains(&"chat.new".to_string()));
        assert!(command_options.contains(&"script.setup-db.run".to_string()));

        let custom_terminal = ResolvedKeybindingRule {
            command: "terminal.toggle".to_string(),
            shortcut: parse_keybinding_shortcut("mod+j").unwrap(),
            when_ast: Some(parse_keybinding_when_expression("!terminalFocus").unwrap()),
        };
        let rows = build_keybinding_rows(&[custom_terminal], "terminal");
        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0].key, "mod+j");
        assert_eq!(rows[0].when, "!terminalFocus");
        assert_eq!(rows[0].default_key.as_deref(), Some("mod+j"));
        assert_eq!(rows[0].default_when, "");
        assert_eq!(rows[0].source, KeybindingSource::Custom);

        let unknown = parse_when_expression_draft("!terminalFocus && terminalFoc")
            .unwrap()
            .unwrap();
        assert_eq!(
            unknown_when_variables(Some(&unknown)),
            vec!["terminalFoc".to_string()]
        );

        let rows = build_keybinding_rows(
            &[
                ResolvedKeybindingRule {
                    command: "chat.new".to_string(),
                    shortcut: parse_keybinding_shortcut("mod+n").unwrap(),
                    when_ast: Some(parse_keybinding_when_expression("!terminalFocus").unwrap()),
                },
                ResolvedKeybindingRule {
                    command: "chat.newLocal".to_string(),
                    shortcut: parse_keybinding_shortcut("mod+n").unwrap(),
                    when_ast: Some(parse_keybinding_when_expression("!terminalFocus").unwrap()),
                },
            ],
            "",
        );
        assert_eq!(rows[0].conflicts, vec!["Chat: New Local".to_string()]);
        assert_eq!(
            keybinding_conflict_labels(&rows, &rows[0].id, "mod+n", ""),
            vec!["Chat: New Local".to_string()]
        );
    }

    #[test]
    fn keybinding_editor_draft_helpers_match_upstream_panel_state() {
        let default_group = default_when_group(BooleanOperator::And);
        assert_eq!(
            when_ast_to_expression(Some(&default_group)),
            "terminalFocus && !terminalFocus"
        );
        assert_eq!(
            flatten_when_children(&default_group, BooleanOperator::And)
                .iter()
                .map(|node| when_ast_to_expression(Some(node)))
                .collect::<Vec<_>>(),
            vec!["terminalFocus", "!terminalFocus"]
        );
        assert_eq!(
            when_ast_to_expression(
                build_when_expression_group(
                    &flatten_when_children(&default_group, BooleanOperator::And),
                    BooleanOperator::Or,
                )
                .as_ref()
            ),
            "terminalFocus || !terminalFocus"
        );

        let condition = KeybindingWhenNode::Not {
            node: Box::new(KeybindingWhenNode::Identifier {
                name: "terminalFocus".to_string(),
            }),
        };
        assert_eq!(
            condition_parts(&condition),
            Some(WhenConditionParts {
                identifier: "terminalFocus".to_string(),
                negated: true,
            })
        );
        assert_eq!(
            set_condition_identifier(&condition, "modelPickerOpen"),
            KeybindingWhenNode::Not {
                node: Box::new(KeybindingWhenNode::Identifier {
                    name: "modelPickerOpen".to_string(),
                }),
            }
        );
        assert_eq!(
            set_condition_negated(&condition, false),
            KeybindingWhenNode::Identifier {
                name: "terminalFocus".to_string(),
            }
        );

        let rows = build_keybinding_rows(
            &[ResolvedKeybindingRule {
                command: "terminal.toggle".to_string(),
                shortcut: parse_keybinding_shortcut("mod+j").unwrap(),
                when_ast: Some(parse_keybinding_when_expression("!terminalFocus").unwrap()),
            }],
            "terminal",
        );
        let row = &rows[0];
        let draft = create_keybinding_row_draft(row);
        assert!(keybinding_row_show_pill(row, &draft));
        assert!(!keybinding_row_is_dirty(row, &draft));
        assert!(keybinding_row_can_reset(row));
        assert!(keybinding_row_can_remove(row));
        assert_eq!(
            row_keybinding_target(row),
            KeybindingTarget {
                command: "terminal.toggle".to_string(),
                key: "mod+j".to_string(),
                when: Some("!terminalFocus".to_string()),
            }
        );

        let changed = apply_keybinding_row_draft_patch(
            &draft,
            KeybindingRowDraftPatch {
                key_draft: Some(" mod+shift+j ".to_string()),
                ..KeybindingRowDraftPatch::default()
            },
        );
        assert!(keybinding_row_is_dirty(row, &changed));
        assert_eq!(
            keybinding_row_save_input(row, &changed),
            Some(KeybindingUpsertInput {
                command: "terminal.toggle".to_string(),
                key: "mod+shift+j".to_string(),
                when: Some("!terminalFocus".to_string()),
                replace: Some(KeybindingTarget {
                    command: "terminal.toggle".to_string(),
                    key: "mod+j".to_string(),
                    when: Some("!terminalFocus".to_string()),
                }),
            })
        );
        assert_eq!(
            keybinding_reset_input(row),
            Some(KeybindingUpsertInput {
                command: "terminal.toggle".to_string(),
                key: "mod+j".to_string(),
                when: None,
                replace: Some(KeybindingTarget {
                    command: "terminal.toggle".to_string(),
                    key: "mod+j".to_string(),
                    when: Some("!terminalFocus".to_string()),
                }),
            })
        );

        let new_draft = apply_keybinding_row_draft_patch(
            &new_keybinding_row_draft(),
            KeybindingRowDraftPatch {
                key_draft: Some(" mod+k ".to_string()),
                when_draft: Some(Some(default_group)),
                ..KeybindingRowDraftPatch::default()
            },
        );
        assert_eq!(
            new_keybinding_save_input("commandPalette.toggle", &new_draft),
            Some(KeybindingUpsertInput {
                command: "commandPalette.toggle".to_string(),
                key: "mod+k".to_string(),
                when: Some("terminalFocus && !terminalFocus".to_string()),
                replace: None,
            })
        );
    }

    #[test]
    fn keybindings_server_runtime_config_contracts_match_upstream() {
        assert_eq!(MAX_KEYBINDINGS_COUNT, 256);
        assert_eq!(default_server_keybinding_rules().len(), 31);

        let custom_toggle = ServerKeybindingRule {
            command: "terminal.toggle".to_string(),
            key: "mod+shift+t".to_string(),
            when: None,
        };
        let state = keybindings_config_state_from_custom_rules(&[custom_toggle.clone()], &[]);
        assert!(
            state
                .keybindings
                .iter()
                .any(|binding| binding.command == "terminal.toggle"
                    && shortcut_to_keybinding_input(&binding.shortcut) == "mod+shift+t")
        );
        assert!(
            !state
                .keybindings
                .iter()
                .any(|binding| binding.command == "terminal.toggle"
                    && shortcut_to_keybinding_input(&binding.shortcut) == "mod+j")
        );

        let with_invalid = compile_server_keybindings_config(&[
            ServerKeybindingRule {
                command: "terminal.toggle".to_string(),
                key: "mod+j".to_string(),
                when: None,
            },
            ServerKeybindingRule {
                command: "terminal.new".to_string(),
                key: "mod+shift+d+o".to_string(),
                when: None,
            },
        ]);
        assert_eq!(with_invalid.len(), 1);
        assert_eq!(with_invalid[0].command, "terminal.toggle");

        let issues = vec![KeybindingsConfigIssue {
            kind: "keybindings.malformed-config".to_string(),
            index: None,
            message: "expected JSON array".to_string(),
        }];
        let skipped = sync_default_keybindings_on_startup_plan(&[custom_toggle.clone()], true);
        assert!(skipped.skipped_due_to_issues);
        assert!(!skipped.changed);
        assert_eq!(
            keybindings_config_state_from_custom_rules(&[], &issues).issues,
            issues
        );

        let conflict_plan = sync_default_keybindings_on_startup_plan(
            &[ServerKeybindingRule {
                command: "script.custom-action.run".to_string(),
                key: "mod+j".to_string(),
                when: None,
            }],
            false,
        );
        assert!(
            !conflict_plan
                .next_config
                .iter()
                .any(|rule| rule.command == "terminal.toggle")
        );
        assert_eq!(
            conflict_plan.skipped_default_conflicts,
            vec![KeybindingsDefaultConflict {
                default_command: "terminal.toggle".to_string(),
                conflicting_command: "script.custom-action.run".to_string(),
                key: "mod+j".to_string(),
                when: None,
            }]
        );

        let sync_plan = sync_default_keybindings_on_startup_plan(&[custom_toggle.clone()], false);
        assert!(sync_plan.changed);
        assert!(
            sync_plan
                .next_config
                .iter()
                .any(|rule| rule.command == "terminal.toggle" && rule.key == "mod+shift+t")
        );
        for default_rule in default_server_keybinding_rules() {
            if default_rule.command != "terminal.toggle" {
                assert!(
                    sync_plan
                        .next_config
                        .iter()
                        .any(|rule| rule.command == default_rule.command),
                    "expected missing default {} to be backfilled",
                    default_rule.command
                );
            }
        }

        let upserted = upsert_keybinding_rule_in_config(
            &[
                ServerKeybindingRule {
                    command: "script.run-tests.run".to_string(),
                    key: "mod+r".to_string(),
                    when: None,
                },
                ServerKeybindingRule {
                    command: "script.run-tests.run".to_string(),
                    key: "mod+shift+r".to_string(),
                    when: None,
                },
            ],
            &KeybindingUpsertInput {
                command: "script.run-tests.run".to_string(),
                key: "mod+alt+r".to_string(),
                when: None,
                replace: Some(KeybindingTarget {
                    command: "script.run-tests.run".to_string(),
                    key: "mod+r".to_string(),
                    when: None,
                }),
            },
        );
        assert_eq!(
            upserted
                .iter()
                .map(|rule| (rule.key.as_str(), rule.command.as_str()))
                .collect::<Vec<_>>(),
            vec![
                ("mod+shift+r", "script.run-tests.run"),
                ("mod+alt+r", "script.run-tests.run")
            ]
        );

        let removed = remove_keybinding_rule_from_config(
            &upserted,
            &KeybindingTarget {
                command: "script.run-tests.run".to_string(),
                key: "mod+shift+r".to_string(),
                when: None,
            },
        );
        assert_eq!(removed.len(), 1);
        assert_eq!(removed[0].key, "mod+alt+r");
    }

