    #[test]
    fn inline_terminal_context_placeholders_match_upstream_contract() {
        let placeholder = INLINE_TERMINAL_CONTEXT_PLACEHOLDER;

        assert_eq!(
            count_inline_terminal_context_placeholders(&format!("a{placeholder}b{placeholder}")),
            2
        );
        assert_eq!(
            ensure_inline_terminal_context_placeholders("Investigate this", 2),
            format!("{placeholder}{placeholder}Investigate this")
        );
        assert_eq!(
            insert_inline_terminal_context_placeholder("abc", 1),
            InlineTerminalContextInsertion {
                prompt: format!("a {placeholder} bc"),
                cursor: 4,
                context_index: 0,
            }
        );
        assert_eq!(
            remove_inline_terminal_context_placeholder(
                &format!("a{placeholder}b{placeholder}c"),
                1
            ),
            InlineTerminalContextRemoval {
                prompt: format!("a{placeholder}bc"),
                cursor: 3,
            }
        );
        assert_eq!(
            strip_inline_terminal_context_placeholders(&format!("a{placeholder}b")),
            "ab"
        );
        assert_eq!(
            insert_inline_terminal_context_placeholder("Inspect @package.json ", 22),
            InlineTerminalContextInsertion {
                prompt: format!("Inspect @package.json {placeholder} "),
                cursor: 24,
                context_index: 0,
            }
        );
        assert_eq!(
            insert_inline_terminal_context_placeholder("yo whats", 3),
            InlineTerminalContextInsertion {
                prompt: format!("yo {placeholder} whats"),
                cursor: 5,
                context_index: 0,
            }
        );
    }

    #[test]
    fn terminal_context_expiry_and_preview_match_upstream_contract() {
        let live_context = make_terminal_context(|_| {});
        let expired_context = make_terminal_context(|context| {
            context.id = "context-2".to_string();
            context.text.clear();
        });
        let invalid_context = make_terminal_context(|context| {
            context.terminal_id = "   ".to_string();
        });
        let blank_context = make_terminal_context(|context| {
            context.id = "context-3".to_string();
            context.text = "\n\n".to_string();
        });

        assert!(has_terminal_context_text(&live_context.text));
        assert!(!is_terminal_context_expired(&live_context.text));
        assert!(!has_terminal_context_text(&expired_context.text));
        assert!(is_terminal_context_expired(&expired_context.text));
        assert_eq!(
            filter_terminal_contexts_with_text(&[expired_context.clone(), live_context.clone()]),
            vec![live_context.clone()]
        );
        assert_eq!(
            build_terminal_context_preview_title(&[
                invalid_context.selection(),
                blank_context.selection()
            ]),
            None
        );
        assert_eq!(
            format_inline_terminal_context_label(&live_context.selection()),
            "@terminal-1:12-13"
        );
    }

    #[test]
    fn terminal_state_cleanup_retains_active_threads_like_upstream() {
        let thread_key = |environment_id: &str, thread_id: &str| {
            scoped_thread_key(&ScopedThreadRef::new(environment_id, thread_id))
        };

        assert_eq!(
            collect_active_terminal_thread_ids(
                &[
                    TerminalRetentionThread {
                        key: thread_key("env-a", "server-1"),
                        deleted_at: None,
                        archived_at: None,
                    },
                    TerminalRetentionThread {
                        key: thread_key("env-b", "server-2"),
                        deleted_at: None,
                        archived_at: None,
                    },
                ],
                Vec::<String>::new()
            ),
            BTreeSet::from([
                thread_key("env-a", "server-1"),
                thread_key("env-b", "server-2")
            ])
        );

        assert_eq!(
            collect_active_terminal_thread_ids(
                &[
                    TerminalRetentionThread {
                        key: thread_key("env-a", "server-active"),
                        deleted_at: None,
                        archived_at: None,
                    },
                    TerminalRetentionThread {
                        key: thread_key("env-a", "server-deleted"),
                        deleted_at: Some("2026-03-05T08:00:00.000Z".to_string()),
                        archived_at: None,
                    },
                    TerminalRetentionThread {
                        key: thread_key("env-a", "server-archived"),
                        deleted_at: None,
                        archived_at: Some("2026-03-05T09:00:00.000Z".to_string()),
                    },
                ],
                [thread_key("env-a", "local-draft")]
            ),
            BTreeSet::from([
                thread_key("env-a", "server-active"),
                thread_key("env-a", "local-draft")
            ])
        );

        let archived_thread_id = thread_key("env-a", "server-archived");
        assert_eq!(
            collect_active_terminal_thread_ids(
                &[TerminalRetentionThread {
                    key: archived_thread_id.clone(),
                    deleted_at: None,
                    archived_at: Some("2026-03-05T09:00:00.000Z".to_string()),
                }],
                [archived_thread_id, thread_key("env-a", "local-draft")]
            ),
            BTreeSet::from([thread_key("env-a", "local-draft")])
        );
    }

    #[test]
    fn composer_send_state_and_expired_terminal_copy_match_upstream() {
        let expired_context = make_terminal_context(|context| {
            context.id = "ctx-expired".to_string();
            context.text.clear();
            context.line_start = 4;
            context.line_end = 4;
        });
        let placeholder = INLINE_TERMINAL_CONTEXT_PLACEHOLDER;

        let expired_only =
            derive_composer_send_state(&placeholder.to_string(), 0, &[expired_context.clone()]);
        assert_eq!(expired_only.trimmed_prompt, "");
        assert_eq!(expired_only.sendable_terminal_contexts, Vec::new());
        assert_eq!(expired_only.expired_terminal_context_count, 1);
        assert!(!expired_only.has_sendable_content);

        let with_text =
            derive_composer_send_state(&format!("yoo {placeholder} waddup"), 0, &[expired_context]);
        assert_eq!(with_text.trimmed_prompt, "yoo  waddup");
        assert_eq!(with_text.expired_terminal_context_count, 1);
        assert!(with_text.has_sendable_content);

        assert_eq!(
            build_expired_terminal_context_toast_copy(1, ExpiredTerminalContextToastVariant::Empty),
            ExpiredTerminalContextToastCopy {
                title: "Expired terminal context won't be sent".to_string(),
                description: "Remove it or re-add it to include terminal output.",
            }
        );
        assert_eq!(
            build_expired_terminal_context_toast_copy(
                2,
                ExpiredTerminalContextToastVariant::Omitted
            ),
            ExpiredTerminalContextToastCopy {
                title: "Expired terminal contexts omitted from message".to_string(),
                description: "Re-add it if you want that terminal output included.",
            }
        );
    }

    #[test]
    fn toast_layout_and_scope_logic_match_upstream() {
        assert!(!should_hide_collapsed_toast_content(0, 1));
        assert!(!should_hide_collapsed_toast_content(0, 3));
        assert!(should_hide_collapsed_toast_content(1, 3));

        let toast =
            |id: &str, height: Option<f64>, transition_status: Option<ToastTransitionStatus>| {
                ToastLayoutInput {
                    id: id.to_string(),
                    height,
                    transition_status,
                }
            };

        let layout = build_visible_toast_layout(&[
            toast("a", Some(48.0), None),
            toast("b", Some(72.0), None),
            toast("c", Some(24.0), None),
        ]);
        assert_eq!(layout.frontmost_height, 48.0);
        assert_eq!(
            layout
                .items
                .iter()
                .map(|item| (
                    item.toast.id.as_str(),
                    item.visible_index,
                    item.offset_y as i32
                ))
                .collect::<Vec<_>>(),
            vec![("a", 0, 0), ("b", 1, 48), ("c", 2, 120)]
        );

        let front_dismissed = build_visible_toast_layout(&[
            toast("a", Some(48.0), Some(ToastTransitionStatus::Ending)),
            toast("b", Some(72.0), None),
            toast("c", Some(24.0), None),
        ]);
        assert_eq!(front_dismissed.frontmost_height, 72.0);
        assert_eq!(
            front_dismissed
                .items
                .iter()
                .map(|item| (
                    item.toast.id.as_str(),
                    item.visible_index,
                    item.offset_y as i32
                ))
                .collect::<Vec<_>>(),
            vec![("a", 0, 0), ("b", 0, 0), ("c", 1, 72)]
        );

        let middle_dismissed = build_visible_toast_layout(&[
            toast("a", Some(48.0), None),
            toast("b", Some(72.0), Some(ToastTransitionStatus::Ending)),
            toast("c", Some(24.0), None),
        ]);
        assert_eq!(middle_dismissed.frontmost_height, 48.0);
        assert_eq!(
            middle_dismissed
                .items
                .iter()
                .map(|item| (
                    item.toast.id.as_str(),
                    item.visible_index,
                    item.offset_y as i32
                ))
                .collect::<Vec<_>>(),
            vec![("a", 0, 0), ("b", 1, 48), ("c", 1, 48)]
        );

        let missing_heights = build_visible_toast_layout(&[
            toast("a", None, None),
            toast("b", None, None),
            toast("c", Some(30.0), None),
        ]);
        assert_eq!(missing_heights.frontmost_height, 0.0);
        assert_eq!(
            missing_heights
                .items
                .iter()
                .map(|item| (item.toast.id.as_str(), item.offset_y as i32))
                .collect::<Vec<_>>(),
            vec![("a", 0), ("b", 0), ("c", 0)]
        );

        let active_thread_ref = ScopedThreadRef::new("environment-a", "thread-1");
        assert!(should_render_thread_scoped_toast(
            Some(&ThreadScopedToastData {
                thread_ref: Some(active_thread_ref.clone()),
                thread_id: None,
            }),
            Some(&active_thread_ref)
        ));
        assert!(!should_render_thread_scoped_toast(
            Some(&ThreadScopedToastData {
                thread_ref: Some(ScopedThreadRef::new("environment-b", "thread-1")),
                thread_id: None,
            }),
            Some(&active_thread_ref)
        ));
        assert!(should_render_thread_scoped_toast(
            Some(&ThreadScopedToastData {
                thread_ref: None,
                thread_id: Some("thread-1".to_string()),
            }),
            Some(&active_thread_ref)
        ));
        assert!(should_render_thread_scoped_toast(
            None,
            Some(&active_thread_ref)
        ));
    }

    #[test]
    fn shortcut_modifier_state_matches_upstream_keyboard_logic() {
        assert!(are_shortcut_modifier_states_equal(
            ShortcutModifierState {
                meta_key: false,
                ctrl_key: true,
                alt_key: false,
                shift_key: true,
            },
            ShortcutModifierState {
                meta_key: false,
                ctrl_key: true,
                alt_key: false,
                shift_key: true,
            }
        ));
        assert!(!are_shortcut_modifier_states_equal(
            ShortcutModifierState {
                meta_key: false,
                ctrl_key: true,
                alt_key: false,
                shift_key: true,
            },
            ShortcutModifierState {
                meta_key: false,
                ctrl_key: false,
                alt_key: false,
                shift_key: true,
            }
        ));

        assert_eq!(
            normalize_modifier_key("Meta"),
            Some(ShortcutModifierKey::Meta)
        );
        assert_eq!(
            normalize_modifier_key("OS"),
            Some(ShortcutModifierKey::Meta)
        );
        assert_eq!(
            normalize_modifier_key("Command"),
            Some(ShortcutModifierKey::Meta)
        );
        assert_eq!(
            normalize_modifier_key("Control"),
            Some(ShortcutModifierKey::Ctrl)
        );
        assert_eq!(
            normalize_modifier_key("Alt"),
            Some(ShortcutModifierKey::Alt)
        );
        assert_eq!(
            normalize_modifier_key("Option"),
            Some(ShortcutModifierKey::Alt)
        );
        assert_eq!(
            normalize_modifier_key("Shift"),
            Some(ShortcutModifierKey::Shift)
        );
        assert_eq!(normalize_modifier_key("Enter"), None);

        let event = |event_type: &str,
                     key: &str,
                     meta_key: bool,
                     ctrl_key: bool,
                     alt_key: bool,
                     shift_key: bool| KeyboardModifierEvent {
            event_type: event_type.to_string(),
            key: key.to_string(),
            meta_key,
            ctrl_key,
            alt_key,
            shift_key,
        };
        let mut state = ShortcutModifierState::default();
        state = sync_shortcut_modifier_state_from_keyboard_event(
            state,
            &event("keydown", "Meta", false, false, false, false),
        );
        assert_eq!(
            state,
            ShortcutModifierState {
                meta_key: true,
                ..ShortcutModifierState::default()
            }
        );
        state = sync_shortcut_modifier_state_from_keyboard_event(
            state,
            &event("keydown", "Shift", true, false, false, false),
        );
        assert_eq!(
            state,
            ShortcutModifierState {
                meta_key: true,
                shift_key: true,
                ..ShortcutModifierState::default()
            }
        );
        state = sync_shortcut_modifier_state_from_keyboard_event(
            state,
            &event("keyup", "Meta", true, false, false, true),
        );
        assert_eq!(
            state,
            ShortcutModifierState {
                shift_key: true,
                ..ShortcutModifierState::default()
            }
        );
        state = sync_shortcut_modifier_state_from_keyboard_event(
            state,
            &event("keyup", "Shift", false, false, false, true),
        );
        assert_eq!(state, ShortcutModifierState::default());

        let non_modifier = sync_shortcut_modifier_state_from_keyboard_event(
            state,
            &event("keydown", "a", true, false, true, false),
        );
        assert_eq!(
            non_modifier,
            ShortcutModifierState {
                meta_key: true,
                ctrl_key: false,
                alt_key: true,
                shift_key: false,
            }
        );
    }

