    #[test]
    fn command_palette_store_transitions_match_upstream_zustand_logic() {
        let initial = initial_command_palette_store_state();
        assert_eq!(
            initial,
            CommandPaletteStoreState {
                open: false,
                open_intent: None,
            }
        );

        let opened = set_command_palette_open(initial, true);
        assert!(opened.open);
        assert_eq!(opened.open_intent, None);

        let add_project = open_command_palette_add_project(opened);
        assert_eq!(
            add_project,
            CommandPaletteStoreState {
                open: true,
                open_intent: Some(CommandPaletteOpenIntent {
                    kind: CommandPaletteOpenIntentKind::AddProject,
                    request_id: 1,
                }),
            }
        );

        let add_project_again = open_command_palette_add_project(add_project);
        assert_eq!(add_project_again.open_intent.unwrap().request_id, 2);

        let cleared = clear_command_palette_open_intent(add_project_again);
        assert!(cleared.open);
        assert_eq!(cleared.open_intent, None);

        let closed = set_command_palette_open(add_project_again, false);
        assert!(!closed.open);
        assert_eq!(closed.open_intent, None);

        let toggled_open = toggle_command_palette_open(closed);
        assert!(toggled_open.open);
        assert_eq!(toggled_open.open_intent, None);

        let toggled_closed = toggle_command_palette_open(add_project_again);
        assert!(!toggled_closed.open);
        assert_eq!(toggled_closed.open_intent, None);
    }

    #[test]
    fn websocket_connection_state_matches_upstream_reconnect_logic() {
        let now = "2026-04-03T20:30:00.000Z";
        let mut status = initial_ws_connection_status(true);

        status = record_ws_connection_attempt(&status, "ws://localhost:3020/ws", None);
        status = record_ws_connection_opened_at(&status, None, now);
        status = record_ws_connection_closed_at(&status, Some(1006), Some("offline"), None, now);
        status = set_browser_online_status(&status, false);
        assert_eq!(
            get_ws_connection_ui_state(&status),
            WsConnectionUiState::Offline
        );

        let connecting = record_ws_connection_attempt(
            &initial_ws_connection_status(true),
            "ws://localhost:3020/ws",
            None,
        );
        assert_eq!(connecting.attempt_count, 1);
        assert!(!connecting.has_connected);
        assert_eq!(connecting.phase, WsConnectionPhase::Connecting);
        assert_eq!(
            get_ws_connection_ui_state(&connecting),
            WsConnectionUiState::Connecting
        );

        let remote_attempt = record_ws_connection_attempt(
            &initial_ws_connection_status(true),
            "ws://localhost:3020/ws",
            Some(&WsConnectionMetadata {
                connection_label: Some("Remote Mac".to_string()),
                version_mismatch_hint: None,
            }),
        );
        let first_retry_delay_ms = get_ws_reconnect_delay_ms_for_retry(0).unwrap();
        let failed = record_ws_connection_errored_at(
            &remote_attempt,
            Some("Unable to connect to the T3 server WebSocket."),
            None,
            now,
        );
        assert_eq!(failed.connection_label.as_deref(), Some("Remote Mac"));
        assert_eq!(
            failed.next_retry_at.as_deref(),
            iso_timestamp_after_millis(now, first_retry_delay_ms).as_deref()
        );
        assert_eq!(failed.reconnect_attempt_count, 1);
        assert_eq!(failed.reconnect_phase, WsReconnectPhase::Waiting);

        let hinted_error = record_ws_connection_errored_at(
            &remote_attempt,
            Some("Unable to connect to the T3 server WebSocket."),
            Some(&WsConnectionMetadata {
                connection_label: None,
                version_mismatch_hint: Some(
                    "Version mismatch. Try syncing the client and server.".to_string(),
                ),
            }),
            now,
        );
        assert_eq!(
            hinted_error.last_error.as_deref(),
            Some(
                "Unable to connect to the T3 server WebSocket. Hint: Version mismatch. Try syncing the client and server."
            )
        );

        let opened = record_ws_connection_opened_at(&remote_attempt, None, now);
        let hinted_close = record_ws_connection_closed_at(
            &opened,
            Some(1006),
            Some("socket closed"),
            Some(&WsConnectionMetadata {
                connection_label: None,
                version_mismatch_hint: Some(
                    "Version mismatch. Try syncing the client and server.".to_string(),
                ),
            }),
            now,
        );
        assert_eq!(
            hinted_close.close_reason.as_deref(),
            Some("socket closed Hint: Version mismatch. Try syncing the client and server.")
        );

        let mut exhausted = initial_ws_connection_status(true);
        for _ in 0..WS_RECONNECT_MAX_ATTEMPTS {
            exhausted = record_ws_connection_attempt(&exhausted, "ws://localhost:3020/ws", None);
            exhausted = record_ws_connection_errored_at(
                &exhausted,
                Some("Unable to connect to the T3 server WebSocket."),
                None,
                now,
            );
            if exhausted.reconnect_phase == WsReconnectPhase::Waiting {
                exhausted.next_retry_at = None;
                exhausted.reconnect_phase = WsReconnectPhase::Attempting;
            }
        }
        assert_eq!(exhausted.next_retry_at, None);
        assert_eq!(exhausted.reconnect_attempt_count, WS_RECONNECT_MAX_ATTEMPTS);
        assert_eq!(exhausted.reconnect_phase, WsReconnectPhase::Exhausted);

        assert_eq!(get_ws_reconnect_delay_ms_for_retry(-1), None);
        assert_eq!(get_ws_reconnect_delay_ms_for_retry(0), Some(1_000));
        assert_eq!(get_ws_reconnect_delay_ms_for_retry(6), Some(64_000));
        assert_eq!(get_ws_reconnect_delay_ms_for_retry(7), None);
    }

    #[test]
    fn request_latency_state_matches_upstream_ack_tracking() {
        let started_at = "2026-04-03T20:30:00.000Z";
        let mut state = initial_rpc_ack_latency_state();

        state = track_rpc_request_sent_at(&state, "1", "server.getConfig", 0, started_at);
        state = promote_elapsed_rpc_ack_requests(&state, SLOW_RPC_ACK_THRESHOLD_MS - 1);
        assert!(state.slow_requests.is_empty());

        state = promote_elapsed_rpc_ack_requests(&state, SLOW_RPC_ACK_THRESHOLD_MS);
        assert_eq!(
            state.slow_requests,
            vec![SlowRpcAckRequest {
                request_id: "1".to_string(),
                started_at: started_at.to_string(),
                started_at_ms: 0,
                tag: "server.getConfig".to_string(),
                threshold_ms: SLOW_RPC_ACK_THRESHOLD_MS,
            }]
        );

        state = acknowledge_rpc_request(&state, "1");
        assert!(state.slow_requests.is_empty());

        state = track_rpc_request_sent_at(&state, "1", "subscribeServerConfig", 0, started_at);
        state = promote_elapsed_rpc_ack_requests(&state, SLOW_RPC_ACK_THRESHOLD_MS * 2);
        assert!(state.slow_requests.is_empty());

        let mut capacity_state = initial_rpc_ack_latency_state();
        for index in 0..=MAX_TRACKED_RPC_ACK_REQUESTS {
            capacity_state = track_rpc_request_sent_at(
                &capacity_state,
                &index.to_string(),
                "server.getConfig",
                0,
                started_at,
            );
        }
        capacity_state =
            promote_elapsed_rpc_ack_requests(&capacity_state, SLOW_RPC_ACK_THRESHOLD_MS);
        assert_eq!(
            capacity_state.slow_requests.len(),
            MAX_TRACKED_RPC_ACK_REQUESTS
        );
        assert_eq!(
            capacity_state
                .slow_requests
                .first()
                .map(|request| request.request_id.as_str()),
            Some("1")
        );
        assert_eq!(
            capacity_state
                .slow_requests
                .last()
                .map(|request| request.request_id.as_str()),
            Some("256")
        );

        let lowered_threshold =
            set_slow_rpc_ack_threshold_ms_for_tests(&initial_rpc_ack_latency_state(), 25);
        assert_eq!(lowered_threshold.slow_rpc_ack_threshold_ms, 25);
        assert!(
            clear_all_tracked_rpc_requests(&capacity_state)
                .pending_requests
                .is_empty()
        );
    }

