    #[test]
    fn turn_diff_stats_sum_only_files_with_numeric_values() {
        let stat = summarize_turn_diff_stats(&[
            diff_file("README.md", Some(3), Some(1)),
            diff_file("docs/notes.md", None, None),
            diff_file("src/index.ts", Some(5), Some(2)),
        ]);

        assert_eq!(
            stat,
            TurnDiffStat {
                additions: 8,
                deletions: 3,
            }
        );
        assert!(has_non_zero_turn_diff_stat(stat));
        assert!(!has_non_zero_turn_diff_stat(TurnDiffStat::default()));
        assert_eq!(
            diff_stat_label_segments(stat, false),
            vec![
                DiffStatLabelSegment {
                    text: "+8".to_string(),
                    class_name: "text-success",
                },
                DiffStatLabelSegment {
                    text: "/".to_string(),
                    class_name: "mx-0.5 text-muted-foreground/70",
                },
                DiffStatLabelSegment {
                    text: "-3".to_string(),
                    class_name: "text-destructive",
                },
            ]
        );
        assert_eq!(
            diff_stat_label_segments(
                TurnDiffStat {
                    additions: 0,
                    deletions: 0,
                },
                true
            ),
            vec![
                DiffStatLabelSegment {
                    text: "(".to_string(),
                    class_name: "text-muted-foreground/70",
                },
                DiffStatLabelSegment {
                    text: "+0".to_string(),
                    class_name: "text-success",
                },
                DiffStatLabelSegment {
                    text: "/".to_string(),
                    class_name: "mx-0.5 text-muted-foreground/70",
                },
                DiffStatLabelSegment {
                    text: "-0".to_string(),
                    class_name: "text-destructive",
                },
                DiffStatLabelSegment {
                    text: ")".to_string(),
                    class_name: "text-muted-foreground/70",
                },
            ]
        );
    }

