    #[test]
    fn terminal_activity_and_event_filters_match_upstream_helpers() {
        let mut state =
            split_thread_terminal(&create_default_thread_terminal_state(), "terminal-2");
        state = set_thread_terminal_activity(&state, "terminal-2", true);
        assert_eq!(state.running_terminal_ids, vec!["terminal-2"]);
        state = set_thread_terminal_activity(&state, "terminal-2", false);
        assert_eq!(state.running_terminal_ids, Vec::<String>::new());

        let output = TerminalEvent::Output {
            thread_id: "thread-1".to_string(),
            terminal_id: "default".to_string(),
            created_at: "2026-04-02T20:00:00.000Z".to_string(),
            data: "before".to_string(),
        };
        let activity = TerminalEvent::Activity {
            thread_id: "thread-1".to_string(),
            terminal_id: "default".to_string(),
            created_at: "2026-04-02T20:00:01.000Z".to_string(),
            has_running_subprocess: true,
        };
        let exited = TerminalEvent::Exited {
            thread_id: "thread-1".to_string(),
            terminal_id: "default".to_string(),
            created_at: "2026-04-02T20:00:02.000Z".to_string(),
            exit_code: Some(0),
            exit_signal: None,
        };
        assert_eq!(terminal_running_subprocess_from_event(&output), None);
        assert_eq!(
            terminal_running_subprocess_from_event(&activity),
            Some(true)
        );
        assert_eq!(terminal_running_subprocess_from_event(&exited), Some(false));

        let entries = vec![
            TerminalEventEntry {
                id: 1,
                event: output,
            },
            TerminalEventEntry {
                id: 2,
                event: activity,
            },
            TerminalEventEntry {
                id: 3,
                event: exited,
            },
        ];
        assert_eq!(
            select_terminal_event_entries_after_snapshot(&entries, "2026-04-02T20:00:00.500Z")
                .iter()
                .map(|entry| entry.id)
                .collect::<Vec<_>>(),
            vec![2, 3]
        );
        assert_eq!(
            select_pending_terminal_event_entries(&entries, 1)
                .iter()
                .map(|entry| entry.id)
                .collect::<Vec<_>>(),
            vec![2, 3]
        );
    }

    #[test]
    fn right_panel_and_terminal_focus_helpers_match_upstream_constants() {
        assert_eq!(RIGHT_PANEL_INLINE_LAYOUT_MEDIA_QUERY, "(max-width: 980px)");
        assert_eq!(WINDOW_CONTROLS_OVERLAY_CLASS_NAME, "wco");
        assert_eq!(
            RIGHT_PANEL_SHEET_CLASS_NAME,
            "w-[min(42vw,28rem)] min-w-80 max-w-[28rem] p-0 max-[760px]:w-[min(88vw,24rem)] max-[760px]:min-w-0 wco:mt-[env(titlebar-area-height)] wco:h-[calc(100%-env(titlebar-area-height))] wco:max-h-[calc(100%-env(titlebar-area-height))]"
        );
        assert_eq!(TERMINAL_HELPER_TEXTAREA_CLASS, "xterm-helper-textarea");
        assert_eq!(
            THREAD_TERMINAL_DRAWER_XTERM_SELECTOR,
            ".thread-terminal-drawer .xterm"
        );

        assert!(!is_terminal_focused_from_active_element(
            false, true, true, true
        ));
        assert!(!is_terminal_focused_from_active_element(
            true, false, true, true
        ));
        assert!(is_terminal_focused_from_active_element(
            true, true, true, false
        ));
        assert!(is_terminal_focused_from_active_element(
            true, true, false, true
        ));
        assert!(!is_terminal_focused_from_active_element(
            true, true, false, false
        ));

        assert_eq!(
            sync_window_controls_overlay_class_plan(false, Some(true)),
            WindowControlsOverlayClassSync {
                should_update_document_class: false,
                class_name: "wco",
                class_present: false,
                listens_for_geometry_changes: false,
            }
        );
        assert_eq!(
            sync_window_controls_overlay_class_plan(true, None),
            WindowControlsOverlayClassSync {
                should_update_document_class: true,
                class_name: "wco",
                class_present: false,
                listens_for_geometry_changes: false,
            }
        );
        assert_eq!(
            sync_window_controls_overlay_class_plan(true, Some(false)),
            WindowControlsOverlayClassSync {
                should_update_document_class: true,
                class_name: "wco",
                class_present: false,
                listens_for_geometry_changes: true,
            }
        );
        assert_eq!(
            sync_window_controls_overlay_class_plan(true, Some(true)),
            WindowControlsOverlayClassSync {
                should_update_document_class: true,
                class_name: "wco",
                class_present: true,
                listens_for_geometry_changes: true,
            }
        );
    }

